        let projects = self
            .list_documents(self.storage_paths.film_projects_dir())?
            .into_iter()
            .map(attach_film_project_graph)
            .collect::<ServerResult<Vec<_>>>()?;
        Ok(Self::apply_list_query(projects, query))
