    fn delete_template(&self, template_key: &str) -> ServerResult<bool> {
        let _guard = self.lock.lock().map_err(|_| {
            ServerError::internal("FILM_LOCK_FAILED", "failed to acquire film lock")
        })?;
        self.ensure_storage_dirs()?;

        let path = self
            .find_document_path_by_key(self.storage_paths.film_templates_dir(), template_key)?
            .ok_or_else(|| {
                ServerError::not_found(
                    "FILM_TEMPLATE_NOT_FOUND",
                    format!("film template {template_key} was not found"),
                )
            })?;
        fs::remove_file(path).map_err(|error| {
            ServerError::internal(
                "FILM_TEMPLATE_DELETE_FAILED",
                format!("failed to delete film template {template_key}: {error}"),
            )
        })?;
        Ok(true)
    }

