fn read_film_project_publish_review_operations_dashboard(
    storage_paths: &AppStoragePaths,
    project_key: &str,
    publish_id: &str,
) -> ServerResult<Value> {
    let context = read_film_project_publish_review_read_model_context(
        storage_paths,
        project_key,
        publish_id,
    )?;
    let operational_context = build_film_publish_review_operational_context(&context);
    let (worklist_summary, worklist_items) = build_film_publish_review_worklist(
        &context.timeline,
        &operational_context.current_round,
        &context.review_state_object,
    );
    let (readiness_summary, blockers, pending_reviewers, active_anchors) =
        build_film_publish_review_readiness(
            &operational_context.current_round,
            &context.review_state_object,
            &worklist_items,
            &operational_context.active_anchors,
        );
    let (backlog_summary, backlog_items) = build_film_publish_review_reviewer_backlog(
        &operational_context.current_round,
        &operational_context.decision_matrix_reviewers,
        &operational_context.reviewer_coverage_reviewers,
    );
    let (reviewer_attention_summary, reviewer_attention_items) =
        build_film_publish_review_reviewer_attention(
            &operational_context.current_round,
            &context.review_state_object,
            &operational_context.reviewer_coverage_reviewers,
        );
    let (stale_decisions_summary, stale_decision_items) = build_film_publish_review_stale_decisions(
        &operational_context.current_round,
        &operational_context.decision_matrix_reviewers,
        &operational_context.reviewer_coverage_reviewers,
        &operational_context.active_anchors,
    );
    let (anchors_summary, anchors) = build_film_publish_review_anchor_responsibility(
        &operational_context.current_round,
        &operational_context.reviewer_coverage_reviewers,
        &operational_context.active_anchors,
    );
    let (summary, signals) = build_film_publish_review_operations_dashboard_summary_and_signals(
        &context.review_state_object,
        &operational_context.current_round,
        &readiness_summary,
        &blockers,
        &backlog_summary,
        &backlog_items,
        &reviewer_attention_summary,
        &reviewer_attention_items,
        &stale_decisions_summary,
        &stale_decision_items,
        &anchors_summary,
        &anchors,
    );

    Ok(json!({
        "publish": context.publish,
        "reviewState": context.review_state,
        "currentRound": operational_context.current_round,
        "summary": summary,
        "decisionMatrix": {
            "summary": operational_context.decision_matrix_summary,
        },
        "reviewerCoverage": {
            "summary": operational_context.reviewer_coverage_summary,
        },
        "worklist": {
            "summary": worklist_summary,
        },
        "readiness": {
            "summary": readiness_summary,
            "blockers": blockers,
            "pendingReviewers": pending_reviewers,
            "activeAnchors": active_anchors,
        },
        "backlog": {
            "summary": backlog_summary,
            "items": backlog_items,
        },
        "reviewerAttention": {
            "summary": reviewer_attention_summary,
            "items": reviewer_attention_items,
        },
        "staleDecisions": {
            "summary": stale_decisions_summary,
            "items": stale_decision_items,
        },
        "anchors": {
            "summary": anchors_summary,
            "anchors": anchors,
        },
        "signals": signals,
    }))
}

