fn read_film_project_publish_review_read_model_context(
    storage_paths: &AppStoragePaths,
    project_key: &str,
    publish_id: &str,
) -> ServerResult<FilmPublishReviewReadModelContext> {
    let snapshot = require_film_project_publish_snapshot(storage_paths, project_key, publish_id)?;
    let publish = snapshot.record.clone();
    let record_object = require_object(snapshot.record, "FILM_PUBLISH_INVALID")?;
    let publish_kind = read_map_text(&record_object, "publishKind")
        .unwrap_or_else(|| "storyboard-review".to_string());
    let published_at_ms =
        read_map_i64(&record_object, "publishedAtMs").unwrap_or_else(current_time_millis);
    let review_state = read_film_publish_review_state(
        &snapshot.publish_root,
        publish_id,
        &publish_kind,
        published_at_ms,
    )?;
    let review_state_object =
        require_object(review_state.clone(), "FILM_PUBLISH_REVIEW_STATE_INVALID")?;
    let (timeline, rounds) =
        build_film_publish_review_timeline_and_rounds(publish_id, &review_state_object);

    Ok(FilmPublishReviewReadModelContext {
        publish,
        review_state,
        review_state_object,
        timeline,
        rounds,
    })
}

fn build_film_publish_review_timeline_and_rounds(
    publish_id: &str,
    review_state: &Map<String, Value>,
) -> (Vec<Value>, Vec<Value>) {
    let mut events = Vec::<FilmPublishReviewTimelineEventRecord>::new();

    for submission in review_state
        .get("submissions")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_object)
    {
        let Some(event_id) = read_map_text(submission, "submissionId") else {
            continue;
        };
        let occurred_at = read_map_i64(submission, "createdAt").unwrap_or_default();
        let actor = submission
            .get("actor")
            .filter(|value| value.is_object())
            .cloned()
            .unwrap_or(Value::Null);
        events.push(FilmPublishReviewTimelineEventRecord {
            event_id,
            event_type: "submission".to_string(),
            occurred_at,
            actor,
            submission: Value::Object(submission.clone()),
            assignment: Value::Null,
            comment: Value::Null,
            consensus: Value::Null,
            decision: Value::Null,
            status_after: "pending".to_string(),
            round_number: 0,
        });
    }

    for assignment in review_state
        .get("assignments")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_object)
    {
        let Some(event_id) = read_map_text(assignment, "assignmentId") else {
            continue;
        };
        let occurred_at = read_map_i64(assignment, "updatedAt")
            .or_else(|| read_map_i64(assignment, "assignedAt"))
            .unwrap_or_default();
        events.push(FilmPublishReviewTimelineEventRecord {
            event_id,
            event_type: "assignment".to_string(),
            occurred_at,
            actor: Value::Null,
            submission: Value::Null,
            assignment: Value::Object(assignment.clone()),
            comment: Value::Null,
            consensus: Value::Null,
            decision: Value::Null,
            status_after: "pending".to_string(),
            round_number: 0,
        });
    }

    for comment in review_state
        .get("comments")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_object)
    {
        let Some(comment_id) = read_map_text(comment, "commentId") else {
            continue;
        };
        let occurred_at = read_map_i64(comment, "createdAt").unwrap_or_default();
        let actor = comment
            .get("actor")
            .filter(|value| value.is_object())
            .cloned()
            .unwrap_or(Value::Null);
        let comment_value = Value::Object(comment.clone());
        events.push(FilmPublishReviewTimelineEventRecord {
            event_id: comment_id.clone(),
            event_type: "comment".to_string(),
            occurred_at,
            actor,
            submission: Value::Null,
            assignment: Value::Null,
            comment: comment_value.clone(),
            consensus: Value::Null,
            decision: Value::Null,
            status_after: "pending".to_string(),
            round_number: 0,
        });

        if comment
            .get("resolved")
            .and_then(Value::as_bool)
            .unwrap_or(false)
        {
            let resolved_at = read_map_i64(comment, "resolvedAt").unwrap_or_default();
            let resolved_by = comment
                .get("resolvedBy")
                .filter(|value| value.is_object())
                .cloned()
                .unwrap_or(Value::Null);
            events.push(FilmPublishReviewTimelineEventRecord {
                event_id: format!("{comment_id}:resolved"),
                event_type: "comment-resolved".to_string(),
                occurred_at: resolved_at,
                actor: resolved_by,
                submission: Value::Null,
                assignment: Value::Null,
                comment: comment_value,
                consensus: Value::Null,
                decision: Value::Null,
                status_after: "pending".to_string(),
                round_number: 0,
            });
        }
    }

    for consensus in review_state
        .get("consensuses")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_object)
    {
        let Some(event_id) = read_map_text(consensus, "consensusId") else {
            continue;
        };
        let occurred_at = read_map_i64(consensus, "createdAt").unwrap_or_default();
        let actor = consensus
            .get("actor")
            .filter(|value| value.is_object())
            .cloned()
            .unwrap_or(Value::Null);
        events.push(FilmPublishReviewTimelineEventRecord {
            event_id,
            event_type: "consensus".to_string(),
            occurred_at,
            actor,
            submission: Value::Null,
            assignment: Value::Null,
            comment: Value::Null,
            consensus: Value::Object(consensus.clone()),
            decision: Value::Null,
            status_after: "pending".to_string(),
            round_number: 0,
        });
    }

    for decision in review_state
        .get("decisions")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_object)
    {
        let Some(event_id) = read_map_text(decision, "decisionId") else {
            continue;
        };
        let occurred_at = read_map_i64(decision, "createdAt").unwrap_or_default();
        let actor = decision
            .get("actor")
            .filter(|value| value.is_object())
            .cloned()
            .unwrap_or(Value::Null);
        events.push(FilmPublishReviewTimelineEventRecord {
            event_id,
            event_type: "decision".to_string(),
            occurred_at,
            actor,
            submission: Value::Null,
            assignment: Value::Null,
            comment: Value::Null,
            consensus: Value::Null,
            decision: Value::Object(decision.clone()),
            status_after: "pending".to_string(),
            round_number: 0,
        });
    }

    events.sort_by(|left, right| {
        left.occurred_at
            .cmp(&right.occurred_at)
            .then_with(|| {
                film_publish_review_timeline_event_type_priority(&left.event_type).cmp(
                    &film_publish_review_timeline_event_type_priority(&right.event_type),
                )
            })
            .then_with(|| left.event_id.cmp(&right.event_id))
    });

    let mut status = "pending".to_string();
    for event in events.iter_mut() {
        match event.event_type.as_str() {
            "submission" => {
                status = "pending".to_string();
            }
            "decision" => {
                if let Some(decision) = event.decision.as_object() {
                    match normalize_film_publish_review_decision_action(read_map_text(
                        decision, "action",
                    ))
                    .as_deref()
                    {
                        Some("approved") => status = "approved".to_string(),
                        Some("changes-requested") => status = "changes-requested".to_string(),
                        Some("reopened") => status = "pending".to_string(),
                        _ => {}
                    }
                }
            }
            _ => {}
        }
        event.status_after = status.clone();
    }

    let mut markers = Vec::<FilmPublishReviewRoundStartMarker>::new();
    for (event_index, event) in events.iter().enumerate() {
        match event.event_type.as_str() {
            "submission" => {
                let submission_kind = event.submission.as_object().and_then(|submission| {
                    Some(normalize_film_publish_review_submission_kind(
                        read_map_text(submission, "kind"),
                    ))
                });
                markers.push(FilmPublishReviewRoundStartMarker {
                    start_reason: "submission".to_string(),
                    start_event_id: Some(event.event_id.clone()),
                    started_at: event.occurred_at,
                    started_by: event.actor.clone(),
                    submission_kind,
                    event_index: Some(event_index),
                });
            }
            "decision" => {
                let action = event.decision.as_object().and_then(|decision| {
                    normalize_film_publish_review_decision_action(read_map_text(decision, "action"))
                });
                if action.as_deref() == Some("reopened") {
                    markers.push(FilmPublishReviewRoundStartMarker {
                        start_reason: "reopened".to_string(),
                        start_event_id: Some(event.event_id.clone()),
                        started_at: event.occurred_at,
                        started_by: event.actor.clone(),
                        submission_kind: None,
                        event_index: Some(event_index),
                    });
                }
            }
            _ => {}
        }
    }

    let review_created_at = read_map_i64(review_state, "createdAt").unwrap_or_default();
    if markers.is_empty()
        || markers
            .first()
            .and_then(|marker| marker.event_index)
            .unwrap_or(events.len())
            > 0
    {
        markers.insert(
            0,
            FilmPublishReviewRoundStartMarker {
                start_reason: "published".to_string(),
                start_event_id: None,
                started_at: review_created_at,
                started_by: Value::Null,
                submission_kind: None,
                event_index: None,
            },
        );
    }

    let fallback_status =
        normalize_film_publish_review_status(read_map_text(review_state, "status"));
    let fallback_latest_activity_at = read_map_i64(review_state, "updatedAt")
        .unwrap_or_else(|| read_map_i64(review_state, "createdAt").unwrap_or_default());
    let summary_object = review_state
        .get("summary")
        .and_then(Value::as_object)
        .cloned()
        .unwrap_or_default();
    let fallback_last_decision_at = read_map_i64(&summary_object, "lastDecisionAt");
    let fallback_last_decision_action = normalize_film_publish_review_decision_action(
        read_map_text(&summary_object, "lastDecisionAction"),
    );

    let mut rounds = Vec::new();
    for (round_index, marker) in markers.iter().enumerate() {
        let round_number = round_index + 1;
        let start_index = marker.event_index.unwrap_or(0);
        let end_index = markers
            .get(round_index + 1)
            .and_then(|next| next.event_index)
            .unwrap_or(events.len());
        let mut latest_activity_at = marker.started_at;
        let mut round_status = "pending".to_string();
        let mut closed_at = None;
        let mut last_decision_at = None;
        let mut last_decision_action = None;
        let mut submission_count = 0usize;
        let mut assignment_count = 0usize;
        let mut comment_count = 0usize;
        let mut resolved_comment_count = 0usize;
        let mut consensus_count = 0usize;
        let mut decision_count = 0usize;
        let mut round_events = Vec::new();

        for event in events[start_index..end_index].iter_mut() {
            event.round_number = round_number;
            latest_activity_at = latest_activity_at.max(event.occurred_at);
            round_status = event.status_after.clone();
            match event.event_type.as_str() {
                "submission" => submission_count += 1,
                "assignment" => assignment_count += 1,
                "comment" => comment_count += 1,
                "comment-resolved" => resolved_comment_count += 1,
                "consensus" => consensus_count += 1,
                "decision" => {
                    decision_count += 1;
                    let action = event.decision.as_object().and_then(|decision| {
                        normalize_film_publish_review_decision_action(read_map_text(
                            decision, "action",
                        ))
                    });
                    last_decision_at = Some(event.occurred_at);
                    last_decision_action = action.clone();
                    if matches!(
                        action.as_deref(),
                        Some("approved") | Some("changes-requested")
                    ) {
                        closed_at = Some(event.occurred_at);
                    }
                }
                _ => {}
            }
            round_events.push(build_film_publish_review_timeline_event_value(event));
        }

        if round_events.is_empty() && round_index + 1 == markers.len() {
            round_status = fallback_status.clone();
            latest_activity_at = latest_activity_at.max(fallback_latest_activity_at);
            last_decision_at = fallback_last_decision_at;
            last_decision_action = fallback_last_decision_action.clone();
            if matches!(
                last_decision_action.as_deref(),
                Some("approved") | Some("changes-requested")
            ) {
                closed_at = last_decision_at;
            }
        }

        let event_count = round_events.len();
        rounds.push(json!({
            "roundId": format!("{publish_id}:review-round-{round_number}"),
            "roundNumber": round_number,
            "startReason": marker.start_reason.clone(),
            "startEventId": marker.start_event_id.clone(),
            "startedAt": marker.started_at,
            "startedBy": marker.started_by.clone(),
            "latestActivityAt": latest_activity_at,
            "closedAt": closed_at,
            "status": round_status,
            "submissionKind": marker.submission_kind.clone(),
            "lastDecisionAt": last_decision_at,
            "lastDecisionAction": last_decision_action,
            "summary": {
                "eventCount": event_count,
                "submissionCount": submission_count,
                "assignmentCount": assignment_count,
                "commentCount": comment_count,
                "resolvedCommentCount": resolved_comment_count,
                "consensusCount": consensus_count,
                "decisionCount": decision_count,
            },
            "events": round_events,
        }));
    }

    let timeline = events
        .iter()
        .map(build_film_publish_review_timeline_event_value)
        .collect::<Vec<_>>();

    (timeline, rounds)
}

fn film_publish_review_timeline_event_type_priority(event_type: &str) -> usize {
    match event_type {
        "submission" => 0,
        "assignment" => 1,
        "comment" => 2,
        "comment-resolved" => 3,
        "consensus" => 4,
        "decision" => 5,
        _ => 6,
    }
}

fn build_film_publish_review_timeline_event_value(
    event: &FilmPublishReviewTimelineEventRecord,
) -> Value {
    json!({
        "eventId": event.event_id.clone(),
        "eventType": event.event_type.clone(),
        "occurredAt": event.occurred_at,
        "roundNumber": event.round_number,
        "actor": event.actor.clone(),
        "statusAfter": event.status_after.clone(),
        "submission": event.submission.clone(),
        "assignment": event.assignment.clone(),
        "comment": event.comment.clone(),
        "consensus": event.consensus.clone(),
        "decision": event.decision.clone(),
    })
}

fn build_film_publish_review_anchor_groups(
    timeline: &[Value],
    review_state: &Map<String, Value>,
) -> Vec<Value> {
    let comments = review_state
        .get("comments")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let comments_by_id = comments
        .iter()
        .filter_map(Value::as_object)
        .filter_map(|comment| {
            read_map_text(comment, "commentId").map(|comment_id| (comment_id, comment.clone()))
        })
        .collect::<BTreeMap<_, _>>();
    let comment_round_numbers = build_film_publish_review_comment_round_numbers_map(timeline);
    let mut anchor_groups = BTreeMap::<String, (Value, Vec<Value>)>::new();

    for comment in comments {
        let Some(comment_object) = comment.as_object() else {
            continue;
        };
        let anchor_value = comment_object
            .get("anchor")
            .filter(|value| value.is_object())
            .cloned()
            .unwrap_or(Value::Null);
        let anchor_key = build_film_publish_review_anchor_group_key(&anchor_value);
        let anchor_entry = anchor_groups
            .entry(anchor_key)
            .or_insert_with(|| (anchor_value.clone(), Vec::new()));
        if anchor_entry.0.is_null() && anchor_value.is_object() {
            anchor_entry.0 = anchor_value;
        }
        anchor_entry.1.push(Value::Object(comment_object.clone()));
    }

    let mut results = anchor_groups
        .into_iter()
        .map(|(anchor_id, (anchor, group_comments))| {
            let mut threads = BTreeMap::<String, Vec<Value>>::new();
            for comment in group_comments {
                let root_comment_id = comment
                    .as_object()
                    .and_then(|comment| read_map_text(comment, "commentId"))
                    .map(|comment_id| {
                        resolve_film_publish_review_root_comment_id(&comment_id, &comments_by_id)
                    })
                    .unwrap_or_else(|| next_film_entity_key("film-publish-review-thread"));
                threads.entry(root_comment_id).or_default().push(comment);
            }

            let mut round_numbers_by_anchor = BTreeSet::new();
            let mut thread_values = threads
                .into_iter()
                .map(|(root_comment_id, mut thread_comments)| {
                    thread_comments.sort_by(|left, right| {
                        film_publish_review_comment_created_at(left)
                            .cmp(&film_publish_review_comment_created_at(right))
                            .then_with(|| {
                                film_publish_review_comment_id(left)
                                    .cmp(&film_publish_review_comment_id(right))
                            })
                    });

                    let comment_count = thread_comments.len();
                    let resolved_comment_count = thread_comments
                        .iter()
                        .filter(|comment| film_publish_review_comment_is_resolved(comment))
                        .count();
                    let open_comment_count = comment_count.saturating_sub(resolved_comment_count);
                    let latest_activity_at = thread_comments
                        .iter()
                        .map(film_publish_review_comment_latest_activity_at)
                        .max()
                        .unwrap_or_default();
                    let latest_open_comment_at = thread_comments
                        .iter()
                        .filter(|comment| !film_publish_review_comment_is_resolved(comment))
                        .map(film_publish_review_comment_latest_activity_at)
                        .max();
                    let mut round_numbers = thread_comments
                        .iter()
                        .filter_map(|comment| {
                            comment
                                .as_object()
                                .and_then(|comment| read_map_text(comment, "commentId"))
                        })
                        .filter_map(|comment_id| comment_round_numbers.get(&comment_id))
                        .flat_map(|numbers| numbers.iter().copied())
                        .collect::<BTreeSet<_>>();
                    if round_numbers.is_empty() {
                        round_numbers.insert(1);
                    }
                    round_numbers_by_anchor.extend(round_numbers.iter().copied());

                    json!({
                        "threadId": format!("thread:{root_comment_id}"),
                        "rootCommentId": root_comment_id,
                        "commentCount": comment_count,
                        "openCommentCount": open_comment_count,
                        "resolvedCommentCount": resolved_comment_count,
                        "latestActivityAt": latest_activity_at,
                        "latestOpenCommentAt": latest_open_comment_at,
                        "roundNumbers": round_numbers.into_iter().collect::<Vec<_>>(),
                        "comments": thread_comments,
                    })
                })
                .collect::<Vec<_>>();

            thread_values.sort_by(|left, right| {
                film_publish_review_anchor_thread_open_comment_count(right)
                    .cmp(&film_publish_review_anchor_thread_open_comment_count(left))
                    .then_with(|| {
                        film_publish_review_anchor_thread_latest_activity_at(right)
                            .cmp(&film_publish_review_anchor_thread_latest_activity_at(left))
                    })
                    .then_with(|| {
                        film_publish_review_anchor_thread_root_comment_id(left)
                            .cmp(&film_publish_review_anchor_thread_root_comment_id(right))
                    })
            });

            let thread_count = thread_values.len();
            let open_thread_count = thread_values
                .iter()
                .filter(|thread| film_publish_review_anchor_thread_open_comment_count(thread) > 0)
                .count();
            let comment_count = thread_values
                .iter()
                .map(film_publish_review_anchor_thread_comment_count)
                .sum::<usize>();
            let resolved_comment_count = thread_values
                .iter()
                .map(film_publish_review_anchor_thread_resolved_comment_count)
                .sum::<usize>();
            let open_comment_count = comment_count.saturating_sub(resolved_comment_count);
            let latest_activity_at = thread_values
                .iter()
                .map(film_publish_review_anchor_thread_latest_activity_at)
                .max()
                .unwrap_or_default();
            let latest_open_comment_at = thread_values
                .iter()
                .filter(|thread| film_publish_review_anchor_thread_open_comment_count(thread) > 0)
                .filter_map(film_publish_review_anchor_thread_latest_open_comment_at)
                .max();
            let round_numbers = if round_numbers_by_anchor.is_empty() {
                vec![1usize]
            } else {
                round_numbers_by_anchor.into_iter().collect::<Vec<_>>()
            };

            json!({
                "anchorId": anchor_id,
                "anchor": anchor,
                "threadCount": thread_count,
                "openThreadCount": open_thread_count,
                "commentCount": comment_count,
                "openCommentCount": open_comment_count,
                "resolvedCommentCount": resolved_comment_count,
                "latestActivityAt": latest_activity_at,
                "latestOpenCommentAt": latest_open_comment_at,
                "roundNumbers": round_numbers,
                "threads": thread_values,
            })
        })
        .collect::<Vec<_>>();

    results.sort_by(|left, right| {
        film_publish_review_anchor_group_open_comment_count(right)
            .cmp(&film_publish_review_anchor_group_open_comment_count(left))
            .then_with(|| {
                film_publish_review_anchor_group_latest_activity_at(right)
                    .cmp(&film_publish_review_anchor_group_latest_activity_at(left))
            })
            .then_with(|| {
                film_publish_review_anchor_group_id(left)
                    .cmp(&film_publish_review_anchor_group_id(right))
            })
    });

    results
}

fn build_film_publish_review_worklist(
    timeline: &[Value],
    current_round: &Value,
    review_state: &Map<String, Value>,
) -> (Value, Vec<Value>) {
    let assignments = review_state
        .get("assignments")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let comments = review_state
        .get("comments")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let current_round_number = current_round
        .as_object()
        .and_then(|round| read_map_i64(round, "roundNumber"))
        .map(|value| value.max(1) as usize);
    let current_round_started_at = current_round
        .as_object()
        .and_then(|round| read_map_i64(round, "startedAt"))
        .unwrap_or_else(|| film_publish_review_current_round_started_at(review_state));
    let open_comment_count = review_state
        .get("summary")
        .and_then(Value::as_object)
        .and_then(|summary| read_map_i64(summary, "openCommentCount"))
        .unwrap_or_default()
        .max(0) as usize;
    let review_state_status =
        normalize_film_publish_review_status(read_map_text(review_state, "status"));
    let reviewer_decisions =
        build_film_publish_review_reviewer_decisions_by_key(review_state, current_round_started_at);
    let comment_round_numbers = build_film_publish_review_comment_round_numbers_map(timeline);

    let mut items = assignments
        .into_iter()
        .filter_map(|assignment| {
            let assignment_object = assignment.as_object()?;
            let reviewer = assignment_object
                .get("reviewer")
                .filter(|value| value.is_object())
                .cloned()
                .unwrap_or(Value::Null);
            let reviewer_key = reviewer
                .as_object()
                .and_then(build_film_publish_review_actor_match_key)?;
            let reviewer_decision = reviewer_decisions
                .get(&reviewer_key)
                .and_then(|decisions| decisions.last())
                .cloned();
            let completed = reviewer_decision.is_some();
            let authored_comments = comments
                .iter()
                .filter_map(Value::as_object)
                .filter(|comment| {
                    comment
                        .get("actor")
                        .and_then(Value::as_object)
                        .and_then(build_film_publish_review_actor_match_key)
                        .as_deref()
                        == Some(reviewer_key.as_str())
                })
                .cloned()
                .collect::<Vec<_>>();
            let authored_comment_count = authored_comments.len();
            let resolved_authored_comment_count = authored_comments
                .iter()
                .filter(|comment| {
                    comment
                        .get("resolved")
                        .and_then(Value::as_bool)
                        .unwrap_or(false)
                })
                .count();
            let open_authored_comment_count =
                authored_comment_count.saturating_sub(resolved_authored_comment_count);
            let latest_comment_activity_at = authored_comments
                .iter()
                .map(|comment| {
                    comment
                        .get("commentId")
                        .and_then(Value::as_str)
                        .and_then(|comment_id| comment_round_numbers.get(comment_id))
                        .map(|_| {
                            read_map_i64(comment, "updatedAt")
                                .or_else(|| read_map_i64(comment, "createdAt"))
                                .unwrap_or_default()
                        })
                        .unwrap_or_else(|| {
                            read_map_i64(comment, "updatedAt")
                                .or_else(|| read_map_i64(comment, "createdAt"))
                                .unwrap_or_default()
                        })
                })
                .max()
                .unwrap_or_default();
            let assignment_updated_at = read_map_i64(assignment_object, "updatedAt")
                .or_else(|| read_map_i64(assignment_object, "assignedAt"))
                .unwrap_or_default();
            let last_decision_at = reviewer_decision
                .as_ref()
                .and_then(|decision| read_map_i64(decision, "createdAt"));
            let last_decision_action = reviewer_decision.as_ref().and_then(|decision| {
                normalize_film_publish_review_decision_action(read_map_text(decision, "action"))
                    .filter(|action| action != "reopened")
            });
            let latest_activity_at = assignment_updated_at
                .max(latest_comment_activity_at)
                .max(last_decision_at.unwrap_or_default());
            let required = assignment_object
                .get("required")
                .and_then(Value::as_bool)
                .unwrap_or(true);

            Some(json!({
                "reviewerKey": reviewer_key,
                "reviewer": reviewer,
                "assignment": Value::Object(assignment_object.clone()),
                "currentRoundNumber": current_round_number,
                "status": if completed { "completed" } else { "pending" },
                "completed": completed,
                "required": required,
                "needsAttention": (!completed && required) || open_authored_comment_count > 0,
                "authoredCommentCount": authored_comment_count,
                "openAuthoredCommentCount": open_authored_comment_count,
                "resolvedAuthoredCommentCount": resolved_authored_comment_count,
                "lastDecisionAt": last_decision_at,
                "lastDecisionAction": last_decision_action,
                "latestActivityAt": latest_activity_at,
            }))
        })
        .collect::<Vec<_>>();

    items.sort_by(|left, right| {
        film_publish_review_worklist_item_required(right)
            .cmp(&film_publish_review_worklist_item_required(left))
            .then_with(|| {
                film_publish_review_worklist_item_completed(left)
                    .cmp(&film_publish_review_worklist_item_completed(right))
            })
            .then_with(|| {
                film_publish_review_worklist_item_latest_activity_at(right)
                    .cmp(&film_publish_review_worklist_item_latest_activity_at(left))
            })
            .then_with(|| {
                film_publish_review_worklist_item_reviewer_key(left)
                    .cmp(&film_publish_review_worklist_item_reviewer_key(right))
            })
    });

    let assignment_count = items.len();
    let required_assignment_count = items
        .iter()
        .filter(|item| film_publish_review_worklist_item_required(item))
        .count();
    let completed_assignment_count = items
        .iter()
        .filter(|item| film_publish_review_worklist_item_completed(item))
        .count();
    let pending_assignment_count = items
        .iter()
        .filter(|item| {
            film_publish_review_worklist_item_required(item)
                && !film_publish_review_worklist_item_completed(item)
        })
        .count();

    (
        json!({
            "reviewerCount": assignment_count,
            "assignmentCount": assignment_count,
            "requiredAssignmentCount": required_assignment_count,
            "completedAssignmentCount": completed_assignment_count,
            "pendingAssignmentCount": pending_assignment_count,
            "openCommentCount": open_comment_count,
            "publishReadyForApproval": pending_assignment_count == 0
                && open_comment_count == 0
                && review_state_status == "pending",
            "currentRoundNumber": current_round_number,
        }),
        items,
    )
}

fn build_film_publish_review_readiness(
    current_round: &Value,
    review_state: &Map<String, Value>,
    worklist_items: &[Value],
    anchor_groups: &[Value],
) -> (Value, Vec<Value>, Vec<Value>, Vec<Value>) {
    let current_round_number = current_round
        .as_object()
        .and_then(|round| read_map_i64(round, "roundNumber"));
    let review_state_status =
        normalize_film_publish_review_status(read_map_text(review_state, "status"));
    let open_comment_count = review_state
        .get("summary")
        .and_then(Value::as_object)
        .and_then(|summary| read_map_i64(summary, "openCommentCount"))
        .unwrap_or_default()
        .max(0) as usize;
    let pending_reviewers = worklist_items
        .iter()
        .filter(|item| {
            film_publish_review_worklist_item_required(item)
                && !film_publish_review_worklist_item_completed(item)
        })
        .cloned()
        .collect::<Vec<_>>();
    let active_anchors = anchor_groups
        .iter()
        .filter(|group| film_publish_review_anchor_group_open_comment_count(group) > 0)
        .cloned()
        .collect::<Vec<_>>();
    let pending_required_assignment_count = pending_reviewers.len();
    let open_anchor_count = active_anchors.len();
    let open_thread_count = active_anchors
        .iter()
        .map(film_publish_review_anchor_group_open_thread_count)
        .sum::<usize>();
    let publish_ready_for_approval = review_state_status == "pending"
        && pending_required_assignment_count == 0
        && open_comment_count == 0;
    let mut blockers = Vec::new();

    if review_state_status != "pending" {
        blockers.push(json!({
            "code": "review-status-not-pending",
            "message": format!(
                "publish review status is {review_state_status} and is not pending approval"
            ),
            "count": 1,
        }));
    }
    if pending_required_assignment_count > 0 {
        blockers.push(json!({
            "code": "required-reviewers-pending",
            "message": format!(
                "{pending_required_assignment_count} required reviewer assignments are still pending in the current round"
            ),
            "count": pending_required_assignment_count,
        }));
    }
    if open_comment_count > 0 {
        blockers.push(json!({
            "code": "open-review-comments",
            "message": format!(
                "{open_comment_count} review comments remain unresolved across {open_anchor_count} anchor groups"
            ),
            "count": open_comment_count,
        }));
    }

    (
        json!({
            "status": review_state_status,
            "currentRoundNumber": current_round_number,
            "blockerCount": blockers.len(),
            "pendingRequiredAssignmentCount": pending_required_assignment_count,
            "openCommentCount": open_comment_count,
            "openThreadCount": open_thread_count,
            "openAnchorCount": open_anchor_count,
            "publishReadyForApproval": publish_ready_for_approval,
        }),
        blockers,
        pending_reviewers,
        active_anchors,
    )
}

fn build_film_publish_review_activity(
    current_round: &Value,
    review_state: &Map<String, Value>,
    timeline: &[Value],
) -> (Value, Vec<Value>) {
    let current_round_number = current_round
        .as_object()
        .and_then(|round| read_map_i64(round, "roundNumber"))
        .map(|value| value.max(1) as usize);
    let assignments = review_state
        .get("assignments")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let comments = review_state
        .get("comments")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let mut actors = BTreeMap::<String, FilmPublishReviewActivityAccumulator>::new();

    for assignment in assignments.iter().filter_map(Value::as_object) {
        let Some(reviewer) = assignment.get("reviewer").filter(|value| value.is_object()) else {
            continue;
        };
        let Some(reviewer_object) = reviewer.as_object() else {
            continue;
        };
        let Some(reviewer_key) = build_film_publish_review_actor_match_key(reviewer_object) else {
            continue;
        };
        let assignment_updated_at = read_map_i64(assignment, "updatedAt")
            .or_else(|| read_map_i64(assignment, "assignedAt"))
            .unwrap_or_default();
        let required = assignment
            .get("required")
            .and_then(Value::as_bool)
            .unwrap_or(true);
        let activity =
            ensure_film_publish_review_activity_actor(&mut actors, reviewer_key, reviewer.clone());
        activity.assigned_review_count += 1;
        if required {
            activity.required_review_count += 1;
        }
        activity.latest_activity_at = activity.latest_activity_at.max(assignment_updated_at);
    }

    for comment in comments.iter().filter_map(Value::as_object) {
        let Some(actor) = comment.get("actor").filter(|value| value.is_object()) else {
            continue;
        };
        let Some(actor_object) = actor.as_object() else {
            continue;
        };
        let Some(actor_key) = build_film_publish_review_actor_match_key(actor_object) else {
            continue;
        };
        let latest_activity_at = read_map_i64(comment, "updatedAt")
            .or_else(|| read_map_i64(comment, "createdAt"))
            .unwrap_or_default();
        let activity =
            ensure_film_publish_review_activity_actor(&mut actors, actor_key, actor.clone());
        activity.authored_comment_count += 1;
        if comment
            .get("resolved")
            .and_then(Value::as_bool)
            .unwrap_or(false)
        {
            activity.resolved_authored_comment_count += 1;
        } else {
            activity.open_authored_comment_count += 1;
        }
        activity.latest_activity_at = activity.latest_activity_at.max(latest_activity_at);
    }

    for event in timeline.iter().filter_map(Value::as_object) {
        let Some(actor) = event.get("actor").filter(|value| value.is_object()) else {
            continue;
        };
        let Some(actor_object) = actor.as_object() else {
            continue;
        };
        let Some(actor_key) = build_film_publish_review_actor_match_key(actor_object) else {
            continue;
        };
        let round_number = read_map_i64(event, "roundNumber")
            .map(|value| value.max(1) as usize)
            .unwrap_or(1);
        let occurred_at = read_map_i64(event, "occurredAt").unwrap_or_default();
        let activity =
            ensure_film_publish_review_activity_actor(&mut actors, actor_key, actor.clone());
        activity.round_numbers.insert(round_number);
        activity.authored_event_count += 1;
        if current_round_number == Some(round_number) {
            activity.current_round_participant = true;
            activity.current_round_authored_event_count += 1;
        }
        activity.latest_activity_at = activity.latest_activity_at.max(occurred_at);

        match read_map_text(event, "eventType").as_deref() {
            Some("submission") => activity.submission_count += 1,
            Some("comment-resolved") => activity.comment_resolution_count += 1,
            Some("consensus") => activity.consensus_count += 1,
            Some("decision") => {
                activity.decision_count += 1;
                let latest_decision_action = event
                    .get("decision")
                    .and_then(Value::as_object)
                    .and_then(|decision| {
                        normalize_film_publish_review_decision_action(read_map_text(
                            decision, "action",
                        ))
                    });
                if activity
                    .latest_decision_at
                    .map(|latest_decision_at| occurred_at >= latest_decision_at)
                    .unwrap_or(true)
                {
                    activity.latest_decision_at = Some(occurred_at);
                    activity.latest_decision_action = latest_decision_action;
                }
            }
            _ => {}
        }
    }

    let mut actor_values = actors
        .into_iter()
        .map(|(actor_key, activity)| {
            json!({
                "actorKey": actor_key,
                "actor": activity.actor,
                "assignedReviewCount": activity.assigned_review_count,
                "requiredReviewCount": activity.required_review_count,
                "currentRoundParticipant": activity.current_round_participant,
                "roundNumbers": activity.round_numbers.into_iter().collect::<Vec<_>>(),
                "authoredEventCount": activity.authored_event_count,
                "currentRoundAuthoredEventCount": activity.current_round_authored_event_count,
                "submissionCount": activity.submission_count,
                "authoredCommentCount": activity.authored_comment_count,
                "openAuthoredCommentCount": activity.open_authored_comment_count,
                "resolvedAuthoredCommentCount": activity.resolved_authored_comment_count,
                "commentResolutionCount": activity.comment_resolution_count,
                "consensusCount": activity.consensus_count,
                "decisionCount": activity.decision_count,
                "latestActivityAt": activity.latest_activity_at,
                "latestDecisionAt": activity.latest_decision_at,
                "latestDecisionAction": activity.latest_decision_action,
            })
        })
        .collect::<Vec<_>>();

    actor_values.sort_by(|left, right| {
        film_publish_review_activity_actor_required_review_count(right)
            .cmp(&film_publish_review_activity_actor_required_review_count(
                left,
            ))
            .then_with(|| {
                film_publish_review_activity_actor_current_round_participant(right)
                    .cmp(&film_publish_review_activity_actor_current_round_participant(left))
            })
            .then_with(|| {
                film_publish_review_activity_actor_authored_event_count(right).cmp(
                    &film_publish_review_activity_actor_authored_event_count(left),
                )
            })
            .then_with(|| {
                film_publish_review_activity_actor_latest_activity_at(right)
                    .cmp(&film_publish_review_activity_actor_latest_activity_at(left))
            })
            .then_with(|| {
                film_publish_review_activity_actor_key(left)
                    .cmp(&film_publish_review_activity_actor_key(right))
            })
    });

    let actor_count = actor_values.len();
    let reviewer_count = actor_values
        .iter()
        .filter(|actor| film_publish_review_activity_actor_assigned_review_count(actor) > 0)
        .count();
    let current_round_participant_count = actor_values
        .iter()
        .filter(|actor| film_publish_review_activity_actor_current_round_participant(actor))
        .count();
    let authored_event_count = actor_values
        .iter()
        .map(film_publish_review_activity_actor_authored_event_count)
        .sum::<usize>();
    let current_round_authored_event_count = actor_values
        .iter()
        .map(film_publish_review_activity_actor_current_round_authored_event_count)
        .sum::<usize>();
    let latest_activity_at = actor_values
        .iter()
        .map(film_publish_review_activity_actor_latest_activity_at)
        .max()
        .unwrap_or_default();

    (
        json!({
            "actorCount": actor_count,
            "reviewerCount": reviewer_count,
            "currentRoundParticipantCount": current_round_participant_count,
            "authoredEventCount": authored_event_count,
            "currentRoundAuthoredEventCount": current_round_authored_event_count,
            "latestActivityAt": latest_activity_at,
            "currentRoundNumber": current_round_number,
        }),
        actor_values,
    )
}

fn ensure_film_publish_review_activity_actor(
    actors: &mut BTreeMap<String, FilmPublishReviewActivityAccumulator>,
    actor_key: String,
    actor: Value,
) -> &mut FilmPublishReviewActivityAccumulator {
    actors
        .entry(actor_key)
        .or_insert_with(|| FilmPublishReviewActivityAccumulator {
            actor,
            assigned_review_count: 0,
            required_review_count: 0,
            current_round_participant: false,
            round_numbers: BTreeSet::new(),
            authored_event_count: 0,
            current_round_authored_event_count: 0,
            submission_count: 0,
            authored_comment_count: 0,
            open_authored_comment_count: 0,
            resolved_authored_comment_count: 0,
            comment_resolution_count: 0,
            consensus_count: 0,
            decision_count: 0,
            latest_activity_at: 0,
            latest_decision_at: None,
            latest_decision_action: None,
        })
}

fn build_film_publish_review_decision_matrix(
    current_round: &Value,
    rounds: &[Value],
    review_state: &Map<String, Value>,
    timeline: &[Value],
) -> (Value, Vec<Value>) {
    let current_round_number = current_round
        .as_object()
        .and_then(|round| read_map_i64(round, "roundNumber"))
        .map(|value| value.max(1) as usize);
    let review_state_status =
        normalize_film_publish_review_status(read_map_text(review_state, "status"));
    let open_comment_count = review_state
        .get("summary")
        .and_then(Value::as_object)
        .and_then(|summary| read_map_i64(summary, "openCommentCount"))
        .unwrap_or_default()
        .max(0) as usize;
    let assignments = review_state
        .get("assignments")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let comments = review_state
        .get("comments")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let comment_round_numbers =
        build_film_publish_review_comment_created_round_numbers_map(timeline);
    let mut round_numbers = rounds
        .iter()
        .filter_map(Value::as_object)
        .filter_map(|round| read_map_i64(round, "roundNumber"))
        .map(|value| value.max(1) as usize)
        .collect::<Vec<_>>();
    if round_numbers.is_empty() {
        round_numbers.push(current_round_number.unwrap_or(1));
    }
    round_numbers.sort_unstable();
    round_numbers.dedup();

    let mut reviewers = BTreeMap::<String, FilmPublishReviewDecisionMatrixRowAccumulator>::new();
    for assignment in assignments.iter().filter_map(Value::as_object) {
        let Some(reviewer) = assignment.get("reviewer").filter(|value| value.is_object()) else {
            continue;
        };
        let Some(reviewer_object) = reviewer.as_object() else {
            continue;
        };
        let Some(reviewer_key) = build_film_publish_review_actor_match_key(reviewer_object) else {
            continue;
        };
        let required = assignment
            .get("required")
            .and_then(Value::as_bool)
            .unwrap_or(true);
        let assignment_value = Value::Object(assignment.clone());
        let assignment_updated_at = read_map_i64(assignment, "updatedAt")
            .or_else(|| read_map_i64(assignment, "assignedAt"))
            .unwrap_or_default();

        reviewers
            .entry(reviewer_key)
            .and_modify(|row| {
                let existing_updated_at = row
                    .assignment
                    .as_object()
                    .and_then(|assignment| {
                        read_map_i64(assignment, "updatedAt")
                            .or_else(|| read_map_i64(assignment, "assignedAt"))
                    })
                    .unwrap_or_default();
                if assignment_updated_at >= existing_updated_at {
                    row.reviewer = reviewer.clone();
                    row.assignment = assignment_value.clone();
                    row.required = required;
                }
                row.latest_activity_at = row.latest_activity_at.max(assignment_updated_at);
            })
            .or_insert_with(|| FilmPublishReviewDecisionMatrixRowAccumulator {
                reviewer: reviewer.clone(),
                assignment: assignment_value,
                required,
                round_numbers: BTreeSet::new(),
                authored_event_count: 0,
                current_round_authored_event_count: 0,
                authored_comment_count: 0,
                open_authored_comment_count: 0,
                resolved_authored_comment_count: 0,
                current_round_participant: false,
                latest_activity_at: assignment_updated_at,
                latest_decision_at: None,
                latest_decision_action: None,
                latest_decision_round_number: None,
                latest_qualifying_decision_at: None,
                latest_qualifying_decision_action: None,
                latest_qualifying_decision_round_number: None,
                cells: BTreeMap::new(),
            });
    }

    for comment in comments.iter().filter_map(Value::as_object) {
        let Some(actor) = comment.get("actor").filter(|value| value.is_object()) else {
            continue;
        };
        let Some(actor_object) = actor.as_object() else {
            continue;
        };
        let Some(reviewer_key) = build_film_publish_review_actor_match_key(actor_object) else {
            continue;
        };
        let Some(row) = reviewers.get_mut(&reviewer_key) else {
            continue;
        };
        let comment_id = read_map_text(comment, "commentId");
        let mut comment_rounds = comment_id
            .as_ref()
            .and_then(|comment_id| comment_round_numbers.get(comment_id))
            .cloned()
            .unwrap_or_default();
        if comment_rounds.is_empty() {
            comment_rounds.insert(1);
        }
        let latest_activity_at = read_map_i64(comment, "updatedAt")
            .or_else(|| read_map_i64(comment, "createdAt"))
            .unwrap_or_default();
        let resolved = comment
            .get("resolved")
            .and_then(Value::as_bool)
            .unwrap_or(false);

        row.authored_comment_count += 1;
        if resolved {
            row.resolved_authored_comment_count += 1;
        } else {
            row.open_authored_comment_count += 1;
        }
        row.latest_activity_at = row.latest_activity_at.max(latest_activity_at);
        row.round_numbers.extend(comment_rounds.iter().copied());

        for round_number in comment_rounds {
            let cell = row.cells.entry(round_number).or_default();
            cell.authored_comment_count += 1;
            if resolved {
                cell.resolved_authored_comment_count += 1;
            } else {
                cell.open_authored_comment_count += 1;
            }
            cell.latest_activity_at = cell.latest_activity_at.max(latest_activity_at);
        }
    }

    for event in timeline.iter().filter_map(Value::as_object) {
        let Some(actor) = event.get("actor").filter(|value| value.is_object()) else {
            continue;
        };
        let Some(actor_object) = actor.as_object() else {
            continue;
        };
        let Some(reviewer_key) = build_film_publish_review_actor_match_key(actor_object) else {
            continue;
        };
        let Some(row) = reviewers.get_mut(&reviewer_key) else {
            continue;
        };
        let round_number = read_map_i64(event, "roundNumber")
            .map(|value| value.max(1) as usize)
            .unwrap_or(1);
        let occurred_at = read_map_i64(event, "occurredAt").unwrap_or_default();
        let cell = row.cells.entry(round_number).or_default();
        cell.participated = true;
        cell.authored_event_count += 1;
        cell.latest_activity_at = cell.latest_activity_at.max(occurred_at);
        row.round_numbers.insert(round_number);
        row.authored_event_count += 1;
        row.latest_activity_at = row.latest_activity_at.max(occurred_at);
        if current_round_number == Some(round_number) {
            row.current_round_participant = true;
            row.current_round_authored_event_count += 1;
        }

        if read_map_text(event, "eventType").as_deref() == Some("decision") {
            cell.decision_count += 1;
            let action = event
                .get("decision")
                .and_then(Value::as_object)
                .and_then(|decision| {
                    normalize_film_publish_review_decision_action(read_map_text(decision, "action"))
                });
            if cell
                .last_decision_at
                .map(|last_decision_at| occurred_at >= last_decision_at)
                .unwrap_or(true)
            {
                cell.last_decision_at = Some(occurred_at);
                cell.last_decision_action = action.clone();
            }
            if row
                .latest_decision_at
                .map(|latest_decision_at| occurred_at >= latest_decision_at)
                .unwrap_or(true)
            {
                row.latest_decision_at = Some(occurred_at);
                row.latest_decision_action = action.clone();
                row.latest_decision_round_number = Some(round_number);
            }
            if matches!(
                action.as_deref(),
                Some("approved") | Some("changes-requested")
            ) {
                cell.qualifying_decision_count += 1;
                if cell
                    .last_qualifying_decision_at
                    .map(|last_decision_at| occurred_at >= last_decision_at)
                    .unwrap_or(true)
                {
                    cell.last_qualifying_decision_at = Some(occurred_at);
                    cell.last_qualifying_decision_action = action.clone();
                }
                if row
                    .latest_qualifying_decision_at
                    .map(|latest_decision_at| occurred_at >= latest_decision_at)
                    .unwrap_or(true)
                {
                    row.latest_qualifying_decision_at = Some(occurred_at);
                    row.latest_qualifying_decision_action = action;
                    row.latest_qualifying_decision_round_number = Some(round_number);
                }
            }
        }
    }

    let mut reviewer_values = reviewers
        .into_iter()
        .map(|(reviewer_key, mut row)| {
            let cells = round_numbers
                .iter()
                .copied()
                .map(|round_number| {
                    let cell = row.cells.remove(&round_number).unwrap_or_default();
                    let status = match cell.last_qualifying_decision_action.as_deref() {
                        Some("approved") => "approved".to_string(),
                        Some("changes-requested") => "changes-requested".to_string(),
                        _ => "pending".to_string(),
                    };

                    json!({
                        "roundNumber": round_number,
                        "status": status,
                        "participated": cell.participated,
                        "completed": cell.qualifying_decision_count > 0,
                        "authoredEventCount": cell.authored_event_count,
                        "authoredCommentCount": cell.authored_comment_count,
                        "openAuthoredCommentCount": cell.open_authored_comment_count,
                        "resolvedAuthoredCommentCount": cell.resolved_authored_comment_count,
                        "decisionCount": cell.decision_count,
                        "qualifyingDecisionCount": cell.qualifying_decision_count,
                        "latestActivityAt": cell.latest_activity_at,
                        "lastDecisionAt": cell.last_decision_at,
                        "lastDecisionAction": cell.last_decision_action,
                        "lastQualifyingDecisionAt": cell.last_qualifying_decision_at,
                        "lastQualifyingDecisionAction": cell.last_qualifying_decision_action,
                    })
                })
                .collect::<Vec<_>>();
            let current_round_cell = current_round_number
                .and_then(|round_number| {
                    cells.iter().find(|cell| {
                        cell.as_object()
                            .and_then(|cell| read_map_i64(cell, "roundNumber"))
                            .map(|value| value.max(1) as usize)
                            == Some(round_number)
                    })
                })
                .cloned();
            let current_round_completed = current_round_cell
                .as_ref()
                .and_then(|cell| cell.as_object())
                .and_then(|cell| cell.get("completed"))
                .and_then(Value::as_bool)
                .unwrap_or(false);
            let current_round_status = current_round_cell
                .as_ref()
                .and_then(Value::as_object)
                .and_then(|cell| read_map_text(cell, "status"))
                .unwrap_or_else(|| "pending".to_string());
            let current_round_authored_comment_count = current_round_cell
                .as_ref()
                .and_then(Value::as_object)
                .and_then(|cell| read_map_i64(cell, "authoredCommentCount"))
                .unwrap_or_default()
                .max(0) as usize;
            let current_round_open_authored_comment_count = current_round_cell
                .as_ref()
                .and_then(Value::as_object)
                .and_then(|cell| read_map_i64(cell, "openAuthoredCommentCount"))
                .unwrap_or_default()
                .max(0) as usize;
            let current_round_resolved_authored_comment_count = current_round_cell
                .as_ref()
                .and_then(Value::as_object)
                .and_then(|cell| read_map_i64(cell, "resolvedAuthoredCommentCount"))
                .unwrap_or_default()
                .max(0) as usize;
            let current_round_decision_count = current_round_cell
                .as_ref()
                .and_then(Value::as_object)
                .and_then(|cell| read_map_i64(cell, "decisionCount"))
                .unwrap_or_default()
                .max(0) as usize;
            let current_round_qualifying_decision_count = current_round_cell
                .as_ref()
                .and_then(Value::as_object)
                .and_then(|cell| read_map_i64(cell, "qualifyingDecisionCount"))
                .unwrap_or_default()
                .max(0) as usize;
            let mut blocker_codes = Vec::<String>::new();
            if row.required && !current_round_completed {
                blocker_codes.push("required-review-pending".to_string());
            }
            if current_round_open_authored_comment_count > 0 {
                blocker_codes.push("open-authored-comments".to_string());
            }
            let round_numbers = row.round_numbers.into_iter().collect::<Vec<_>>();

            json!({
                "reviewerKey": reviewer_key,
                "reviewer": row.reviewer,
                "assignment": row.assignment,
                "required": row.required,
                "status": current_round_status,
                "completed": current_round_completed,
                "currentRoundParticipant": row.current_round_participant,
                "roundNumbers": round_numbers,
                "authoredEventCount": row.authored_event_count,
                "currentRoundAuthoredEventCount": row.current_round_authored_event_count,
                "authoredCommentCount": row.authored_comment_count,
                "openAuthoredCommentCount": row.open_authored_comment_count,
                "resolvedAuthoredCommentCount": row.resolved_authored_comment_count,
                "currentRoundAuthoredCommentCount": current_round_authored_comment_count,
                "currentRoundOpenAuthoredCommentCount": current_round_open_authored_comment_count,
                "currentRoundResolvedAuthoredCommentCount": current_round_resolved_authored_comment_count,
                "currentRoundDecisionCount": current_round_decision_count,
                "currentRoundQualifyingDecisionCount": current_round_qualifying_decision_count,
                "needsAttention": !blocker_codes.is_empty(),
                "blockerCodes": blocker_codes,
                "latestActivityAt": row.latest_activity_at,
                "latestDecisionAt": row.latest_decision_at,
                "latestDecisionAction": row.latest_decision_action,
                "latestDecisionRoundNumber": row.latest_decision_round_number,
                "latestQualifyingDecisionAt": row.latest_qualifying_decision_at,
                "latestQualifyingDecisionAction": row.latest_qualifying_decision_action,
                "latestQualifyingDecisionRoundNumber": row.latest_qualifying_decision_round_number,
                "cells": cells,
            })
        })
        .collect::<Vec<_>>();

    reviewer_values.sort_by(|left, right| {
        film_publish_review_decision_matrix_reviewer_required(right)
            .cmp(&film_publish_review_decision_matrix_reviewer_required(left))
            .then_with(|| {
                film_publish_review_decision_matrix_reviewer_completed(left).cmp(
                    &film_publish_review_decision_matrix_reviewer_completed(right),
                )
            })
            .then_with(|| {
                film_publish_review_decision_matrix_reviewer_latest_activity_at(right)
                    .cmp(&film_publish_review_decision_matrix_reviewer_latest_activity_at(left))
            })
            .then_with(|| {
                film_publish_review_decision_matrix_reviewer_key(left)
                    .cmp(&film_publish_review_decision_matrix_reviewer_key(right))
            })
    });

    let reviewer_count = reviewer_values.len();
    let required_reviewer_count = reviewer_values
        .iter()
        .filter(|reviewer| film_publish_review_decision_matrix_reviewer_required(reviewer))
        .count();
    let completed_reviewer_count = reviewer_values
        .iter()
        .filter(|reviewer| film_publish_review_decision_matrix_reviewer_completed(reviewer))
        .count();
    let completed_required_reviewer_count = reviewer_values
        .iter()
        .filter(|reviewer| {
            film_publish_review_decision_matrix_reviewer_required(reviewer)
                && film_publish_review_decision_matrix_reviewer_completed(reviewer)
        })
        .count();
    let pending_required_reviewer_count =
        required_reviewer_count.saturating_sub(completed_required_reviewer_count);
    let current_round_participant_count = reviewer_values
        .iter()
        .filter(|reviewer| {
            film_publish_review_decision_matrix_reviewer_current_round_participant(reviewer)
        })
        .count();
    let publish_ready_for_approval = review_state_status == "pending"
        && pending_required_reviewer_count == 0
        && open_comment_count == 0;

    (
        json!({
            "roundCount": round_numbers.len(),
            "reviewerCount": reviewer_count,
            "requiredReviewerCount": required_reviewer_count,
            "optionalReviewerCount": reviewer_count.saturating_sub(required_reviewer_count),
            "completedReviewerCount": completed_reviewer_count,
            "pendingReviewerCount": reviewer_count.saturating_sub(completed_reviewer_count),
            "completedRequiredReviewerCount": completed_required_reviewer_count,
            "pendingRequiredReviewerCount": pending_required_reviewer_count,
            "currentRoundParticipantCount": current_round_participant_count,
            "openCommentCount": open_comment_count,
            "publishReadyForApproval": publish_ready_for_approval,
            "currentRoundNumber": current_round_number,
        }),
        reviewer_values,
    )
}

fn build_film_publish_review_reviewer_coverage(
    current_round: &Value,
    review_state: &Map<String, Value>,
    decision_matrix_reviewers: &[Value],
    active_anchors: &[Value],
) -> (Value, Vec<Value>) {
    let current_round_number = current_round
        .as_object()
        .and_then(|round| read_map_i64(round, "roundNumber"));
    let review_state_status =
        normalize_film_publish_review_status(read_map_text(review_state, "status"));
    let open_thread_count = active_anchors
        .iter()
        .map(film_publish_review_anchor_group_open_thread_count)
        .sum::<usize>();
    let open_anchor_count = active_anchors.len();
    let mut open_thread_exposure_by_reviewer = BTreeMap::<String, usize>::new();
    let mut open_anchor_exposure_by_reviewer = BTreeMap::<String, usize>::new();

    for group in active_anchors.iter().filter_map(Value::as_object) {
        let mut anchor_contributors = BTreeSet::<String>::new();
        for thread in group
            .get("threads")
            .and_then(Value::as_array)
            .into_iter()
            .flatten()
        {
            if film_publish_review_anchor_thread_open_comment_count(thread) == 0 {
                continue;
            }
            let mut thread_contributors = BTreeSet::<String>::new();
            for comment in thread
                .as_object()
                .and_then(|thread| thread.get("comments"))
                .and_then(Value::as_array)
                .into_iter()
                .flatten()
            {
                let Some(actor_key) = comment
                    .as_object()
                    .and_then(|comment| comment.get("actor"))
                    .and_then(Value::as_object)
                    .and_then(build_film_publish_review_actor_match_key)
                else {
                    continue;
                };
                thread_contributors.insert(actor_key.clone());
                anchor_contributors.insert(actor_key);
            }
            for reviewer_key in thread_contributors {
                *open_thread_exposure_by_reviewer
                    .entry(reviewer_key)
                    .or_default() += 1;
            }
        }
        for reviewer_key in anchor_contributors {
            *open_anchor_exposure_by_reviewer
                .entry(reviewer_key)
                .or_default() += 1;
        }
    }

    let mut reviewers = decision_matrix_reviewers
        .iter()
        .filter_map(Value::as_object)
        .filter_map(|reviewer| {
            let reviewer_key = read_map_text(reviewer, "reviewerKey")?;
            let required = reviewer
                .get("required")
                .and_then(Value::as_bool)
                .unwrap_or(true);
            let completed = reviewer
                .get("completed")
                .and_then(Value::as_bool)
                .unwrap_or(false);
            let current_round_participant = reviewer
                .get("currentRoundParticipant")
                .and_then(Value::as_bool)
                .unwrap_or(false);
            let current_round_authored_event_count = read_map_i64(
                reviewer,
                "currentRoundAuthoredEventCount",
            )
            .unwrap_or_default()
            .max(0) as usize;
            let current_round_open_authored_comment_count = read_map_i64(
                reviewer,
                "currentRoundOpenAuthoredCommentCount",
            )
            .unwrap_or_default()
            .max(0) as usize;
            let open_thread_exposure_count = open_thread_exposure_by_reviewer
                .get(&reviewer_key)
                .copied()
                .unwrap_or_default();
            let open_anchor_exposure_count = open_anchor_exposure_by_reviewer
                .get(&reviewer_key)
                .copied()
                .unwrap_or_default();
            let coverage_status = if completed {
                "covered".to_string()
            } else if current_round_participant
                || current_round_authored_event_count > 0
                || open_thread_exposure_count > 0
            {
                "in-progress".to_string()
            } else {
                "uncovered".to_string()
            };
            let needs_attention = (required && !completed)
                || current_round_open_authored_comment_count > 0
                || open_thread_exposure_count > 0;

            Some(json!({
                "reviewerKey": reviewer_key,
                "reviewer": reviewer.get("reviewer").cloned().unwrap_or(Value::Null),
                "assignment": reviewer.get("assignment").cloned().unwrap_or(Value::Null),
                "required": required,
                "coverageStatus": coverage_status,
                "currentRoundStatus": normalize_film_publish_review_status(read_map_text(reviewer, "status")),
                "completed": completed,
                "currentRoundParticipant": current_round_participant,
                "roundNumbers": reviewer
                    .get("roundNumbers")
                    .cloned()
                    .unwrap_or_else(|| Value::Array(Vec::new())),
                "authoredEventCount": read_map_i64(reviewer, "authoredEventCount").unwrap_or_default(),
                "currentRoundAuthoredEventCount": read_map_i64(
                    reviewer,
                    "currentRoundAuthoredEventCount",
                )
                .unwrap_or_default(),
                "authoredCommentCount": read_map_i64(reviewer, "authoredCommentCount")
                    .unwrap_or_default(),
                "openAuthoredCommentCount": read_map_i64(reviewer, "openAuthoredCommentCount")
                    .unwrap_or_default(),
                "resolvedAuthoredCommentCount": read_map_i64(
                    reviewer,
                    "resolvedAuthoredCommentCount",
                )
                .unwrap_or_default(),
                "openThreadExposureCount": open_thread_exposure_count,
                "openAnchorExposureCount": open_anchor_exposure_count,
                "needsAttention": needs_attention,
                "latestActivityAt": read_map_i64(reviewer, "latestActivityAt").unwrap_or_default(),
                "latestDecisionAt": reviewer.get("latestDecisionAt").cloned().unwrap_or(Value::Null),
                "latestDecisionAction": reviewer
                    .get("latestDecisionAction")
                    .cloned()
                    .unwrap_or(Value::Null),
            }))
        })
        .collect::<Vec<_>>();

    reviewers.sort_by(|left, right| {
        film_publish_review_reviewer_coverage_required(right)
            .cmp(&film_publish_review_reviewer_coverage_required(left))
            .then_with(|| {
                film_publish_review_reviewer_coverage_status_priority(left).cmp(
                    &film_publish_review_reviewer_coverage_status_priority(right),
                )
            })
            .then_with(|| {
                film_publish_review_reviewer_coverage_latest_activity_at(right).cmp(
                    &film_publish_review_reviewer_coverage_latest_activity_at(left),
                )
            })
            .then_with(|| {
                film_publish_review_reviewer_coverage_key(left)
                    .cmp(&film_publish_review_reviewer_coverage_key(right))
            })
    });

    let reviewer_count = reviewers.len();
    let required_reviewer_count = reviewers
        .iter()
        .filter(|reviewer| film_publish_review_reviewer_coverage_required(reviewer))
        .count();
    let covered_reviewer_count = reviewers
        .iter()
        .filter(|reviewer| {
            film_publish_review_reviewer_coverage_status(reviewer).as_deref() == Some("covered")
        })
        .count();
    let in_progress_reviewer_count = reviewers
        .iter()
        .filter(|reviewer| {
            film_publish_review_reviewer_coverage_status(reviewer).as_deref() == Some("in-progress")
        })
        .count();
    let uncovered_reviewer_count = reviewer_count
        .saturating_sub(covered_reviewer_count)
        .saturating_sub(in_progress_reviewer_count);
    let pending_required_reviewer_count = reviewers
        .iter()
        .filter(|reviewer| {
            film_publish_review_reviewer_coverage_required(reviewer)
                && !film_publish_review_reviewer_coverage_completed(reviewer)
        })
        .count();
    let current_round_participant_count = reviewers
        .iter()
        .filter(|reviewer| {
            film_publish_review_reviewer_coverage_current_round_participant(reviewer)
        })
        .count();
    let reviewers_with_open_thread_exposure_count = reviewers
        .iter()
        .filter(|reviewer| {
            film_publish_review_reviewer_coverage_open_thread_exposure_count(reviewer) > 0
        })
        .count();
    let reviewers_with_open_anchor_exposure_count = reviewers
        .iter()
        .filter(|reviewer| {
            film_publish_review_reviewer_coverage_open_anchor_exposure_count(reviewer) > 0
        })
        .count();
    let publish_ready_for_approval = review_state_status == "pending"
        && pending_required_reviewer_count == 0
        && open_thread_count == 0;

    (
        json!({
            "reviewerCount": reviewer_count,
            "requiredReviewerCount": required_reviewer_count,
            "optionalReviewerCount": reviewer_count.saturating_sub(required_reviewer_count),
            "coveredReviewerCount": covered_reviewer_count,
            "inProgressReviewerCount": in_progress_reviewer_count,
            "uncoveredReviewerCount": uncovered_reviewer_count,
            "pendingRequiredReviewerCount": pending_required_reviewer_count,
            "currentRoundParticipantCount": current_round_participant_count,
            "reviewersWithOpenThreadExposureCount": reviewers_with_open_thread_exposure_count,
            "reviewersWithOpenAnchorExposureCount": reviewers_with_open_anchor_exposure_count,
            "openThreadCount": open_thread_count,
            "openAnchorCount": open_anchor_count,
            "publishReadyForApproval": publish_ready_for_approval,
            "currentRoundNumber": current_round_number,
        }),
        reviewers,
    )
}

fn build_film_publish_review_operational_context(
    context: &FilmPublishReviewReadModelContext,
) -> FilmPublishReviewOperationalContext {
    let current_round = context.rounds.last().cloned().unwrap_or(Value::Null);
    let (decision_matrix_summary, decision_matrix_reviewers) =
        build_film_publish_review_decision_matrix(
            &current_round,
            &context.rounds,
            &context.review_state_object,
            &context.timeline,
        );
    let active_anchors =
        build_film_publish_review_anchor_groups(&context.timeline, &context.review_state_object)
            .into_iter()
            .filter(|group| film_publish_review_anchor_group_open_comment_count(group) > 0)
            .collect::<Vec<_>>();
    let (reviewer_coverage_summary, reviewer_coverage_reviewers) =
        build_film_publish_review_reviewer_coverage(
            &current_round,
            &context.review_state_object,
            &decision_matrix_reviewers,
            &active_anchors,
        );

    FilmPublishReviewOperationalContext {
        current_round,
        decision_matrix_summary,
        decision_matrix_reviewers,
        active_anchors,
        reviewer_coverage_summary,
        reviewer_coverage_reviewers,
    }
}

fn build_film_publish_review_reviewer_backlog(
    current_round: &Value,
    decision_matrix_reviewers: &[Value],
    reviewer_coverage_reviewers: &[Value],
) -> (Value, Vec<Value>) {
    let now_at = current_time_millis();
    let current_round_number = current_round
        .as_object()
        .and_then(|round| read_map_i64(round, "roundNumber"));
    let current_round_started_at = current_round
        .as_object()
        .and_then(|round| read_map_i64(round, "startedAt"));
    let coverage_reviewers_by_key = reviewer_coverage_reviewers
        .iter()
        .filter_map(Value::as_object)
        .filter_map(|reviewer| {
            read_map_text(reviewer, "reviewerKey")
                .map(|reviewer_key| (reviewer_key, reviewer.clone()))
        })
        .collect::<BTreeMap<_, _>>();

    let mut items = decision_matrix_reviewers
        .iter()
        .filter_map(Value::as_object)
        .filter_map(|reviewer| {
            let reviewer_key = read_map_text(reviewer, "reviewerKey")?;
            let required = reviewer
                .get("required")
                .and_then(Value::as_bool)
                .unwrap_or(true);
            let completed = reviewer
                .get("completed")
                .and_then(Value::as_bool)
                .unwrap_or(false);
            if completed {
                return None;
            }

            let assignment = reviewer.get("assignment").cloned().unwrap_or(Value::Null);
            let assignment_updated_at = assignment
                .as_object()
                .and_then(|assignment| {
                    read_map_i64(assignment, "updatedAt")
                        .or_else(|| read_map_i64(assignment, "assignedAt"))
                })
                .unwrap_or_default();
            let pending_since_at = current_round_started_at
                .unwrap_or(assignment_updated_at)
                .max(assignment_updated_at);
            let latest_activity_at = read_map_i64(reviewer, "latestActivityAt")
                .unwrap_or_default()
                .max(pending_since_at);
            let pending_age_ms = (now_at - pending_since_at).max(0);
            let idle_age_ms = (now_at - latest_activity_at).max(0);
            let current_round_participant = reviewer
                .get("currentRoundParticipant")
                .and_then(Value::as_bool)
                .unwrap_or(false);
            let coverage_reviewer = coverage_reviewers_by_key.get(&reviewer_key);
            let open_thread_exposure_count = coverage_reviewer
                .and_then(|reviewer| read_map_i64(reviewer, "openThreadExposureCount"))
                .unwrap_or_default()
                .max(0) as usize;
            let open_anchor_exposure_count = coverage_reviewer
                .and_then(|reviewer| read_map_i64(reviewer, "openAnchorExposureCount"))
                .unwrap_or_default()
                .max(0) as usize;
            let open_authored_comment_count = read_map_i64(reviewer, "openAuthoredCommentCount")
                .unwrap_or_default()
                .max(0) as usize;
            let overdue = required && pending_age_ms >= FILM_PUBLISH_REVIEW_BACKLOG_OVERDUE_AFTER_MS;
            let at_risk = required
                && !overdue
                && pending_age_ms >= FILM_PUBLISH_REVIEW_BACKLOG_AT_RISK_AFTER_MS;
            let participation_missing = required && !current_round_participant;
            let stalled = required && idle_age_ms >= FILM_PUBLISH_REVIEW_BACKLOG_IDLE_AFTER_MS;

            let mut reasons = Vec::<Value>::new();
            if overdue {
                reasons.push(json!({
                    "code": "required-review-overdue",
                    "message": "required reviewer has exceeded the canonical review SLA window",
                    "count": 1,
                }));
            } else if at_risk {
                reasons.push(json!({
                    "code": "required-review-at-risk",
                    "message": "required reviewer is approaching the canonical review SLA limit",
                    "count": 1,
                }));
            }
            if participation_missing {
                reasons.push(json!({
                    "code": "current-round-participation-missing",
                    "message": "required reviewer has not participated in the current review round",
                    "count": 1,
                }));
            }
            if stalled {
                reasons.push(json!({
                    "code": "stalled-reviewer",
                    "message": "reviewer backlog item has been idle beyond the canonical inactivity threshold",
                    "count": 1,
                }));
            }
            if open_thread_exposure_count > 0 {
                reasons.push(json!({
                    "code": "open-thread-exposure",
                    "message": format!(
                        "{open_thread_exposure_count} active review threads still require reviewer follow-up"
                    ),
                    "count": open_thread_exposure_count,
                }));
            }

            let backlog_level = if overdue {
                "overdue"
            } else if at_risk || participation_missing || stalled {
                "at-risk"
            } else {
                "queued"
            };

            Some(json!({
                "reviewerKey": reviewer_key,
                "reviewer": reviewer.get("reviewer").cloned().unwrap_or(Value::Null),
                "assignment": assignment,
                "required": required,
                "backlogLevel": backlog_level,
                "reasons": reasons,
                "coverageStatus": coverage_reviewer
                    .and_then(|reviewer| read_map_text(reviewer, "coverageStatus"))
                    .unwrap_or_else(|| "uncovered".to_string()),
                "currentRoundStatus": normalize_film_publish_review_status(read_map_text(
                    reviewer,
                    "status",
                )),
                "currentRoundParticipant": current_round_participant,
                "queueRank": 0,
                "pendingSinceAt": pending_since_at,
                "pendingAgeMs": pending_age_ms,
                "idleAgeMs": idle_age_ms,
                "openAuthoredCommentCount": open_authored_comment_count,
                "openThreadExposureCount": open_thread_exposure_count,
                "openAnchorExposureCount": open_anchor_exposure_count,
                "latestActivityAt": latest_activity_at,
                "latestDecisionAt": reviewer.get("latestDecisionAt").cloned().unwrap_or(Value::Null),
                "latestDecisionAction": reviewer
                    .get("latestDecisionAction")
                    .cloned()
                    .unwrap_or(Value::Null),
            }))
        })
        .collect::<Vec<_>>();

    items.sort_by(|left, right| {
        film_publish_review_reviewer_backlog_level_priority(left)
            .cmp(&film_publish_review_reviewer_backlog_level_priority(right))
            .then_with(|| {
                film_publish_review_reviewer_backlog_required(right)
                    .cmp(&film_publish_review_reviewer_backlog_required(left))
            })
            .then_with(|| {
                film_publish_review_reviewer_backlog_pending_age_ms(right)
                    .cmp(&film_publish_review_reviewer_backlog_pending_age_ms(left))
            })
            .then_with(|| {
                film_publish_review_reviewer_backlog_open_thread_exposure_count(right)
                    .cmp(&film_publish_review_reviewer_backlog_open_thread_exposure_count(left))
            })
            .then_with(|| {
                film_publish_review_reviewer_backlog_key(left)
                    .cmp(&film_publish_review_reviewer_backlog_key(right))
            })
    });

    for (index, item) in items.iter_mut().enumerate() {
        if let Some(item_object) = item.as_object_mut() {
            item_object.insert("queueRank".to_string(), json!(index + 1));
        }
    }

    let item_count = items.len();
    let overdue_count = items
        .iter()
        .filter(|item| {
            film_publish_review_reviewer_backlog_level(item).as_deref() == Some("overdue")
        })
        .count();
    let at_risk_count = items
        .iter()
        .filter(|item| {
            film_publish_review_reviewer_backlog_level(item).as_deref() == Some("at-risk")
        })
        .count();
    let queued_count = items
        .iter()
        .filter(|item| {
            film_publish_review_reviewer_backlog_level(item).as_deref() == Some("queued")
        })
        .count();
    let required_pending_count = items
        .iter()
        .filter(|item| film_publish_review_reviewer_backlog_required(item))
        .count();
    let reviewers_without_current_round_participation_count = items
        .iter()
        .filter(|item| {
            film_publish_review_reviewer_backlog_reason_codes(item)
                .iter()
                .any(|code| code == "current-round-participation-missing")
        })
        .count();
    let stalled_reviewer_count = items
        .iter()
        .filter(|item| {
            film_publish_review_reviewer_backlog_reason_codes(item)
                .iter()
                .any(|code| code == "stalled-reviewer")
        })
        .count();
    let reviewers_with_open_thread_exposure_count = items
        .iter()
        .filter(|item| film_publish_review_reviewer_backlog_open_thread_exposure_count(item) > 0)
        .count();

    (
        json!({
            "itemCount": item_count,
            "overdueCount": overdue_count,
            "atRiskCount": at_risk_count,
            "queuedCount": queued_count,
            "requiredPendingCount": required_pending_count,
            "optionalPendingCount": item_count.saturating_sub(required_pending_count),
            "reviewersWithoutCurrentRoundParticipationCount": reviewers_without_current_round_participation_count,
            "stalledReviewerCount": stalled_reviewer_count,
            "reviewersWithOpenThreadExposureCount": reviewers_with_open_thread_exposure_count,
            "currentRoundNumber": current_round_number,
            "currentRoundStartedAt": current_round_started_at,
            "nowAt": now_at,
            "policy": {
                "atRiskAfterMs": FILM_PUBLISH_REVIEW_BACKLOG_AT_RISK_AFTER_MS,
                "overdueAfterMs": FILM_PUBLISH_REVIEW_BACKLOG_OVERDUE_AFTER_MS,
                "idleAfterMs": FILM_PUBLISH_REVIEW_BACKLOG_IDLE_AFTER_MS,
            },
        }),
        items,
    )
}

fn build_film_publish_review_reviewer_attention(
    current_round: &Value,
    review_state: &Map<String, Value>,
    reviewer_coverage_reviewers: &[Value],
) -> (Value, Vec<Value>) {
    let current_round_number = current_round
        .as_object()
        .and_then(|round| read_map_i64(round, "roundNumber"));
    let review_state_status =
        normalize_film_publish_review_status(read_map_text(review_state, "status"));
    let open_comment_count = review_state
        .get("summary")
        .and_then(Value::as_object)
        .and_then(|summary| read_map_i64(summary, "openCommentCount"))
        .unwrap_or_default()
        .max(0) as usize;

    let mut items = reviewer_coverage_reviewers
        .iter()
        .filter_map(Value::as_object)
        .filter_map(|reviewer| {
            let reviewer_key = read_map_text(reviewer, "reviewerKey")?;
            let required = reviewer
                .get("required")
                .and_then(Value::as_bool)
                .unwrap_or(true);
            let completed = reviewer
                .get("completed")
                .and_then(Value::as_bool)
                .unwrap_or(false);
            let current_round_participant = reviewer
                .get("currentRoundParticipant")
                .and_then(Value::as_bool)
                .unwrap_or(false);
            let open_authored_comment_count = read_map_i64(reviewer, "openAuthoredCommentCount")
                .unwrap_or_default()
                .max(0) as usize;
            let open_thread_exposure_count =
                read_map_i64(reviewer, "openThreadExposureCount")
                    .unwrap_or_default()
                    .max(0) as usize;
            let open_anchor_exposure_count =
                read_map_i64(reviewer, "openAnchorExposureCount")
                    .unwrap_or_default()
                    .max(0) as usize;
            let required_review_pending = required && !completed;
            let current_round_participation_missing =
                required_review_pending && !current_round_participant;
            let mut reasons = Vec::<Value>::new();

            if required_review_pending {
                reasons.push(json!({
                    "code": "required-review-pending",
                    "message": "required reviewer has not completed a qualifying decision in the current round",
                    "count": 1,
                }));
            }
            if current_round_participation_missing {
                reasons.push(json!({
                    "code": "current-round-participation-missing",
                    "message": "required reviewer has not participated in the current round",
                    "count": 1,
                }));
            }
            if open_authored_comment_count > 0 {
                reasons.push(json!({
                    "code": "open-authored-comments",
                    "message": format!(
                        "{open_authored_comment_count} authored review comments remain unresolved"
                    ),
                    "count": open_authored_comment_count,
                }));
            }
            if open_thread_exposure_count > 0 {
                reasons.push(json!({
                    "code": "open-thread-exposure",
                    "message": format!(
                        "{open_thread_exposure_count} active review threads still involve this reviewer"
                    ),
                    "count": open_thread_exposure_count,
                }));
            }
            if reasons.is_empty() {
                return None;
            }
            let attention_level = if current_round_participation_missing {
                "critical"
            } else if required_review_pending {
                "high"
            } else if open_thread_exposure_count > 0 || open_authored_comment_count > 0 {
                "medium"
            } else {
                "low"
            };

            Some(json!({
                "reviewerKey": reviewer_key,
                "reviewer": reviewer.get("reviewer").cloned().unwrap_or(Value::Null),
                "assignment": reviewer.get("assignment").cloned().unwrap_or(Value::Null),
                "required": required,
                "attentionLevel": attention_level,
                "reasons": reasons,
                "coverageStatus": read_map_text(reviewer, "coverageStatus")
                    .unwrap_or_else(|| "uncovered".to_string()),
                "currentRoundStatus": normalize_film_publish_review_status(read_map_text(
                    reviewer,
                    "currentRoundStatus",
                )),
                "completed": completed,
                "currentRoundParticipant": current_round_participant,
                "openAuthoredCommentCount": open_authored_comment_count,
                "openThreadExposureCount": open_thread_exposure_count,
                "openAnchorExposureCount": open_anchor_exposure_count,
                "latestActivityAt": read_map_i64(reviewer, "latestActivityAt").unwrap_or_default(),
                "latestDecisionAt": reviewer.get("latestDecisionAt").cloned().unwrap_or(Value::Null),
                "latestDecisionAction": reviewer
                    .get("latestDecisionAction")
                    .cloned()
                    .unwrap_or(Value::Null),
            }))
        })
        .collect::<Vec<_>>();

    items.sort_by(|left, right| {
        film_publish_review_reviewer_attention_level_priority(left)
            .cmp(&film_publish_review_reviewer_attention_level_priority(
                right,
            ))
            .then_with(|| {
                film_publish_review_reviewer_attention_required(right)
                    .cmp(&film_publish_review_reviewer_attention_required(left))
            })
            .then_with(|| {
                film_publish_review_reviewer_attention_latest_activity_at(right).cmp(
                    &film_publish_review_reviewer_attention_latest_activity_at(left),
                )
            })
            .then_with(|| {
                film_publish_review_reviewer_attention_key(left)
                    .cmp(&film_publish_review_reviewer_attention_key(right))
            })
    });

    let item_count = items.len();
    let critical_count = items
        .iter()
        .filter(|item| {
            film_publish_review_reviewer_attention_level(item).as_deref() == Some("critical")
        })
        .count();
    let high_count = items
        .iter()
        .filter(|item| {
            film_publish_review_reviewer_attention_level(item).as_deref() == Some("high")
        })
        .count();
    let medium_count = items
        .iter()
        .filter(|item| {
            film_publish_review_reviewer_attention_level(item).as_deref() == Some("medium")
        })
        .count();
    let low_count = items
        .iter()
        .filter(|item| film_publish_review_reviewer_attention_level(item).as_deref() == Some("low"))
        .count();
    let required_pending_count = items
        .iter()
        .filter(|item| {
            film_publish_review_reviewer_attention_reason_codes(item)
                .iter()
                .any(|code| code == "required-review-pending")
        })
        .count();
    let current_round_participation_missing_count = items
        .iter()
        .filter(|item| {
            film_publish_review_reviewer_attention_reason_codes(item)
                .iter()
                .any(|code| code == "current-round-participation-missing")
        })
        .count();
    let reviewers_with_open_authored_comments_count = items
        .iter()
        .filter(|item| {
            film_publish_review_reviewer_attention_reason_codes(item)
                .iter()
                .any(|code| code == "open-authored-comments")
        })
        .count();
    let reviewers_with_open_thread_exposure_count = items
        .iter()
        .filter(|item| {
            film_publish_review_reviewer_attention_reason_codes(item)
                .iter()
                .any(|code| code == "open-thread-exposure")
        })
        .count();
    let publish_ready_for_approval =
        review_state_status == "pending" && required_pending_count == 0 && open_comment_count == 0;

    (
        json!({
            "itemCount": item_count,
            "criticalCount": critical_count,
            "highCount": high_count,
            "mediumCount": medium_count,
            "lowCount": low_count,
            "requiredPendingCount": required_pending_count,
            "currentRoundParticipationMissingCount": current_round_participation_missing_count,
            "reviewersWithOpenAuthoredCommentsCount": reviewers_with_open_authored_comments_count,
            "reviewersWithOpenThreadExposureCount": reviewers_with_open_thread_exposure_count,
            "publishReadyForApproval": publish_ready_for_approval,
            "currentRoundNumber": current_round_number,
        }),
        items,
    )
}

fn build_film_publish_review_stale_decisions(
    current_round: &Value,
    decision_matrix_reviewers: &[Value],
    reviewer_coverage_reviewers: &[Value],
    active_anchors: &[Value],
) -> (Value, Vec<Value>) {
    let now_at = current_time_millis();
    let current_round_number = current_round
        .as_object()
        .and_then(|round| read_map_i64(round, "roundNumber"));
    let current_round_started_at = current_round
        .as_object()
        .and_then(|round| read_map_i64(round, "startedAt"));
    let current_round_start_reason = current_round
        .as_object()
        .and_then(|round| read_map_text(round, "startReason"));
    let coverage_reviewers_by_key = reviewer_coverage_reviewers
        .iter()
        .filter_map(Value::as_object)
        .filter_map(|reviewer| {
            read_map_text(reviewer, "reviewerKey")
                .map(|reviewer_key| (reviewer_key, reviewer.clone()))
        })
        .collect::<BTreeMap<_, _>>();
    let latest_qualifying_decision_at_by_reviewer = decision_matrix_reviewers
        .iter()
        .filter_map(Value::as_object)
        .filter_map(|reviewer| {
            let reviewer_key = read_map_text(reviewer, "reviewerKey")?;
            let latest_qualifying_decision_at =
                read_map_i64(reviewer, "latestQualifyingDecisionAt")?;
            Some((reviewer_key, latest_qualifying_decision_at))
        })
        .collect::<BTreeMap<_, _>>();
    let mut newer_open_thread_count_by_reviewer = BTreeMap::<String, usize>::new();
    let mut newer_open_comment_count_by_reviewer = BTreeMap::<String, usize>::new();
    let mut latest_newer_open_comment_at_by_reviewer = BTreeMap::<String, i64>::new();

    for group in active_anchors.iter().filter_map(Value::as_object) {
        for thread in group
            .get("threads")
            .and_then(Value::as_array)
            .into_iter()
            .flatten()
            .filter_map(Value::as_object)
        {
            let latest_open_comment_at =
                read_map_i64(thread, "latestOpenCommentAt").unwrap_or_default();
            if latest_open_comment_at <= 0 {
                continue;
            }

            let unresolved_comments = thread
                .get("comments")
                .and_then(Value::as_array)
                .into_iter()
                .flatten()
                .filter_map(Value::as_object)
                .filter(|comment| {
                    !comment
                        .get("resolved")
                        .and_then(Value::as_bool)
                        .unwrap_or(false)
                })
                .cloned()
                .collect::<Vec<_>>();
            if unresolved_comments.is_empty() {
                continue;
            }

            let thread_contributors = thread
                .get("comments")
                .and_then(Value::as_array)
                .into_iter()
                .flatten()
                .filter_map(Value::as_object)
                .filter_map(|comment| {
                    comment
                        .get("actor")
                        .and_then(Value::as_object)
                        .and_then(build_film_publish_review_actor_match_key)
                })
                .collect::<BTreeSet<_>>();

            for reviewer_key in thread_contributors {
                let Some(latest_qualifying_decision_at) = latest_qualifying_decision_at_by_reviewer
                    .get(&reviewer_key)
                    .copied()
                else {
                    continue;
                };
                if latest_open_comment_at <= latest_qualifying_decision_at {
                    continue;
                }

                *newer_open_thread_count_by_reviewer
                    .entry(reviewer_key.clone())
                    .or_default() += 1;

                let newer_open_comment_count = unresolved_comments
                    .iter()
                    .filter(|comment| {
                        read_map_i64(comment, "createdAt").unwrap_or_default()
                            > latest_qualifying_decision_at
                    })
                    .count();
                if newer_open_comment_count == 0 {
                    continue;
                }

                *newer_open_comment_count_by_reviewer
                    .entry(reviewer_key.clone())
                    .or_default() += newer_open_comment_count;

                if let Some(latest_newer_open_comment_at) = unresolved_comments
                    .iter()
                    .filter(|comment| {
                        read_map_i64(comment, "createdAt").unwrap_or_default()
                            > latest_qualifying_decision_at
                    })
                    .map(|comment| {
                        read_map_i64(comment, "updatedAt")
                            .or_else(|| read_map_i64(comment, "createdAt"))
                            .unwrap_or_default()
                    })
                    .max()
                {
                    latest_newer_open_comment_at_by_reviewer
                        .entry(reviewer_key)
                        .and_modify(|current| {
                            *current = (*current).max(latest_newer_open_comment_at);
                        })
                        .or_insert(latest_newer_open_comment_at);
                }
            }
        }
    }

    let mut items = decision_matrix_reviewers
        .iter()
        .filter_map(Value::as_object)
        .filter_map(|reviewer| {
            let reviewer_key = read_map_text(reviewer, "reviewerKey")?;
            let latest_qualifying_decision_at =
                read_map_i64(reviewer, "latestQualifyingDecisionAt")?;
            let current_round_participant = reviewer
                .get("currentRoundParticipant")
                .and_then(Value::as_bool)
                .unwrap_or(false);
            let required = reviewer
                .get("required")
                .and_then(Value::as_bool)
                .unwrap_or(true);
            let newer_open_thread_count = newer_open_thread_count_by_reviewer
                .get(&reviewer_key)
                .copied()
                .unwrap_or_default();
            let newer_open_comment_count = newer_open_comment_count_by_reviewer
                .get(&reviewer_key)
                .copied()
                .unwrap_or_default();
            let latest_newer_open_comment_at = latest_newer_open_comment_at_by_reviewer
                .get(&reviewer_key)
                .copied();
            let decision_precedes_current_round = current_round_started_at
                .map(|started_at| latest_qualifying_decision_at < started_at)
                .unwrap_or(false);
            let reopened_after_decision = decision_precedes_current_round
                && current_round_start_reason.as_deref() == Some("reopened");
            let current_round_participation_missing =
                decision_precedes_current_round && !current_round_participant;

            let mut reasons = Vec::<Value>::new();
            if decision_precedes_current_round {
                reasons.push(json!({
                    "code": "qualifying-decision-precedes-current-round",
                    "message": "reviewer's latest qualifying decision predates the current review round",
                    "count": 1,
                }));
            }
            if reopened_after_decision {
                reasons.push(json!({
                    "code": "reopened-after-qualifying-decision",
                    "message": "the current review round was reopened after the latest qualifying decision",
                    "count": 1,
                }));
            }
            if newer_open_thread_count > 0 {
                reasons.push(json!({
                    "code": "new-open-thread-after-decision",
                    "message": format!(
                        "{newer_open_thread_count} active review threads advanced after the latest qualifying decision"
                    ),
                    "count": newer_open_thread_count,
                }));
            }
            if newer_open_comment_count > 0 {
                reasons.push(json!({
                    "code": "new-open-comment-after-decision",
                    "message": format!(
                        "{newer_open_comment_count} unresolved review comments were added after the latest qualifying decision"
                    ),
                    "count": newer_open_comment_count,
                }));
            }
            if current_round_participation_missing {
                reasons.push(json!({
                    "code": "current-round-participation-missing",
                    "message": "reviewer has not participated in the current round since the stale decision boundary",
                    "count": 1,
                }));
            }
            if reasons.is_empty() {
                return None;
            }

            let staleness_level = if decision_precedes_current_round || reopened_after_decision {
                "critical"
            } else if newer_open_comment_count > 0 && required {
                "high"
            } else {
                "medium"
            };
            let stale_since_at = if decision_precedes_current_round {
                current_round_started_at.unwrap_or(latest_qualifying_decision_at)
            } else {
                latest_newer_open_comment_at.unwrap_or(latest_qualifying_decision_at)
            };
            let stale_age_ms = (now_at - stale_since_at).max(0);
            let coverage_reviewer = coverage_reviewers_by_key.get(&reviewer_key);

            Some(json!({
                "reviewerKey": reviewer_key,
                "reviewer": reviewer.get("reviewer").cloned().unwrap_or(Value::Null),
                "assignment": reviewer.get("assignment").cloned().unwrap_or(Value::Null),
                "required": required,
                "stalenessLevel": staleness_level,
                "reasons": reasons,
                "currentRoundParticipant": current_round_participant,
                "latestQualifyingDecisionAt": latest_qualifying_decision_at,
                "latestQualifyingDecisionAction": reviewer
                    .get("latestQualifyingDecisionAction")
                    .cloned()
                    .unwrap_or(Value::Null),
                "latestQualifyingDecisionRoundNumber": reviewer
                    .get("latestQualifyingDecisionRoundNumber")
                    .cloned()
                    .unwrap_or(Value::Null),
                "latestDecisionAt": reviewer.get("latestDecisionAt").cloned().unwrap_or(Value::Null),
                "latestDecisionAction": reviewer
                    .get("latestDecisionAction")
                    .cloned()
                    .unwrap_or(Value::Null),
                "staleSinceAt": stale_since_at,
                "staleAgeMs": stale_age_ms,
                "newerOpenThreadCount": newer_open_thread_count,
                "newerOpenCommentCount": newer_open_comment_count,
                "latestNewerOpenCommentAt": latest_newer_open_comment_at,
                "openThreadExposureCount": coverage_reviewer
                    .and_then(|reviewer| read_map_i64(reviewer, "openThreadExposureCount"))
                    .unwrap_or_default(),
                "openAnchorExposureCount": coverage_reviewer
                    .and_then(|reviewer| read_map_i64(reviewer, "openAnchorExposureCount"))
                    .unwrap_or_default(),
                "latestActivityAt": read_map_i64(reviewer, "latestActivityAt").unwrap_or_default(),
            }))
        })
        .collect::<Vec<_>>();

    items.sort_by(|left, right| {
        film_publish_review_stale_decision_level_priority(left)
            .cmp(&film_publish_review_stale_decision_level_priority(right))
            .then_with(|| {
                film_publish_review_stale_decision_required(right)
                    .cmp(&film_publish_review_stale_decision_required(left))
            })
            .then_with(|| {
                film_publish_review_stale_decision_age_ms(right)
                    .cmp(&film_publish_review_stale_decision_age_ms(left))
            })
            .then_with(|| {
                film_publish_review_stale_decision_newer_open_comment_count(right)
                    .cmp(&film_publish_review_stale_decision_newer_open_comment_count(left))
            })
            .then_with(|| {
                film_publish_review_stale_decision_key(left)
                    .cmp(&film_publish_review_stale_decision_key(right))
            })
    });

    let item_count = items.len();
    let critical_count = items
        .iter()
        .filter(|item| {
            film_publish_review_stale_decision_level(item).as_deref() == Some("critical")
        })
        .count();
    let high_count = items
        .iter()
        .filter(|item| film_publish_review_stale_decision_level(item).as_deref() == Some("high"))
        .count();
    let medium_count = items
        .iter()
        .filter(|item| film_publish_review_stale_decision_level(item).as_deref() == Some("medium"))
        .count();
    let previous_round_decision_count = items
        .iter()
        .filter(|item| {
            film_publish_review_stale_decision_reason_codes(item)
                .iter()
                .any(|code| code == "qualifying-decision-precedes-current-round")
        })
        .count();
    let reopened_after_decision_count = items
        .iter()
        .filter(|item| {
            film_publish_review_stale_decision_reason_codes(item)
                .iter()
                .any(|code| code == "reopened-after-qualifying-decision")
        })
        .count();
    let reviewers_with_new_open_thread_count = items
        .iter()
        .filter(|item| film_publish_review_stale_decision_newer_open_thread_count(item) > 0)
        .count();
    let reviewers_with_new_open_comment_count = items
        .iter()
        .filter(|item| film_publish_review_stale_decision_newer_open_comment_count(item) > 0)
        .count();
    let reviewers_without_current_round_participation_count = items
        .iter()
        .filter(|item| {
            film_publish_review_stale_decision_reason_codes(item)
                .iter()
                .any(|code| code == "current-round-participation-missing")
        })
        .count();

    (
        json!({
            "itemCount": item_count,
            "criticalCount": critical_count,
            "highCount": high_count,
            "mediumCount": medium_count,
            "previousRoundDecisionCount": previous_round_decision_count,
            "reopenedAfterDecisionCount": reopened_after_decision_count,
            "reviewersWithNewOpenThreadCount": reviewers_with_new_open_thread_count,
            "reviewersWithNewOpenCommentCount": reviewers_with_new_open_comment_count,
            "reviewersWithoutCurrentRoundParticipationCount": reviewers_without_current_round_participation_count,
            "currentRoundNumber": current_round_number,
            "currentRoundStartedAt": current_round_started_at,
            "currentRoundStartReason": current_round_start_reason,
            "nowAt": now_at,
        }),
        items,
    )
}

fn build_film_publish_review_anchor_responsibility(
    current_round: &Value,
    reviewer_coverage_reviewers: &[Value],
    active_anchors: &[Value],
) -> (Value, Vec<Value>) {
    let current_round_number = current_round
        .as_object()
        .and_then(|round| read_map_i64(round, "roundNumber"));
    let coverage_reviewers = reviewer_coverage_reviewers
        .iter()
        .filter_map(Value::as_object)
        .cloned()
        .collect::<Vec<_>>();

    let mut anchors = active_anchors
        .iter()
        .filter_map(Value::as_object)
        .map(|group| {
            let mut engaged_reviewer_keys = BTreeSet::<String>::new();
            let mut open_comment_count_by_reviewer = BTreeMap::<String, usize>::new();
            let mut latest_comment_at_by_reviewer = BTreeMap::<String, i64>::new();

            for comment in group
                .get("threads")
                .and_then(Value::as_array)
                .into_iter()
                .flatten()
                .filter_map(Value::as_object)
                .filter_map(|thread| thread.get("comments").and_then(Value::as_array))
                .flatten()
                .filter_map(Value::as_object)
            {
                let Some(reviewer_key) = comment
                    .get("actor")
                    .and_then(Value::as_object)
                    .and_then(build_film_publish_review_actor_match_key)
                else {
                    continue;
                };
                engaged_reviewer_keys.insert(reviewer_key.clone());
                let latest_comment_at = read_map_i64(comment, "updatedAt")
                    .or_else(|| read_map_i64(comment, "createdAt"))
                    .unwrap_or_default();
                latest_comment_at_by_reviewer
                    .entry(reviewer_key.clone())
                    .and_modify(|current| {
                        *current = (*current).max(latest_comment_at);
                    })
                    .or_insert(latest_comment_at);
                if !comment
                    .get("resolved")
                    .and_then(Value::as_bool)
                    .unwrap_or(false)
                {
                    *open_comment_count_by_reviewer.entry(reviewer_key).or_default() += 1;
                }
            }

            let mut reviewers = coverage_reviewers
                .iter()
                .filter_map(|reviewer| {
                    let reviewer_key = read_map_text(reviewer, "reviewerKey")?;
                    Some(json!({
                        "reviewerKey": reviewer_key,
                        "reviewer": reviewer.get("reviewer").cloned().unwrap_or(Value::Null),
                        "required": reviewer.get("required").and_then(Value::as_bool).unwrap_or(true),
                        "engaged": engaged_reviewer_keys.contains(
                            &read_map_text(reviewer, "reviewerKey").unwrap_or_default(),
                        ),
                        "completed": reviewer.get("completed").and_then(Value::as_bool).unwrap_or(false),
                        "currentRoundParticipant": reviewer
                            .get("currentRoundParticipant")
                            .and_then(Value::as_bool)
                            .unwrap_or(false),
                        "openCommentCount": open_comment_count_by_reviewer
                            .get(&read_map_text(reviewer, "reviewerKey").unwrap_or_default())
                            .copied()
                            .unwrap_or_default(),
                        "latestCommentAt": latest_comment_at_by_reviewer
                            .get(&read_map_text(reviewer, "reviewerKey").unwrap_or_default())
                            .copied(),
                    }))
                })
                .collect::<Vec<_>>();

            reviewers.sort_by(|left, right| {
                film_publish_review_anchor_responsibility_reviewer_required(right)
                    .cmp(&film_publish_review_anchor_responsibility_reviewer_required(left))
                    .then_with(|| {
                        film_publish_review_anchor_responsibility_reviewer_engaged(right)
                            .cmp(&film_publish_review_anchor_responsibility_reviewer_engaged(left))
                    })
                    .then_with(|| {
                        film_publish_review_anchor_responsibility_reviewer_latest_comment_at(right)
                            .cmp(
                                &film_publish_review_anchor_responsibility_reviewer_latest_comment_at(
                                    left,
                                ),
                            )
                    })
                    .then_with(|| {
                        film_publish_review_anchor_responsibility_reviewer_key(left)
                            .cmp(&film_publish_review_anchor_responsibility_reviewer_key(right))
                    })
            });

            let assigned_reviewer_count = reviewers.len();
            let required_reviewer_count = reviewers
                .iter()
                .filter(|reviewer| film_publish_review_anchor_responsibility_reviewer_required(reviewer))
                .count();
            let engaged_reviewer_count = reviewers
                .iter()
                .filter(|reviewer| film_publish_review_anchor_responsibility_reviewer_engaged(reviewer))
                .count();
            let engaged_required_reviewer_count = reviewers
                .iter()
                .filter(|reviewer| {
                    film_publish_review_anchor_responsibility_reviewer_required(reviewer)
                        && film_publish_review_anchor_responsibility_reviewer_engaged(reviewer)
                })
                .count();
            let completed_reviewer_count = reviewers
                .iter()
                .filter(|reviewer| {
                    film_publish_review_anchor_responsibility_reviewer_completed(reviewer)
                })
                .count();
            let completed_required_reviewer_count = reviewers
                .iter()
                .filter(|reviewer| {
                    film_publish_review_anchor_responsibility_reviewer_required(reviewer)
                        && film_publish_review_anchor_responsibility_reviewer_completed(reviewer)
                })
                .count();
            let pending_required_reviewer_count =
                required_reviewer_count.saturating_sub(engaged_required_reviewer_count);
            let coverage_status = if required_reviewer_count == 0 {
                if engaged_reviewer_count == 0 {
                    "unowned"
                } else {
                    "covered"
                }
            } else if engaged_required_reviewer_count == 0 {
                "unowned"
            } else if pending_required_reviewer_count > 0 {
                "partial"
            } else {
                "covered"
            };
            let open_thread_count = read_map_i64(group, "openThreadCount")
                .unwrap_or_default()
                .max(0) as usize;
            let open_comment_count = read_map_i64(group, "openCommentCount")
                .unwrap_or_default()
                .max(0) as usize;
            let escalation_level = match coverage_status {
                "unowned" => "critical",
                "partial" => "high",
                _ => {
                    if open_thread_count > 1 || open_comment_count > 1 {
                        "medium"
                    } else {
                        "low"
                    }
                }
            };

            json!({
                "anchorId": read_map_text(group, "anchorId").unwrap_or_default(),
                "anchor": group.get("anchor").cloned().unwrap_or(Value::Null),
                "threadCount": read_map_i64(group, "threadCount").unwrap_or_default(),
                "openThreadCount": open_thread_count,
                "commentCount": read_map_i64(group, "commentCount").unwrap_or_default(),
                "openCommentCount": open_comment_count,
                "latestActivityAt": read_map_i64(group, "latestActivityAt").unwrap_or_default(),
                "latestOpenCommentAt": read_map_i64(group, "latestOpenCommentAt"),
                "roundNumbers": group.get("roundNumbers").cloned().unwrap_or_else(|| json!([])),
                "coverageStatus": coverage_status,
                "escalationLevel": escalation_level,
                "assignedReviewerCount": assigned_reviewer_count,
                "requiredReviewerCount": required_reviewer_count,
                "engagedReviewerCount": engaged_reviewer_count,
                "engagedRequiredReviewerCount": engaged_required_reviewer_count,
                "completedReviewerCount": completed_reviewer_count,
                "completedRequiredReviewerCount": completed_required_reviewer_count,
                "pendingRequiredReviewerCount": pending_required_reviewer_count,
                "reviewers": reviewers,
            })
        })
        .collect::<Vec<_>>();

    anchors.sort_by(|left, right| {
        film_publish_review_anchor_responsibility_escalation_level_priority(left)
            .cmp(&film_publish_review_anchor_responsibility_escalation_level_priority(right))
            .then_with(|| {
                film_publish_review_anchor_responsibility_open_comment_count(right)
                    .cmp(&film_publish_review_anchor_responsibility_open_comment_count(left))
            })
            .then_with(|| {
                film_publish_review_anchor_responsibility_open_thread_count(right)
                    .cmp(&film_publish_review_anchor_responsibility_open_thread_count(left))
            })
            .then_with(|| {
                film_publish_review_anchor_responsibility_latest_open_comment_at(right)
                    .cmp(&film_publish_review_anchor_responsibility_latest_open_comment_at(left))
            })
            .then_with(|| {
                film_publish_review_anchor_responsibility_anchor_id(left)
                    .cmp(&film_publish_review_anchor_responsibility_anchor_id(right))
            })
    });

    let active_anchor_count = anchors.len();
    let critical_count = anchors
        .iter()
        .filter(|anchor| {
            film_publish_review_anchor_responsibility_escalation_level(anchor).as_deref()
                == Some("critical")
        })
        .count();
    let high_count = anchors
        .iter()
        .filter(|anchor| {
            film_publish_review_anchor_responsibility_escalation_level(anchor).as_deref()
                == Some("high")
        })
        .count();
    let medium_count = anchors
        .iter()
        .filter(|anchor| {
            film_publish_review_anchor_responsibility_escalation_level(anchor).as_deref()
                == Some("medium")
        })
        .count();
    let low_count = anchors
        .iter()
        .filter(|anchor| {
            film_publish_review_anchor_responsibility_escalation_level(anchor).as_deref()
                == Some("low")
        })
        .count();
    let unowned_anchor_count = anchors
        .iter()
        .filter(|anchor| {
            film_publish_review_anchor_responsibility_coverage_status(anchor).as_deref()
                == Some("unowned")
        })
        .count();
    let partial_anchor_count = anchors
        .iter()
        .filter(|anchor| {
            film_publish_review_anchor_responsibility_coverage_status(anchor).as_deref()
                == Some("partial")
        })
        .count();
    let covered_anchor_count = anchors
        .iter()
        .filter(|anchor| {
            film_publish_review_anchor_responsibility_coverage_status(anchor).as_deref()
                == Some("covered")
        })
        .count();
    let open_thread_count = anchors
        .iter()
        .map(film_publish_review_anchor_responsibility_open_thread_count)
        .sum::<usize>();
    let open_comment_count = anchors
        .iter()
        .map(film_publish_review_anchor_responsibility_open_comment_count)
        .sum::<usize>();

    (
        json!({
            "activeAnchorCount": active_anchor_count,
            "criticalCount": critical_count,
            "highCount": high_count,
            "mediumCount": medium_count,
            "lowCount": low_count,
            "unownedAnchorCount": unowned_anchor_count,
            "partialAnchorCount": partial_anchor_count,
            "coveredAnchorCount": covered_anchor_count,
            "openThreadCount": open_thread_count,
            "openCommentCount": open_comment_count,
            "currentRoundNumber": current_round_number,
        }),
        anchors,
    )
}

#[allow(clippy::too_many_arguments)]
fn build_film_publish_review_operations_dashboard_summary_and_signals(
    review_state: &Map<String, Value>,
    current_round: &Value,
    readiness_summary: &Value,
    blockers: &[Value],
    backlog_summary: &Value,
    backlog_items: &[Value],
    reviewer_attention_summary: &Value,
    reviewer_attention_items: &[Value],
    stale_decisions_summary: &Value,
    stale_decision_items: &[Value],
    anchors_summary: &Value,
    anchors: &[Value],
) -> (Value, Vec<Value>) {
    let now_at = current_time_millis();
    let status = normalize_film_publish_review_status(read_map_text(review_state, "status"));
    let current_round_number = current_round
        .as_object()
        .and_then(|round| read_map_i64(round, "roundNumber"));
    let current_round_started_at = current_round
        .as_object()
        .and_then(|round| read_map_i64(round, "startedAt"));
    let current_round_elapsed_ms =
        current_round_started_at.map(|started_at| (now_at - started_at).max(0));
    let mut signals = Vec::<Value>::new();

    for blocker in blockers.iter().filter_map(Value::as_object) {
        let code =
            read_map_text(blocker, "code").unwrap_or_else(|| "readiness-blocker".to_string());
        let count = read_map_i64(blocker, "count").unwrap_or(1).max(1) as usize;
        let message = read_map_text(blocker, "message")
            .unwrap_or_else(|| "review readiness blocker detected".to_string());
        signals.push(build_film_publish_review_operations_signal(
            format!("readiness-blocker:{code}"),
            "readiness-blocker",
            map_film_publish_review_readiness_blocker_signal_severity(&code),
            map_film_publish_review_readiness_blocker_signal_title(&code),
            message,
            count,
            None,
            None,
            Some(code.clone()),
            vec![code],
            current_round_started_at,
        ));
    }

    for item in backlog_items {
        let reviewer_key = film_publish_review_reviewer_backlog_key(item);
        if reviewer_key.is_empty() {
            continue;
        }
        let backlog_level = film_publish_review_reviewer_backlog_level(item)
            .unwrap_or_else(|| "queued".to_string());
        let title = match backlog_level.as_str() {
            "overdue" => "Reviewer backlog overdue",
            "at-risk" => "Reviewer backlog at risk",
            _ => "Reviewer backlog queued",
        };
        let message = film_publish_review_item_first_reason_message(item)
            .unwrap_or_else(|| "reviewer has pending work in the current round".to_string());
        let count = film_publish_review_item_reason_max_count(item).max(1);
        signals.push(build_film_publish_review_operations_signal(
            format!("reviewer-backlog:{reviewer_key}"),
            "reviewer-backlog",
            map_film_publish_review_backlog_level_signal_severity(Some(backlog_level)),
            title.to_string(),
            message,
            count,
            Some(reviewer_key.clone()),
            None,
            None,
            film_publish_review_reviewer_backlog_reason_codes(item),
            Some(film_publish_review_reviewer_backlog_pending_since_at(item)),
        ));
    }

    for item in reviewer_attention_items {
        let reviewer_key = film_publish_review_reviewer_attention_key(item);
        if reviewer_key.is_empty() {
            continue;
        }
        let attention_level =
            film_publish_review_reviewer_attention_level(item).unwrap_or_else(|| "low".to_string());
        let message = film_publish_review_item_first_reason_message(item)
            .unwrap_or_else(|| "reviewer attention signal detected".to_string());
        let count = film_publish_review_item_reason_max_count(item).max(1);
        signals.push(build_film_publish_review_operations_signal(
            format!("reviewer-attention:{reviewer_key}"),
            "reviewer-attention",
            attention_level.clone(),
            "Reviewer attention required".to_string(),
            message,
            count,
            Some(reviewer_key),
            None,
            None,
            film_publish_review_reviewer_attention_reason_codes(item),
            Some(film_publish_review_reviewer_attention_latest_activity_at(
                item,
            )),
        ));
    }

    for item in stale_decision_items {
        let reviewer_key = film_publish_review_stale_decision_key(item);
        if reviewer_key.is_empty() {
            continue;
        }
        let staleness_level =
            film_publish_review_stale_decision_level(item).unwrap_or_else(|| "medium".to_string());
        let message = film_publish_review_item_first_reason_message(item)
            .unwrap_or_else(|| "reviewer decision is stale for the current round".to_string());
        let count = film_publish_review_item_reason_max_count(item).max(1);
        signals.push(build_film_publish_review_operations_signal(
            format!("stale-decision:{reviewer_key}"),
            "stale-decision",
            staleness_level.clone(),
            "Reviewer decision has drifted".to_string(),
            message,
            count,
            Some(reviewer_key),
            None,
            None,
            film_publish_review_stale_decision_reason_codes(item),
            Some(film_publish_review_stale_decision_latest_at(item)),
        ));
    }

    for anchor in anchors {
        let anchor_id = film_publish_review_anchor_responsibility_anchor_id(anchor);
        if anchor_id.is_empty() {
            continue;
        }
        let escalation_level = film_publish_review_anchor_responsibility_escalation_level(anchor)
            .unwrap_or_else(|| "low".to_string());
        let open_comment_count =
            film_publish_review_anchor_responsibility_open_comment_count(anchor);
        let open_thread_count = film_publish_review_anchor_responsibility_open_thread_count(anchor);
        let count = open_comment_count.max(open_thread_count).max(1);
        let message = format!(
            "{open_thread_count} open review threads and {open_comment_count} open comments remain on this anchor"
        );
        signals.push(build_film_publish_review_operations_signal(
            format!("anchor-escalation:{anchor_id}"),
            "anchor-escalation",
            escalation_level.clone(),
            "Anchor escalation requires follow-up".to_string(),
            message,
            count,
            None,
            Some(anchor_id),
            None,
            Vec::new(),
            Some(film_publish_review_anchor_responsibility_latest_open_comment_at(anchor)),
        ));
    }

    signals.sort_by(|left, right| {
        film_publish_review_operations_signal_severity_priority(left)
            .cmp(&film_publish_review_operations_signal_severity_priority(
                right,
            ))
            .then_with(|| {
                film_publish_review_operations_signal_count(right)
                    .cmp(&film_publish_review_operations_signal_count(left))
            })
            .then_with(|| {
                film_publish_review_operations_signal_latest_at(right)
                    .cmp(&film_publish_review_operations_signal_latest_at(left))
            })
            .then_with(|| {
                film_publish_review_operations_signal_id(left)
                    .cmp(&film_publish_review_operations_signal_id(right))
            })
    });

    let signal_count = signals.len();
    let critical_signal_count = signals
        .iter()
        .filter(|signal| {
            film_publish_review_operations_signal_severity(signal).as_deref() == Some("critical")
        })
        .count();
    let high_signal_count = signals
        .iter()
        .filter(|signal| {
            film_publish_review_operations_signal_severity(signal).as_deref() == Some("high")
        })
        .count();
    let medium_signal_count = signals
        .iter()
        .filter(|signal| {
            film_publish_review_operations_signal_severity(signal).as_deref() == Some("medium")
        })
        .count();
    let low_signal_count = signals
        .iter()
        .filter(|signal| {
            film_publish_review_operations_signal_severity(signal).as_deref() == Some("low")
        })
        .count();

    (
        json!({
            "status": status,
            "currentRoundNumber": current_round_number,
            "currentRoundStartedAt": current_round_started_at,
            "currentRoundElapsedMs": current_round_elapsed_ms,
            "publishReadyForApproval": readiness_summary
                .as_object()
                .and_then(|summary| summary.get("publishReadyForApproval"))
                .and_then(Value::as_bool)
                .unwrap_or(false),
            "blockerCount": blockers.len(),
            "signalCount": signal_count,
            "criticalSignalCount": critical_signal_count,
            "highSignalCount": high_signal_count,
            "mediumSignalCount": medium_signal_count,
            "lowSignalCount": low_signal_count,
            "pendingRequiredAssignmentCount": readiness_summary
                .as_object()
                .and_then(|summary| read_map_i64(summary, "pendingRequiredAssignmentCount"))
                .unwrap_or_default(),
            "overdueReviewerCount": backlog_summary
                .as_object()
                .and_then(|summary| read_map_i64(summary, "overdueCount"))
                .unwrap_or_default(),
            "atRiskReviewerCount": backlog_summary
                .as_object()
                .and_then(|summary| read_map_i64(summary, "atRiskCount"))
                .unwrap_or_default(),
            "criticalAttentionCount": reviewer_attention_summary
                .as_object()
                .and_then(|summary| read_map_i64(summary, "criticalCount"))
                .unwrap_or_default(),
            "staleDecisionCount": stale_decisions_summary
                .as_object()
                .and_then(|summary| read_map_i64(summary, "itemCount"))
                .unwrap_or_default(),
            "criticalStaleDecisionCount": stale_decisions_summary
                .as_object()
                .and_then(|summary| read_map_i64(summary, "criticalCount"))
                .unwrap_or_default(),
            "activeAnchorCount": anchors_summary
                .as_object()
                .and_then(|summary| read_map_i64(summary, "activeAnchorCount"))
                .unwrap_or_default(),
            "criticalAnchorCount": anchors_summary
                .as_object()
                .and_then(|summary| read_map_i64(summary, "criticalCount"))
                .unwrap_or_default(),
            "openThreadCount": readiness_summary
                .as_object()
                .and_then(|summary| read_map_i64(summary, "openThreadCount"))
                .unwrap_or_default(),
            "openCommentCount": readiness_summary
                .as_object()
                .and_then(|summary| read_map_i64(summary, "openCommentCount"))
                .unwrap_or_default(),
            "nowAt": now_at,
        }),
        signals,
    )
}

#[allow(clippy::too_many_arguments)]
fn build_film_publish_review_latency_analytics(
    timeline: &[Value],
    rounds: &[Value],
    review_state: &Map<String, Value>,
    current_round: &Value,
    decision_matrix_reviewers: &[Value],
    reviewer_coverage_reviewers: &[Value],
    active_anchors: &[Value],
    backlog_items: &[Value],
) -> (
    Value,
    Vec<Value>,
    Vec<Value>,
    Vec<Value>,
    Vec<Value>,
    Vec<Value>,
) {
    let now_at = current_time_millis();
    let status = normalize_film_publish_review_status(read_map_text(review_state, "status"));
    let current_round_number = current_round
        .as_object()
        .and_then(|round| read_map_i64(round, "roundNumber"))
        .map(|value| value.max(1) as usize);
    let current_round_started_at = current_round
        .as_object()
        .and_then(|round| read_map_i64(round, "startedAt"));
    let current_round_elapsed_ms =
        current_round_started_at.map(|started_at| (now_at - started_at).max(0));
    let backlog_items_by_reviewer = backlog_items
        .iter()
        .filter_map(Value::as_object)
        .filter_map(|item| {
            read_map_text(item, "reviewerKey").map(|reviewer_key| (reviewer_key, item.clone()))
        })
        .collect::<BTreeMap<_, _>>();
    let reviewer_coverage_by_key = reviewer_coverage_reviewers
        .iter()
        .filter_map(Value::as_object)
        .filter_map(|reviewer| {
            read_map_text(reviewer, "reviewerKey")
                .map(|reviewer_key| (reviewer_key, reviewer.clone()))
        })
        .collect::<BTreeMap<_, _>>();
    let mut earliest_current_round_participation_by_reviewer = BTreeMap::<String, i64>::new();
    let mut latest_current_round_decision_at_by_reviewer = BTreeMap::<String, i64>::new();
    let mut latest_current_round_qualifying_decision_at_by_reviewer =
        BTreeMap::<String, i64>::new();

    for event in timeline.iter().filter_map(Value::as_object) {
        let round_number = read_map_i64(event, "roundNumber")
            .map(|value| value.max(1) as usize)
            .unwrap_or(1);
        if Some(round_number) != current_round_number {
            continue;
        }
        let Some(actor_key) = event
            .get("actor")
            .and_then(Value::as_object)
            .and_then(build_film_publish_review_actor_match_key)
        else {
            continue;
        };
        let occurred_at = read_map_i64(event, "occurredAt").unwrap_or_default();
        earliest_current_round_participation_by_reviewer
            .entry(actor_key.clone())
            .and_modify(|current| {
                *current = (*current).min(occurred_at);
            })
            .or_insert(occurred_at);

        if read_map_text(event, "eventType").as_deref() != Some("decision") {
            continue;
        }
        latest_current_round_decision_at_by_reviewer
            .entry(actor_key.clone())
            .and_modify(|current| {
                *current = (*current).max(occurred_at);
            })
            .or_insert(occurred_at);
        let decision_action =
            event
                .get("decision")
                .and_then(Value::as_object)
                .and_then(|decision| {
                    normalize_film_publish_review_decision_action(read_map_text(decision, "action"))
                });
        if matches!(
            decision_action.as_deref(),
            Some("approved") | Some("changes-requested")
        ) {
            latest_current_round_qualifying_decision_at_by_reviewer
                .entry(actor_key)
                .and_modify(|current| {
                    *current = (*current).max(occurred_at);
                })
                .or_insert(occurred_at);
        }
    }

    let mut participant_count_by_round = BTreeMap::<usize, usize>::new();
    let mut qualifying_reviewer_count_by_round = BTreeMap::<usize, usize>::new();
    let mut qualifying_decision_count_by_round = BTreeMap::<usize, usize>::new();
    for reviewer in decision_matrix_reviewers
        .iter()
        .filter_map(Value::as_object)
    {
        for cell in reviewer
            .get("cells")
            .and_then(Value::as_array)
            .into_iter()
            .flatten()
            .filter_map(Value::as_object)
        {
            let round_number = read_map_i64(cell, "roundNumber")
                .map(|value| value.max(1) as usize)
                .unwrap_or(1);
            if cell
                .get("participated")
                .and_then(Value::as_bool)
                .unwrap_or(false)
            {
                *participant_count_by_round.entry(round_number).or_default() += 1;
            }
            if cell
                .get("completed")
                .and_then(Value::as_bool)
                .unwrap_or(false)
            {
                *qualifying_reviewer_count_by_round
                    .entry(round_number)
                    .or_default() += 1;
            }
            *qualifying_decision_count_by_round
                .entry(round_number)
                .or_default() += read_map_i64(cell, "qualifyingDecisionCount")
                .unwrap_or_default()
                .max(0) as usize;
        }
    }

    let mut reviewer_values = decision_matrix_reviewers
        .iter()
        .filter_map(Value::as_object)
        .filter_map(|reviewer| {
            let reviewer_key = read_map_text(reviewer, "reviewerKey")?;
            let coverage_reviewer = reviewer_coverage_by_key.get(&reviewer_key);
            let backlog_item = backlog_items_by_reviewer.get(&reviewer_key);
            let current_round_time_to_first_participation_ms = current_round_started_at
                .zip(earliest_current_round_participation_by_reviewer.get(&reviewer_key).copied())
                .map(|(started_at, first_participation_at)| {
                    (first_participation_at - started_at).max(0)
                });
            let current_round_time_to_latest_decision_ms = current_round_started_at
                .zip(latest_current_round_decision_at_by_reviewer.get(&reviewer_key).copied())
                .map(|(started_at, latest_decision_at)| (latest_decision_at - started_at).max(0));
            let current_round_time_to_latest_qualifying_decision_ms = current_round_started_at
                .zip(
                    latest_current_round_qualifying_decision_at_by_reviewer
                        .get(&reviewer_key)
                        .copied(),
                )
                .map(|(started_at, latest_decision_at)| (latest_decision_at - started_at).max(0));

            Some(json!({
                "reviewerKey": reviewer_key,
                "reviewer": reviewer.get("reviewer").cloned().unwrap_or(Value::Null),
                "assignment": reviewer.get("assignment").cloned().unwrap_or(Value::Null),
                "required": reviewer.get("required").and_then(Value::as_bool).unwrap_or(true),
                "completed": reviewer.get("completed").and_then(Value::as_bool).unwrap_or(false),
                "currentRoundParticipant": reviewer
                    .get("currentRoundParticipant")
                    .and_then(Value::as_bool)
                    .unwrap_or(false),
                "queueRank": backlog_item.and_then(|item| read_map_i64(item, "queueRank")),
                "currentRoundPendingAgeMs": backlog_item
                    .and_then(|item| read_map_i64(item, "pendingAgeMs")),
                "currentRoundTimeToFirstParticipationMs": current_round_time_to_first_participation_ms,
                "currentRoundTimeToLatestDecisionMs": current_round_time_to_latest_decision_ms,
                "currentRoundTimeToLatestQualifyingDecisionMs":
                    current_round_time_to_latest_qualifying_decision_ms,
                "latestDecisionAt": reviewer.get("latestDecisionAt").cloned().unwrap_or(Value::Null),
                "latestDecisionAction": reviewer
                    .get("latestDecisionAction")
                    .cloned()
                    .unwrap_or(Value::Null),
                "latestQualifyingDecisionAt": reviewer
                    .get("latestQualifyingDecisionAt")
                    .cloned()
                    .unwrap_or(Value::Null),
                "latestQualifyingDecisionAction": reviewer
                    .get("latestQualifyingDecisionAction")
                    .cloned()
                    .unwrap_or(Value::Null),
                "latestActivityAt": read_map_i64(reviewer, "latestActivityAt").unwrap_or_default(),
                "openAuthoredCommentCount": read_map_i64(reviewer, "openAuthoredCommentCount")
                    .unwrap_or_default(),
                "openThreadExposureCount": coverage_reviewer
                    .and_then(|reviewer| read_map_i64(reviewer, "openThreadExposureCount"))
                    .unwrap_or_default(),
                "openAnchorExposureCount": coverage_reviewer
                    .and_then(|reviewer| read_map_i64(reviewer, "openAnchorExposureCount"))
                    .unwrap_or_default(),
            }))
        })
        .collect::<Vec<_>>();

    reviewer_values.sort_by(|left, right| {
        film_publish_review_latency_reviewer_required(right)
            .cmp(&film_publish_review_latency_reviewer_required(left))
            .then_with(|| {
                film_publish_review_latency_reviewer_completed(left)
                    .cmp(&film_publish_review_latency_reviewer_completed(right))
            })
            .then_with(|| {
                film_publish_review_latency_reviewer_pending_age_ms(right)
                    .cmp(&film_publish_review_latency_reviewer_pending_age_ms(left))
            })
            .then_with(|| {
                film_publish_review_latency_reviewer_latest_activity_at(right).cmp(
                    &film_publish_review_latency_reviewer_latest_activity_at(left),
                )
            })
            .then_with(|| {
                film_publish_review_latency_reviewer_key(left)
                    .cmp(&film_publish_review_latency_reviewer_key(right))
            })
    });

    let mut round_values = rounds
        .iter()
        .filter_map(Value::as_object)
        .map(|round| {
            let round_number = read_map_i64(round, "roundNumber")
                .map(|value| value.max(1) as usize)
                .unwrap_or(1);
            let started_at = read_map_i64(round, "startedAt").unwrap_or_default();
            let closed_at = read_map_i64(round, "closedAt");
            let elapsed_ms = closed_at
                .map(|closed_at| (closed_at - started_at).max(0))
                .unwrap_or_else(|| (now_at - started_at).max(0));
            let duration_ms = closed_at.map(|closed_at| (closed_at - started_at).max(0));
            let summary = round
                .get("summary")
                .and_then(Value::as_object)
                .cloned()
                .unwrap_or_default();

            json!({
                "roundId": read_map_text(round, "roundId").unwrap_or_default(),
                "roundNumber": round_number,
                "status": normalize_film_publish_review_status(read_map_text(round, "status")),
                "startedAt": started_at,
                "closedAt": closed_at,
                "current": Some(round_number) == current_round_number,
                "elapsedMs": elapsed_ms,
                "durationMs": duration_ms,
                "submissionCount": read_map_i64(&summary, "submissionCount").unwrap_or_default(),
                "assignmentCount": read_map_i64(&summary, "assignmentCount").unwrap_or_default(),
                "commentCount": read_map_i64(&summary, "commentCount").unwrap_or_default(),
                "resolvedCommentCount": read_map_i64(&summary, "resolvedCommentCount").unwrap_or_default(),
                "consensusCount": read_map_i64(&summary, "consensusCount").unwrap_or_default(),
                "decisionCount": read_map_i64(&summary, "decisionCount").unwrap_or_default(),
                "qualifyingDecisionCount": qualifying_decision_count_by_round
                    .get(&round_number)
                    .copied()
                    .unwrap_or_default(),
                "participantCount": participant_count_by_round
                    .get(&round_number)
                    .copied()
                    .unwrap_or_default(),
                "qualifyingReviewerCount": qualifying_reviewer_count_by_round
                    .get(&round_number)
                    .copied()
                    .unwrap_or_default(),
            })
        })
        .collect::<Vec<_>>();
    round_values.sort_by(|left, right| {
        film_publish_review_latency_round_number(left)
            .cmp(&film_publish_review_latency_round_number(right))
    });

    let mut open_threads = Vec::<Value>::new();
    let mut thread_ages = Vec::<i64>::new();
    let mut comment_ages = Vec::<i64>::new();
    for anchor_group in active_anchors.iter().filter_map(Value::as_object) {
        let anchor_id = read_map_text(anchor_group, "anchorId").unwrap_or_default();
        let anchor = anchor_group.get("anchor").cloned().unwrap_or(Value::Null);
        for thread in anchor_group
            .get("threads")
            .and_then(Value::as_array)
            .into_iter()
            .flatten()
            .filter_map(Value::as_object)
        {
            let open_comment_count = read_map_i64(thread, "openCommentCount")
                .unwrap_or_default()
                .max(0) as usize;
            if open_comment_count == 0 {
                continue;
            }
            let unresolved_comments = thread
                .get("comments")
                .and_then(Value::as_array)
                .into_iter()
                .flatten()
                .filter_map(Value::as_object)
                .filter(|comment| {
                    !comment
                        .get("resolved")
                        .and_then(Value::as_bool)
                        .unwrap_or(false)
                })
                .cloned()
                .collect::<Vec<_>>();
            if unresolved_comments.is_empty() {
                continue;
            }
            let first_open_comment_at = unresolved_comments
                .iter()
                .filter_map(|comment| read_map_i64(comment, "createdAt"))
                .min()
                .unwrap_or_default();
            let latest_open_comment_at = unresolved_comments
                .iter()
                .filter_map(|comment| {
                    read_map_i64(comment, "updatedAt")
                        .or_else(|| read_map_i64(comment, "createdAt"))
                })
                .max()
                .unwrap_or_default();
            let open_thread_age_ms = (now_at - first_open_comment_at).max(0);
            let latest_open_comment_age_ms = (now_at - latest_open_comment_at).max(0);
            thread_ages.push(open_thread_age_ms);
            for comment in unresolved_comments {
                if let Some(created_at) = read_map_i64(&comment, "createdAt") {
                    comment_ages.push((now_at - created_at).max(0));
                }
            }

            open_threads.push(json!({
                "anchorId": anchor_id.clone(),
                "anchor": anchor.clone(),
                "threadId": read_map_text(thread, "threadId").unwrap_or_default(),
                "rootCommentId": read_map_text(thread, "rootCommentId").unwrap_or_default(),
                "roundNumbers": thread.get("roundNumbers").cloned().unwrap_or_else(|| json!([])),
                "openCommentCount": open_comment_count,
                "firstOpenCommentAt": first_open_comment_at,
                "latestOpenCommentAt": latest_open_comment_at,
                "oldestOpenCommentAgeMs": open_thread_age_ms,
                "latestOpenCommentAgeMs": latest_open_comment_age_ms,
                "openThreadAgeMs": open_thread_age_ms,
            }));
        }
    }

    open_threads.sort_by(|left, right| {
        film_publish_review_latency_open_thread_age_ms(right)
            .cmp(&film_publish_review_latency_open_thread_age_ms(left))
            .then_with(|| {
                film_publish_review_latency_open_thread_comment_count(right)
                    .cmp(&film_publish_review_latency_open_thread_comment_count(left))
            })
            .then_with(|| {
                film_publish_review_latency_open_thread_id(left)
                    .cmp(&film_publish_review_latency_open_thread_id(right))
            })
    });

    let reviewer_count = reviewer_values.len();
    let required_reviewer_count = reviewer_values
        .iter()
        .filter(|reviewer| film_publish_review_latency_reviewer_required(reviewer))
        .count();
    let completed_reviewer_count = reviewer_values
        .iter()
        .filter(|reviewer| film_publish_review_latency_reviewer_completed(reviewer))
        .count();
    let pending_required_reviewer_count = reviewer_values
        .iter()
        .filter(|reviewer| {
            film_publish_review_latency_reviewer_required(reviewer)
                && !film_publish_review_latency_reviewer_completed(reviewer)
        })
        .count();
    let participating_reviewer_count = reviewer_values
        .iter()
        .filter(|reviewer| film_publish_review_latency_reviewer_current_round_participant(reviewer))
        .count();
    let open_comment_count = open_threads
        .iter()
        .map(film_publish_review_latency_open_thread_comment_count)
        .sum::<usize>();
    let longest_pending_required_review_age_ms = reviewer_values
        .iter()
        .filter(|reviewer| {
            film_publish_review_latency_reviewer_required(reviewer)
                && !film_publish_review_latency_reviewer_completed(reviewer)
        })
        .map(film_publish_review_latency_reviewer_pending_age_ms)
        .max()
        .unwrap_or_default();
    let longest_open_thread_age_ms = thread_ages.iter().copied().max().unwrap_or_default();
    let longest_open_comment_age_ms = comment_ages.iter().copied().max().unwrap_or_default();
    let average_time_to_first_participation_ms = average_i64(
        &reviewer_values
            .iter()
            .filter_map(film_publish_review_latency_reviewer_time_to_first_participation_ms)
            .collect::<Vec<_>>(),
    );
    let average_time_to_qualifying_decision_ms = average_i64(
        &reviewer_values
            .iter()
            .filter_map(film_publish_review_latency_reviewer_time_to_latest_qualifying_decision_ms)
            .collect::<Vec<_>>(),
    );

    (
        json!({
            "status": status,
            "currentRoundNumber": current_round_number,
            "currentRoundStartedAt": current_round_started_at,
            "currentRoundElapsedMs": current_round_elapsed_ms,
            "nowAt": now_at,
            "roundCount": round_values.len(),
            "reviewerCount": reviewer_count,
            "requiredReviewerCount": required_reviewer_count,
            "pendingRequiredReviewerCount": pending_required_reviewer_count,
            "participatingReviewerCount": participating_reviewer_count,
            "completedReviewerCount": completed_reviewer_count,
            "openThreadCount": open_threads.len(),
            "openCommentCount": open_comment_count,
            "longestPendingRequiredReviewAgeMs": longest_pending_required_review_age_ms,
            "longestOpenThreadAgeMs": longest_open_thread_age_ms,
            "longestOpenCommentAgeMs": longest_open_comment_age_ms,
            "averageTimeToFirstParticipationMs": average_time_to_first_participation_ms,
            "averageTimeToQualifyingDecisionMs": average_time_to_qualifying_decision_ms,
        }),
        reviewer_values,
        round_values,
        open_threads,
        build_film_publish_review_latency_age_buckets(&thread_ages),
        build_film_publish_review_latency_age_buckets(&comment_ages),
    )
}

fn build_film_publish_review_comment_round_numbers_map(
    timeline: &[Value],
) -> BTreeMap<String, BTreeSet<usize>> {
    let mut comment_round_numbers = BTreeMap::<String, BTreeSet<usize>>::new();
    for event in timeline.iter().filter_map(Value::as_object) {
        let Some(comment_id) = event
            .get("comment")
            .and_then(Value::as_object)
            .and_then(|comment| read_map_text(comment, "commentId"))
        else {
            continue;
        };
        let round_number = read_map_i64(event, "roundNumber")
            .map(|value| value.max(1) as usize)
            .unwrap_or(1);
        comment_round_numbers
            .entry(comment_id)
            .or_default()
            .insert(round_number);
    }
    comment_round_numbers
}

fn build_film_publish_review_comment_created_round_numbers_map(
    timeline: &[Value],
) -> BTreeMap<String, BTreeSet<usize>> {
    let mut comment_round_numbers = BTreeMap::<String, BTreeSet<usize>>::new();
    for event in timeline.iter().filter_map(Value::as_object) {
        if read_map_text(event, "eventType").as_deref() != Some("comment") {
            continue;
        }
        let Some(comment_id) = event
            .get("comment")
            .and_then(Value::as_object)
            .and_then(|comment| read_map_text(comment, "commentId"))
        else {
            continue;
        };
        let round_number = read_map_i64(event, "roundNumber")
            .map(|value| value.max(1) as usize)
            .unwrap_or(1);
        comment_round_numbers
            .entry(comment_id)
            .or_default()
            .insert(round_number);
    }
    comment_round_numbers
}

fn resolve_film_publish_review_root_comment_id(
    comment_id: &str,
    comments_by_id: &BTreeMap<String, Map<String, Value>>,
) -> String {
    let mut current = comment_id.to_string();
    let mut visited = BTreeSet::new();
    while visited.insert(current.clone()) {
        let Some(comment) = comments_by_id.get(&current) else {
            break;
        };
        let Some(parent_comment_id) =
            normalize_optional_text(read_map_text(comment, "parentCommentId"))
        else {
            break;
        };
        if !comments_by_id.contains_key(&parent_comment_id) {
            break;
        }
        current = parent_comment_id;
    }
    current
}

fn build_film_publish_review_anchor_group_key(anchor: &Value) -> String {
    let Some(anchor_object) = anchor.as_object() else {
        return "unanchored".to_string();
    };

    format!(
        "artifact:{}|path:{}|scene:{}|shot:{}",
        normalize_optional_text(read_map_text(anchor_object, "artifactKind"))
            .unwrap_or_else(|| "_".to_string()),
        normalize_optional_text(read_map_text(anchor_object, "path"))
            .unwrap_or_else(|| "_".to_string()),
        normalize_optional_text(read_map_text(anchor_object, "sceneUuid"))
            .unwrap_or_else(|| "_".to_string()),
        normalize_optional_text(read_map_text(anchor_object, "shotUuid"))
            .unwrap_or_else(|| "_".to_string()),
    )
}

fn build_film_publish_review_reviewer_decisions_by_key(
    review_state: &Map<String, Value>,
    current_round_started_at: i64,
) -> BTreeMap<String, Vec<Map<String, Value>>> {
    let mut decisions_by_key = BTreeMap::<String, Vec<Map<String, Value>>>::new();
    for decision in review_state
        .get("decisions")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_object)
    {
        let created_at = read_map_i64(decision, "createdAt").unwrap_or_default();
        if created_at < current_round_started_at {
            continue;
        }
        let Some(action) =
            normalize_film_publish_review_decision_action(read_map_text(decision, "action"))
        else {
            continue;
        };
        if !matches!(action.as_str(), "approved" | "changes-requested") {
            continue;
        }
        let Some(reviewer_key) = decision
            .get("actor")
            .and_then(Value::as_object)
            .and_then(build_film_publish_review_actor_match_key)
        else {
            continue;
        };
        decisions_by_key
            .entry(reviewer_key)
            .or_default()
            .push(decision.clone());
    }
    for decisions in decisions_by_key.values_mut() {
        decisions.sort_by(|left, right| {
            read_map_i64(left, "createdAt")
                .unwrap_or_default()
                .cmp(&read_map_i64(right, "createdAt").unwrap_or_default())
        });
    }
    decisions_by_key
}

fn film_publish_review_current_round_started_at(review_state: &Map<String, Value>) -> i64 {
    let created_at = read_map_i64(review_state, "createdAt").unwrap_or_default();
    let latest_submission_at = review_state
        .get("submissions")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_object)
        .filter_map(|submission| read_map_i64(submission, "createdAt"))
        .max()
        .unwrap_or(created_at);
    let latest_reopened_at = review_state
        .get("decisions")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_object)
        .filter(|decision| {
            normalize_film_publish_review_decision_action(read_map_text(decision, "action"))
                .as_deref()
                == Some("reopened")
        })
        .filter_map(|decision| read_map_i64(decision, "createdAt"))
        .max()
        .unwrap_or(created_at);

    created_at.max(latest_submission_at).max(latest_reopened_at)
}

