fn map_film_publish_review_readiness_blocker_signal_severity(code: &str) -> String {
    match code {
        "required-reviewers-pending" => "critical".to_string(),
        "open-review-comments" => "high".to_string(),
        "review-status-not-pending" => "medium".to_string(),
        _ => "high".to_string(),
    }
}

fn map_film_publish_review_readiness_blocker_signal_title(code: &str) -> String {
    match code {
        "required-reviewers-pending" => "Required reviewers still pending".to_string(),
        "open-review-comments" => "Open review comments block approval".to_string(),
        "review-status-not-pending" => "Review is not in a pending state".to_string(),
        _ => "Readiness blocker detected".to_string(),
    }
}

fn map_film_publish_review_backlog_level_signal_severity(level: Option<String>) -> String {
    match level.as_deref() {
        Some("overdue") => "critical".to_string(),
        Some("at-risk") => "high".to_string(),
        Some("queued") => "low".to_string(),
        _ => "medium".to_string(),
    }
}

