fn build_film_publish_review_latency_age_buckets(ages: &[i64]) -> Vec<Value> {
    let bucket_definitions = [
        (
            "under-6h",
            "Under 6h",
            0i64,
            Some(FILM_PUBLISH_REVIEW_BACKLOG_IDLE_AFTER_MS),
        ),
        (
            "6-12h",
            "6-12h",
            FILM_PUBLISH_REVIEW_BACKLOG_IDLE_AFTER_MS,
            Some(FILM_PUBLISH_REVIEW_BACKLOG_AT_RISK_AFTER_MS),
        ),
        (
            "12-24h",
            "12-24h",
            FILM_PUBLISH_REVIEW_BACKLOG_AT_RISK_AFTER_MS,
            Some(FILM_PUBLISH_REVIEW_BACKLOG_OVERDUE_AFTER_MS),
        ),
        (
            "24h-plus",
            "24h+",
            FILM_PUBLISH_REVIEW_BACKLOG_OVERDUE_AFTER_MS,
            None,
        ),
    ];

    bucket_definitions
        .into_iter()
        .map(|(bucket_key, label, min_age_ms, max_age_ms)| {
            let count = ages
                .iter()
                .filter(|age| {
                    **age >= min_age_ms
                        && max_age_ms
                            .map(|max_age_ms| **age < max_age_ms)
                            .unwrap_or(true)
                })
                .count();

            json!({
                "bucketKey": bucket_key,
                "label": label,
                "minAgeMs": min_age_ms,
                "maxAgeMs": max_age_ms,
                "count": count,
            })
        })
        .collect()
}

fn average_i64(values: &[i64]) -> Option<i64> {
    if values.is_empty() {
        return None;
    }

    let sum = values.iter().copied().sum::<i64>();
    Some(sum / values.len() as i64)
}

