fn delete_film_project_publish(
    storage_paths: &AppStoragePaths,
    project_key: &str,
    publish_id: &str,
) -> ServerResult<()> {
    let snapshot = read_film_publish_snapshot(storage_paths, publish_id)?;
    if !publish_record_matches_project(&snapshot.record, project_key) {
        return Err(ServerError::not_found(
            "FILM_PUBLISH_NOT_FOUND",
            format!("film publish {publish_id} was not found for project {project_key}"),
        ));
    }

    if let Some(archive_path) = resolve_film_publish_archive_path(storage_paths, &snapshot) {
        if archive_path.exists() {
            fs::remove_file(&archive_path).map_err(|error| {
                ServerError::internal(
                    "FILM_PUBLISH_ARCHIVE_DELETE_FAILED",
                    format!(
                        "failed to delete film publish archive {}: {error}",
                        archive_path.display()
                    ),
                )
            })?;
        }
    }

    if snapshot.publish_root.exists() {
        fs::remove_dir_all(&snapshot.publish_root).map_err(|error| {
            ServerError::internal(
                "FILM_PUBLISH_DELETE_FAILED",
                format!(
                    "failed to delete film publish directory {}: {error}",
                    snapshot.publish_root.display()
                ),
            )
        })?;
    }

    prune_empty_film_publish_parent_dirs(
        snapshot.publish_root.parent(),
        storage_paths.generated_film_publishes_dir(),
    )?;

    Ok(())
}

fn find_film_publish_artifact_record(
    record: &Value,
    artifact_kind: &str,
) -> Option<Map<String, Value>> {
    record
        .as_object()
        .and_then(|object| object.get("artifacts"))
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_object)
        .find(|artifact| read_map_text(artifact, "kind").as_deref() == Some(artifact_kind))
        .cloned()
}

fn require_film_publish_artifact_relative_path(
    artifact: &Map<String, Value>,
    artifact_kind: &str,
    publish_id: &str,
) -> ServerResult<String> {
    read_map_text(artifact, "relativePath").ok_or_else(|| {
        ServerError::internal(
            "FILM_PUBLISH_ARTIFACT_PATH_MISSING",
            format!(
                "artifact kind {artifact_kind} is missing relativePath for publish {publish_id}"
            ),
        )
    })
}

fn resolve_film_publish_artifact_absolute_path(
    snapshot: &FilmPublishSnapshot,
    artifact_kind: &str,
    relative_path: &str,
) -> PathBuf {
    if artifact_kind == "storyboard-archive" {
        snapshot.archive_parent_dir.join(relative_path)
    } else {
        snapshot.publish_root.join(relative_path)
    }
}

fn resolve_film_publish_archive_path(
    storage_paths: &AppStoragePaths,
    snapshot: &FilmPublishSnapshot,
) -> Option<PathBuf> {
    let record_object = snapshot.record.as_object()?;
    read_map_text(record_object, "relativeArchivePath")
        .map(|relative_path| storage_paths.root_dir().join(relative_path))
        .or_else(|| {
            read_map_text(record_object, "fileName")
                .map(|file_name| snapshot.archive_parent_dir.join(file_name))
        })
}

fn prune_empty_film_publish_parent_dirs(start: Option<&Path>, stop_at: &Path) -> ServerResult<()> {
    let mut current = start.map(PathBuf::from);
    while let Some(path) = current {
        if !path.starts_with(stop_at) || path == stop_at {
            break;
        }

        let entries = match fs::read_dir(&path) {
            Ok(entries) => entries,
            Err(error) if error.kind() == ErrorKind::NotFound => break,
            Err(error) => {
                return Err(ServerError::internal(
                    "FILM_PUBLISH_DIR_READ_FAILED",
                    format!(
                        "failed to inspect film publish parent directory {}: {error}",
                        path.display()
                    ),
                ))
            }
        };

        if entries.count() > 0 {
            break;
        }

        fs::remove_dir(&path).map_err(|error| {
            ServerError::internal(
                "FILM_PUBLISH_DIR_DELETE_FAILED",
                format!(
                    "failed to delete empty film publish parent directory {}: {error}",
                    path.display()
                ),
            )
        })?;
        current = path.parent().map(PathBuf::from);
    }

    Ok(())
}

fn collect_film_publish_manifest_paths(
    dir: &Path,
    manifest_paths: &mut Vec<PathBuf>,
) -> ServerResult<()> {
    if !dir.exists() {
        return Ok(());
    }

    let entries = fs::read_dir(dir).map_err(|error| {
        ServerError::internal(
            "FILM_PUBLISH_DIR_READ_FAILED",
            format!(
                "failed to read film publish directory {}: {error}",
                dir.display()
            ),
        )
    })?;

    for entry in entries {
        let entry = entry.map_err(|error| {
            ServerError::internal(
                "FILM_PUBLISH_DIR_ENTRY_READ_FAILED",
                format!(
                    "failed to read a film publish directory entry from {}: {error}",
                    dir.display()
                ),
            )
        })?;
        let path = entry.path();
        if path.is_dir() {
            collect_film_publish_manifest_paths(&path, manifest_paths)?;
            continue;
        }
        if path.file_name().and_then(|value| value.to_str()) == Some("manifest.json") {
            manifest_paths.push(path);
        }
    }

    Ok(())
}

fn build_film_publish_record(
    storage_paths: &AppStoragePaths,
    manifest_path: &Path,
    manifest: Value,
) -> ServerResult<Value> {
    let manifest_object = require_object(manifest, "FILM_PUBLISH_MANIFEST_INVALID")?;
    let publish_id = read_map_text(&manifest_object, "publishId").ok_or_else(|| {
        ServerError::internal(
            "FILM_PUBLISH_MANIFEST_ID_MISSING",
            format!(
                "film publish manifest {} is missing publishId",
                manifest_path.display()
            ),
        )
    })?;
    let publish_kind = read_map_text(&manifest_object, "publishKind")
        .unwrap_or_else(|| "storyboard-review".to_string());
    let published_at_ms = read_map_i64(&manifest_object, "publishedAtMs").unwrap_or_default();
    let project_object = manifest_object
        .get("project")
        .and_then(Value::as_object)
        .ok_or_else(|| {
            ServerError::internal(
                "FILM_PUBLISH_MANIFEST_PROJECT_MISSING",
                format!(
                    "film publish manifest {} is missing project data",
                    manifest_path.display()
                ),
            )
        })?;
    let project_counts = project_object.get("counts").and_then(Value::as_object);
    let review_object = manifest_object.get("review").and_then(Value::as_object);
    let contents_object = manifest_object.get("contents").and_then(Value::as_object);
    let archive_object = manifest_object.get("archive").and_then(Value::as_object);

    let publish_root = manifest_path.parent().ok_or_else(|| {
        ServerError::internal(
            "FILM_PUBLISH_MANIFEST_PATH_INVALID",
            format!(
                "film publish manifest {} does not have a parent directory",
                manifest_path.display()
            ),
        )
    })?;
    let archive_parent_dir = publish_root.parent().unwrap_or(publish_root);
    let archive_file_name = archive_object
        .and_then(|archive| read_map_text(archive, "fileName"))
        .unwrap_or_else(|| format!("{publish_id}.zip"));
    let archive_path = archive_parent_dir.join(&archive_file_name);
    let artifacts =
        build_film_publish_history_artifacts(&archive_path, &archive_file_name, publish_root)?;
    let review_state =
        read_film_publish_review_state(publish_root, &publish_id, &publish_kind, published_at_ms)?;
    let review_state_object = require_object(review_state, "FILM_PUBLISH_REVIEW_STATE_INVALID")?;

    let project_id = read_map_text(project_object, "id")
        .or_else(|| read_map_text(project_object, "uuid"))
        .unwrap_or_default();
    let project_uuid = read_map_text(project_object, "uuid").unwrap_or_else(|| project_id.clone());
    let project_name = read_map_text(project_object, "name")
        .unwrap_or_else(|| "Untitled Film Project".to_string());
    let project_status =
        read_map_text(project_object, "status").unwrap_or_else(|| "DRAFT".to_string());

    Ok(json!({
        "publishId": publish_id,
        "publishKind": publish_kind,
        "publishedAtMs": published_at_ms,
        "createdAt": published_at_ms,
        "updatedAt": published_at_ms,
        "name": archive_file_name,
        "description": format!("{} publish for {}", publish_kind, project_name),
        "projectId": project_id,
        "projectUuid": project_uuid,
        "projectName": project_name,
        "projectStatus": project_status,
        "fileName": archive_file_name,
        "mimeType": archive_object
            .and_then(|archive| read_map_text(archive, "mimeType"))
            .unwrap_or_else(|| "application/zip".to_string()),
        "relativePublishRootPath": relative_storage_path(storage_paths.root_dir(), publish_root),
        "relativeArchivePath": relative_storage_path(storage_paths.root_dir(), &archive_path),
        "summary": {
            "sceneCount": review_object
                .and_then(|review| read_map_i64(review, "sceneCount"))
                .unwrap_or_else(|| project_counts.and_then(|counts| read_map_i64(counts, "scenes")).unwrap_or(0)),
            "shotCount": review_object
                .and_then(|review| read_map_i64(review, "shotCount"))
                .unwrap_or_else(|| project_counts.and_then(|counts| read_map_i64(counts, "shots")).unwrap_or(0)),
            "characterCount": project_counts.and_then(|counts| read_map_i64(counts, "characters")).unwrap_or(0),
            "locationCount": project_counts.and_then(|counts| read_map_i64(counts, "locations")).unwrap_or(0),
            "propCount": project_counts.and_then(|counts| read_map_i64(counts, "props")).unwrap_or(0),
            "mediaCount": project_counts.and_then(|counts| read_map_i64(counts, "media")).unwrap_or(0),
        },
        "contents": {
            "projectSnapshotIncluded": contents_object
                .and_then(|contents| contents.get("projectSnapshotIncluded"))
                .and_then(Value::as_bool)
                .unwrap_or(false),
            "reviewStateIncluded": contents_object
                .and_then(|contents| contents.get("reviewStateIncluded"))
                .and_then(Value::as_bool)
                .unwrap_or(false),
            "storyboardHtmlIncluded": contents_object
                .and_then(|contents| contents.get("storyboardHtmlIncluded"))
                .and_then(Value::as_bool)
                .unwrap_or(false),
            "storyboardMarkdownIncluded": contents_object
                .and_then(|contents| contents.get("storyboardMarkdownIncluded"))
                .and_then(Value::as_bool)
                .unwrap_or(false),
            "storyboardJsonIncluded": contents_object
                .and_then(|contents| contents.get("storyboardJsonIncluded"))
                .and_then(Value::as_bool)
                .unwrap_or(false),
            "projectGraphIncluded": contents_object
                .and_then(|contents| contents.get("projectGraphIncluded"))
                .and_then(Value::as_bool)
                .unwrap_or(false),
        },
        "review": build_film_publish_review_summary(&review_state_object),
        "artifacts": artifacts,
        "manifest": Value::Object(manifest_object),
    }))
}

fn build_film_publish_history_artifacts(
    archive_path: &Path,
    archive_file_name: &str,
    publish_root: &Path,
) -> ServerResult<Vec<Value>> {
    let mut artifacts = Vec::new();
    let expected_files = [
        ("manifest.json", "manifest-json", "application/json"),
        (
            "project-snapshot.json",
            "project-snapshot-json",
            "application/json",
        ),
        ("review-state.json", "review-state-json", "application/json"),
        ("storyboard.json", "storyboard-json", "application/json"),
        ("storyboard-review.html", "storyboard-html", "text/html"),
        (
            "storyboard-review.md",
            "storyboard-markdown",
            "text/markdown",
        ),
    ];

    for (file_name, kind, mime_type) in expected_files {
        let path = publish_root.join(file_name);
        if path.exists() {
            artifacts.push(build_film_publish_artifact_record(
                file_name, kind, mime_type, &path,
            )?);
        }
    }

    if archive_path.exists() {
        artifacts.push(build_film_publish_artifact_record(
            archive_file_name,
            "storyboard-archive",
            "application/zip",
            archive_path,
        )?);
    }

    Ok(artifacts)
}

fn publish_record_matches_project(record: &Value, project_key: &str) -> bool {
    let Some(object) = record.as_object() else {
        return false;
    };

    read_map_text(object, "projectId")
        .into_iter()
        .chain(read_map_text(object, "projectUuid"))
        .any(|value| value == project_key)
}

fn build_film_project_counts(project: &Map<String, Value>) -> Value {
    json!({
        "characters": array_len(project.get("characters")),
        "locations": array_len(project.get("locations")),
        "props": array_len(project.get("props")),
        "scenes": array_len(project.get("scenes")),
        "shots": array_len(project.get("shots")),
        "media": array_len(project.get("media")),
    })
}

fn film_publish_review_state_path(publish_root: &Path) -> PathBuf {
    publish_root.join("review-state.json")
}

