fn build_film_entity_name_by_key(values: &[Value]) -> BTreeMap<String, String> {
    let mut items = BTreeMap::new();
    for value in values {
        let Some(object) = value.as_object() else {
            continue;
        };
        let Some(name) = read_map_text(object, "name") else {
            continue;
        };
        if let Some(uuid) = read_map_text(object, "uuid") {
            items.insert(uuid, name.clone());
        }
        if let Some(id) = read_map_text(object, "id") {
            items.insert(id, name.clone());
        }
    }
    items
}

fn build_film_entity_reference_map(values: &[Value]) -> BTreeMap<String, Value> {
    let mut items = BTreeMap::new();
    for value in values {
        let Some(object) = value.as_object() else {
            continue;
        };
        let Some(name) = read_map_text(object, "name") else {
            continue;
        };
        let id = read_map_text(object, "id");
        let uuid = read_map_text(object, "uuid").or_else(|| id.clone());
        let Some(uuid) = uuid else {
            continue;
        };

        let reference = json!({
            "id": id,
            "uuid": uuid,
            "name": name,
        });
        items.insert(uuid.clone(), reference.clone());
        if let Some(id) = id {
            items.insert(id, reference);
        }
    }

    items
}

fn resolve_film_scene_location_name(
    scene: &Map<String, Value>,
    location_name_by_key: &BTreeMap<String, String>,
    fallback_index: usize,
) -> String {
    read_map_text(scene, "locationUuid")
        .or_else(|| read_map_text(scene, "locationId"))
        .and_then(|key| location_name_by_key.get(&key).cloned())
        .unwrap_or_else(|| resolve_scene_title_from_object(scene, fallback_index))
}

fn build_film_scene_match_key(
    scene: &Map<String, Value>,
    location_name_by_key: &BTreeMap<String, String>,
    fallback_index: usize,
) -> String {
    let location_name = normalize_film_match_key(Some(resolve_film_scene_location_name(
        scene,
        location_name_by_key,
        fallback_index,
    )))
    .unwrap_or_else(|| "unassigned-location".to_string());
    let summary = normalize_film_match_key(read_map_text(scene, "summary"))
        .unwrap_or_else(|| format!("scene-{}", fallback_index + 1));
    format!("{location_name}|{summary}")
}

fn merge_film_scene_entity(
    existing: Option<&Map<String, Value>>,
    refreshed: Map<String, Value>,
    now_ms: i64,
) -> Map<String, Value> {
    let mut merged = existing.cloned().unwrap_or_default();
    for (key, value) in refreshed {
        merged.insert(key, value);
    }
    if let Some(existing) = existing {
        copy_selected_map_fields(
            &mut merged,
            existing,
            &["id", "uuid", "createdAt", "propUuids"],
        );
    }
    merged.insert("updatedAt".to_string(), json_number(now_ms));
    merged
}

fn reconcile_film_scene_collection(
    existing: Vec<Value>,
    refreshed: Vec<Value>,
    locations: &[Value],
    now_ms: i64,
) -> Vec<Value> {
    let location_name_by_key = build_film_entity_name_by_key(locations);
    let existing_scenes = existing
        .into_iter()
        .filter_map(|value| value.as_object().cloned())
        .collect::<Vec<_>>();
    let mut used = vec![false; existing_scenes.len()];

    let mut reconciled = Vec::new();
    for (refresh_index, value) in refreshed.into_iter().enumerate() {
        let Some(object) = value.as_object().cloned() else {
            continue;
        };
        let signature = build_film_scene_match_key(&object, &location_name_by_key, refresh_index);

        let exact_match = existing_scenes
            .iter()
            .enumerate()
            .find_map(|(index, scene)| {
                if used[index] {
                    return None;
                }
                let existing_signature =
                    build_film_scene_match_key(scene, &location_name_by_key, index);
                if existing_signature == signature {
                    Some(index)
                } else {
                    None
                }
            });

        let order_match = exact_match.or_else(|| {
            let target_order = resolve_scene_order_from_object(&object, refresh_index);
            existing_scenes
                .iter()
                .enumerate()
                .find_map(|(index, scene)| {
                    if used[index] {
                        return None;
                    }
                    if resolve_scene_order_from_object(scene, index) == target_order {
                        Some(index)
                    } else {
                        None
                    }
                })
        });

        let existing_match = order_match.map(|index| {
            used[index] = true;
            &existing_scenes[index]
        });

        reconciled.push(Value::Object(merge_film_scene_entity(
            existing_match,
            object,
            now_ms,
        )));
    }

    reconciled
}

fn refresh_film_project_analysis(
    service: &FileBackedFilmService,
    project_key: &str,
    input: FilmRefreshAnalysisInput,
) -> ServerResult<Value> {
    let include_validation = input.include_validation.unwrap_or(true);
    let (path, project) = service.read_document_by_key(
        service.storage_paths.film_projects_dir(),
        project_key,
        "film project",
    )?;
    let (refreshed_project, summary) = refresh_film_project_analysis_document(project, input)?;

    FileBackedFilmService::write_document(&path, &refreshed_project, "FILM_PROJECT")?;

    let mut response = Map::new();
    response.insert("project".to_string(), refreshed_project.clone());
    response.insert("summary".to_string(), summary);
    if include_validation {
        response.insert(
            "validation".to_string(),
            build_film_project_validation_report(
                preview_normalize_film_project(refreshed_project, Some(project_key))?,
                "stored-project",
                false,
            )?,
        );
    }

    Ok(Value::Object(response))
}

fn prepare_film_project_analysis(
    service: &FileBackedFilmService,
    project_key: &str,
    input: FilmPrepareAnalysisInput,
) -> ServerResult<Value> {
    let include_validation = input.include_validation.unwrap_or(true);
    let (path, project) = service.read_document_by_key(
        service.storage_paths.film_projects_dir(),
        project_key,
        "film project",
    )?;

    let (standardized_project, standardized_summary) =
        standardize_film_project_script_document(project)?;
    let refreshed_entities =
        refresh_film_project_analysis_entities(standardized_project, input.language.clone())?;
    let shot_strategy = if input.replace_shots.unwrap_or(false) {
        FilmAnalysisShotStrategy::Clear
    } else {
        FilmAnalysisShotStrategy::Sync
    };
    let (prepared_project, analysis_summary) =
        apply_film_project_analysis_shot_strategy(refreshed_entities, shot_strategy)?;

    FileBackedFilmService::write_document(&path, &prepared_project, "FILM_PROJECT")?;

    let mut response = Map::new();
    response.insert("project".to_string(), prepared_project.clone());
    response.insert(
        "summary".to_string(),
        json!({
            "standardizedScript": standardized_summary,
            "analysis": analysis_summary,
        }),
    );
    if include_validation {
        response.insert(
            "validation".to_string(),
            build_film_project_validation_report(
                preview_normalize_film_project(prepared_project, Some(project_key))?,
                "stored-project",
                false,
            )?,
        );
    }

    Ok(Value::Object(response))
}

fn rebuild_film_project_storyboard(
    service: &FileBackedFilmService,
    project_key: &str,
    input: FilmRebuildStoryboardInput,
) -> ServerResult<Value> {
    let include_validation = input.include_validation.unwrap_or(true);
    let (path, project) = service.read_document_by_key(
        service.storage_paths.film_projects_dir(),
        project_key,
        "film project",
    )?;

    let (standardized_project, standardized_summary) =
        standardize_film_project_script_document(project)?;
    let refreshed_entities =
        refresh_film_project_analysis_entities(standardized_project, input.language.clone())?;
    let (analysis_ready_project, analysis_summary) = apply_film_project_analysis_shot_strategy(
        refreshed_entities,
        FilmAnalysisShotStrategy::Clear,
    )?;
    let (rebuilt_project, _) = apply_film_project_analysis_shot_strategy(
        analysis_ready_project,
        FilmAnalysisShotStrategy::Regenerate(FilmStoryboardGenerateInput {
            language: input.language,
            replace_shots: Some(true),
            max_shots_per_scene: input.max_shots_per_scene,
            include_establishing_shot: input.include_establishing_shot,
        }),
    )?;

    FileBackedFilmService::write_document(&path, &rebuilt_project, "FILM_PROJECT")?;

    let rebuilt_object = require_object(rebuilt_project.clone(), "FILM_PROJECT_INVALID")?;
    let mut response = Map::new();
    response.insert("project".to_string(), rebuilt_project.clone());
    response.insert(
        "summary".to_string(),
        json!({
            "standardizedScript": standardized_summary,
            "analysis": analysis_summary,
            "sceneCount": array_len(rebuilt_object.get("scenes")),
            "shotCount": array_len(rebuilt_object.get("shots")),
        }),
    );
    if include_validation {
        response.insert(
            "validation".to_string(),
            build_film_project_validation_report(
                preview_normalize_film_project(rebuilt_project, Some(project_key))?,
                "stored-project",
                false,
            )?,
        );
    }

    Ok(Value::Object(response))
}

fn create_film_project_scene_breakdown(
    service: &FileBackedFilmService,
    project_key: &str,
    input: FilmSceneBreakdownCreateInput,
) -> ServerResult<Value> {
    let include_validation = input.include_validation.unwrap_or(true);
    let refresh_analysis = input.refresh_analysis.unwrap_or(true);
    let (path, project) = service.read_document_by_key(
        service.storage_paths.film_projects_dir(),
        project_key,
        "film project",
    )?;

    let project = if refresh_analysis {
        let (standardized_project, _) = standardize_film_project_script_document(project)?;
        let refreshed_entities =
            refresh_film_project_analysis_entities(standardized_project, input.language.clone())?;
        apply_film_project_analysis_shot_strategy(
            refreshed_entities,
            FilmAnalysisShotStrategy::Sync,
        )?
        .0
    } else {
        project
    };

    let (updated_project, breakdown_summary) = attach_film_scene_breakdown_to_project(project)?;
    FileBackedFilmService::write_document(&path, &updated_project, "FILM_PROJECT")?;

    let mut response = Map::new();
    response.insert("project".to_string(), updated_project.clone());
    response.insert(
        "summary".to_string(),
        json!({
            "analysisRefreshed": refresh_analysis,
            "breakdown": breakdown_summary,
        }),
    );
    if include_validation {
        response.insert(
            "validation".to_string(),
            build_film_project_validation_report(
                preview_normalize_film_project(updated_project, Some(project_key))?,
                "stored-project",
                false,
            )?,
        );
    }

    Ok(Value::Object(response))
}

