fn refresh_film_project_analysis_document(
    document: Value,
    input: FilmRefreshAnalysisInput,
) -> ServerResult<(Value, Value)> {
    let refreshed_entities =
        refresh_film_project_analysis_entities(document, input.language.clone())?;
    let regenerate_storyboard = input.regenerate_storyboard.unwrap_or(false);
    let replace_shots = input.replace_shots.unwrap_or(regenerate_storyboard);
    let shot_strategy = if regenerate_storyboard {
        FilmAnalysisShotStrategy::Regenerate(FilmStoryboardGenerateInput {
            language: input.language,
            replace_shots: Some(true),
            max_shots_per_scene: None,
            include_establishing_shot: None,
        })
    } else if replace_shots {
        FilmAnalysisShotStrategy::Clear
    } else {
        FilmAnalysisShotStrategy::Sync
    };

    apply_film_project_analysis_shot_strategy(refreshed_entities, shot_strategy)
}

fn refresh_film_project_analysis_entities(
    document: Value,
    language: Option<String>,
) -> ServerResult<Value> {
    let mut object = require_object(document, "FILM_PROJECT_INVALID")?;
    let script_content = object
        .get("script")
        .and_then(Value::as_object)
        .and_then(|script| read_map_text(script, "content"))
        .ok_or_else(|| {
            ServerError::bad_request(
                "FILM_REFRESH_ANALYSIS_SCRIPT_EMPTY",
                "refresh-analysis requires project.script.content",
            )
        })?;
    let script_content = require_non_empty_text(
        &script_content,
        "FILM_REFRESH_ANALYSIS_SCRIPT_EMPTY",
        "project.script.content",
    )?;

    let now_ms = current_time_millis();
    let lines = normalize_script_lines(&script_content);
    let character_names = extract_character_names(&lines);
    let scene_drafts = build_scene_drafts(&lines, &character_names);
    let location_names = collect_location_names(&scene_drafts);
    let prop_names = extract_prop_names(&lines, &character_names, &location_names);

    let next_characters = reconcile_film_named_entity_collection(
        object
            .get("characters")
            .and_then(Value::as_array)
            .cloned()
            .unwrap_or_default(),
        build_film_characters(&character_names, now_ms),
        now_ms,
        merge_film_character_entity,
    );
    let next_locations = reconcile_film_named_entity_collection(
        object
            .get("locations")
            .and_then(Value::as_array)
            .cloned()
            .unwrap_or_default(),
        build_film_locations(&location_names, &scene_drafts, now_ms),
        now_ms,
        merge_film_location_entity,
    );
    let next_props = reconcile_film_named_entity_collection(
        object
            .get("props")
            .and_then(Value::as_array)
            .cloned()
            .unwrap_or_default(),
        build_film_props(prop_names, now_ms),
        now_ms,
        merge_film_prop_entity,
    );

    let location_uuid_by_name = next_locations
        .iter()
        .filter_map(|location| {
            let object = location.as_object()?;
            let name = read_map_text(object, "name")?;
            let uuid = read_map_text(object, "uuid").or_else(|| read_map_text(object, "id"))?;
            Some((name, uuid))
        })
        .collect::<BTreeMap<_, _>>();
    let character_uuid_by_name = next_characters
        .iter()
        .filter_map(|character| {
            let object = character.as_object()?;
            let name = read_map_text(object, "name")?;
            let uuid = read_map_text(object, "uuid").or_else(|| read_map_text(object, "id"))?;
            Some((name, uuid))
        })
        .collect::<BTreeMap<_, _>>();
    let next_scenes = reconcile_film_scene_collection(
        object
            .get("scenes")
            .and_then(Value::as_array)
            .cloned()
            .unwrap_or_default(),
        build_film_scenes(
            &scene_drafts,
            &location_uuid_by_name,
            &character_uuid_by_name,
            now_ms,
        ),
        &next_locations,
        now_ms,
    );

    object.insert("characters".to_string(), Value::Array(next_characters));
    object.insert("locations".to_string(), Value::Array(next_locations));
    object.insert("props".to_string(), Value::Array(next_props));
    object.insert("scenes".to_string(), Value::Array(next_scenes));
    object.insert("updatedAt".to_string(), json_number(now_ms));

    set_film_project_status(&mut object);

    hydrate_film_project_from_script_analysis(&mut object, language)?;
    Ok(Value::Object(object))
}

fn apply_film_project_analysis_shot_strategy(
    document: Value,
    shot_strategy: FilmAnalysisShotStrategy,
) -> ServerResult<(Value, Value)> {
    let refreshed_project = match shot_strategy.clone() {
        FilmAnalysisShotStrategy::Clear => {
            let mut object = require_object(document, "FILM_PROJECT_INVALID")?;
            object.insert("shots".to_string(), Value::Array(Vec::<Value>::new()));
            object.insert("updatedAt".to_string(), json_number(current_time_millis()));
            set_film_project_status(&mut object);
            attach_film_project_graph(Value::Object(object))?
        }
        FilmAnalysisShotStrategy::Sync => sync_film_project_shots(
            document,
            FilmShotSyncInput {
                regenerate_shot_numbers: Some(true),
                fill_scene_bindings: Some(true),
            },
        )?,
        FilmAnalysisShotStrategy::Regenerate(mut storyboard_input) => {
            storyboard_input.replace_shots = Some(true);
            generate_storyboard_project(document, storyboard_input)?
        }
    };
    let refreshed_object = require_object(refreshed_project, "FILM_PROJECT_INVALID")?;
    let storyboard_regenerated = matches!(shot_strategy, FilmAnalysisShotStrategy::Regenerate(_));
    let shots_cleared = matches!(shot_strategy, FilmAnalysisShotStrategy::Clear);
    let shots_synchronized = matches!(shot_strategy, FilmAnalysisShotStrategy::Sync);
    let summary = json!({
        "counts": build_film_project_count_snapshot(&refreshed_object),
        "storyboardRegenerated": storyboard_regenerated,
        "shotsCleared": shots_cleared,
        "shotsSynchronized": shots_synchronized,
    });

    Ok((Value::Object(refreshed_object), summary))
}

fn attach_film_scene_breakdown_to_project(document: Value) -> ServerResult<(Value, Value)> {
    let mut object = require_object(document, "FILM_PROJECT_INVALID")?;
    let now_ms = current_time_millis();
    let breakdown_state = build_film_scene_breakdown_state(&object, now_ms);
    let summary = breakdown_state
        .as_object()
        .and_then(|state| state.get("summary"))
        .cloned()
        .unwrap_or_else(|| json!({}));
    object.insert("preProduction".to_string(), breakdown_state);
    object.insert("updatedAt".to_string(), json_number(now_ms));
    let project = attach_film_project_graph(Value::Object(object))?;
    Ok((project, summary))
}

fn build_film_scene_breakdown_state(project: &Map<String, Value>, now_ms: i64) -> Value {
    let scenes = project
        .get("scenes")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let shots = project
        .get("shots")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let locations = project
        .get("locations")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let characters = project
        .get("characters")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let props = project
        .get("props")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();

    let location_refs = build_film_entity_reference_map(&locations);
    let character_refs = build_film_entity_reference_map(&characters);
    let prop_refs = build_film_entity_reference_map(&props);

    let mut ordered_scenes = scenes
        .iter()
        .enumerate()
        .filter_map(|(fallback_index, value)| {
            value.as_object().cloned().map(|scene| {
                (
                    resolve_scene_order_from_object(&scene, fallback_index),
                    scene,
                )
            })
        })
        .collect::<Vec<_>>();
    ordered_scenes.sort_by(|left, right| left.0.cmp(&right.0));

    let mut scene_lookup = BTreeMap::<String, String>::new();
    for (fallback_index, (_, scene)) in ordered_scenes.iter().enumerate() {
        let scene_uuid = read_map_text(scene, "uuid")
            .or_else(|| read_map_text(scene, "id"))
            .unwrap_or_else(|| format!("scene-{}", fallback_index + 1));
        scene_lookup.insert(scene_uuid.clone(), scene_uuid.clone());
        if let Some(scene_id) = read_map_text(scene, "id") {
            scene_lookup.insert(scene_id, scene_uuid);
        }
    }

    let mut shots_by_scene = BTreeMap::<String, Vec<(i64, String)>>::new();
    let mut ordered_shots = shots
        .iter()
        .enumerate()
        .filter_map(|(fallback_index, value)| {
            value
                .as_object()
                .cloned()
                .map(|shot| (resolve_shot_order_from_object(&shot, fallback_index), shot))
        })
        .collect::<Vec<_>>();
    ordered_shots.sort_by(|left, right| left.0.cmp(&right.0));
    for (fallback_index, (_, shot)) in ordered_shots.into_iter().enumerate() {
        let Some(scene_key) = read_map_text(&shot, "sceneUuid")
            .or_else(|| read_map_text(&shot, "sceneId"))
            .and_then(|scene_key| scene_lookup.get(&scene_key).cloned())
        else {
            continue;
        };
        let shot_uuid = read_map_text(&shot, "uuid")
            .or_else(|| read_map_text(&shot, "id"))
            .unwrap_or_else(|| format!("shot-{}", fallback_index + 1));
        let shot_number = read_map_i64(&shot, "shotNumber")
            .or_else(|| read_map_i64(&shot, "index"))
            .unwrap_or_else(|| fallback_index as i64 + 1);
        shots_by_scene
            .entry(scene_key)
            .or_default()
            .push((shot_number, shot_uuid));
    }

    let mut scene_breakdown = Vec::new();
    let mut ready_count = 0usize;
    let mut needs_review_count = 0usize;
    let mut total_shot_count = 0usize;
    let mut scenes_without_location_count = 0usize;
    let mut scenes_without_characters_count = 0usize;
    let mut scenes_without_props_count = 0usize;
    let mut scenes_without_shots_count = 0usize;

    for (fallback_index, (_, scene)) in ordered_scenes.into_iter().enumerate() {
        let scene_uuid = read_map_text(&scene, "uuid")
            .or_else(|| read_map_text(&scene, "id"))
            .unwrap_or_else(|| format!("scene-{}", fallback_index + 1));
        let scene_id = read_map_text(&scene, "id");
        let scene_number = read_map_i64(&scene, "sceneNumber")
            .or_else(|| read_map_i64(&scene, "index"))
            .unwrap_or_else(|| fallback_index as i64 + 1);
        let title = resolve_scene_title_from_object(&scene, fallback_index);
        let summary = read_map_text(&scene, "summary").unwrap_or_default();
        let time_of_day = read_map_text(&scene, "timeOfDay")
            .or_else(|| read_map_string_array(&scene, "moodTags").into_iter().next());
        let mood_tags = read_map_string_array(&scene, "moodTags");
        let visual_prompt = read_map_text(&scene, "visualPrompt");

        let location = read_map_text(&scene, "locationUuid")
            .or_else(|| read_map_text(&scene, "locationId"))
            .and_then(|key| location_refs.get(&key).cloned());
        let character_keys = {
            let keys = read_map_string_array(&scene, "characterUuids");
            if keys.is_empty() {
                read_map_string_array(&scene, "characterIds")
            } else {
                keys
            }
        };
        let characters = character_keys
            .iter()
            .filter_map(|key| character_refs.get(key).cloned())
            .collect::<Vec<_>>();
        let prop_keys = read_map_string_array(&scene, "propUuids");
        let props = prop_keys
            .iter()
            .filter_map(|key| prop_refs.get(key).cloned())
            .collect::<Vec<_>>();
        let scene_shots = shots_by_scene.get(&scene_uuid).cloned().unwrap_or_default();
        let shot_numbers = scene_shots
            .iter()
            .map(|(number, _)| *number)
            .collect::<Vec<_>>();
        let shot_uuids = scene_shots
            .iter()
            .map(|(_, shot_uuid)| shot_uuid.clone())
            .collect::<Vec<_>>();
        let shot_count = shot_numbers.len();
        total_shot_count += shot_count;

        let mut production_flags = Vec::<String>::new();
        if location.is_none() {
            scenes_without_location_count += 1;
            production_flags.push("missing-location".to_string());
        }
        if characters.is_empty() {
            scenes_without_characters_count += 1;
            production_flags.push("missing-characters".to_string());
        }
        if props.is_empty() {
            scenes_without_props_count += 1;
            production_flags.push("missing-props".to_string());
        }
        if shot_count == 0 {
            scenes_without_shots_count += 1;
            production_flags.push("missing-storyboard".to_string());
        }

        let mut continuity_notes = Vec::<String>::new();
        if let Some(time_of_day) = time_of_day.clone() {
            continuity_notes.push(format!("Time of day: {time_of_day}"));
        }
        if let Some(location_name) = location
            .as_ref()
            .and_then(Value::as_object)
            .and_then(|value| read_map_text(value, "name"))
        {
            continuity_notes.push(format!("Location: {location_name}"));
        }
        let character_names = characters
            .iter()
            .filter_map(Value::as_object)
            .filter_map(|value| read_map_text(value, "name"))
            .collect::<Vec<_>>();
        if !character_names.is_empty() {
            continuity_notes.push(format!(
                "Primary cast: {}",
                join_names_with_and(&character_names),
            ));
        }
        let prop_names = props
            .iter()
            .filter_map(Value::as_object)
            .filter_map(|value| read_map_text(value, "name"))
            .collect::<Vec<_>>();
        if !prop_names.is_empty() {
            continuity_notes.push(format!("Key props: {}", join_names_with_and(&prop_names)));
        }
        if shot_count == 0 {
            continuity_notes.push("Storyboard coverage needs to be generated.".to_string());
        } else {
            continuity_notes.push(format!("Storyboard coverage: {shot_count} shot(s)."));
        }

        let blocking_issue = location.is_none() || shot_count == 0;
        if blocking_issue {
            needs_review_count += 1;
        } else {
            ready_count += 1;
        }

        scene_breakdown.push(json!({
            "sceneId": scene_id,
            "sceneUuid": scene_uuid,
            "sceneNumber": scene_number,
            "title": title,
            "summary": summary,
            "timeOfDay": time_of_day,
            "location": location,
            "characters": characters,
            "props": props,
            "shotCount": shot_count,
            "shotNumbers": shot_numbers,
            "shotUuids": shot_uuids,
            "moodTags": mood_tags,
            "visualPrompt": visual_prompt,
            "continuityNotes": continuity_notes,
            "productionFlags": production_flags,
            "status": if blocking_issue { "NEEDS_REVIEW" } else { "READY" },
        }));
    }

    json!({
        "updatedAt": now_ms,
        "summary": {
            "sceneCount": scene_breakdown.len(),
            "readyCount": ready_count,
            "needsReviewCount": needs_review_count,
            "totalShotCount": total_shot_count,
            "scenesWithoutLocationCount": scenes_without_location_count,
            "scenesWithoutCharactersCount": scenes_without_characters_count,
            "scenesWithoutPropsCount": scenes_without_props_count,
            "scenesWithoutShotsCount": scenes_without_shots_count,
        },
        "sceneBreakdown": scene_breakdown,
    })
}

fn attach_film_shot_variants_to_project(
    document: Value,
    input: FilmShotVariantsGenerateInput,
) -> ServerResult<(Value, Value)> {
    let mut object = require_object(document, "FILM_PROJECT_INVALID")?;
    let now_ms = current_time_millis();
    let mut pre_production = object
        .get("preProduction")
        .and_then(Value::as_object)
        .cloned()
        .unwrap_or_default();
    let scene_breakdown = pre_production
        .get("sceneBreakdown")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    if scene_breakdown.is_empty() {
        return Err(ServerError::bad_request(
            "FILM_SCENE_BREAKDOWN_REQUIRED",
            "generate-shot-variants requires project.preProduction.sceneBreakdown",
        ));
    }

    let requested_scene_uuids = input
        .scene_uuids
        .into_iter()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .collect::<BTreeSet<_>>();
    let selected_scenes = scene_breakdown
        .iter()
        .filter_map(Value::as_object)
        .filter(|scene| {
            if requested_scene_uuids.is_empty() {
                return true;
            }
            read_map_text(scene, "sceneUuid")
                .is_some_and(|scene_uuid| requested_scene_uuids.contains(&scene_uuid))
        })
        .cloned()
        .collect::<Vec<_>>();

    if selected_scenes.is_empty() {
        return Err(ServerError::bad_request(
            "FILM_SHOT_VARIANT_SCENES_EMPTY",
            "generate-shot-variants did not match any canonical scene breakdown entries",
        ));
    }
    let selected_scene_uuids = selected_scenes
        .iter()
        .filter_map(|scene| read_map_text(scene, "sceneUuid"))
        .collect::<BTreeSet<_>>();

    let strategies =
        resolve_film_shot_variant_strategies(&input.strategies, input.variant_count_per_scene);
    let existing_variants = pre_production
        .get("shotVariants")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let replace_existing = input.replace_existing.unwrap_or(true);
    let mut next_variants = if replace_existing {
        existing_variants
            .into_iter()
            .filter(|value| {
                let Some(object) = value.as_object() else {
                    return true;
                };
                !read_map_text(object, "sceneUuid")
                    .is_some_and(|scene_uuid| selected_scene_uuids.contains(&scene_uuid))
            })
            .collect::<Vec<_>>()
    } else {
        existing_variants
    };

    let existing_keys = next_variants
        .iter()
        .filter_map(Value::as_object)
        .filter_map(|variant| {
            Some((
                read_map_text(variant, "sceneUuid")?,
                read_map_text(variant, "strategy")?,
            ))
        })
        .collect::<BTreeSet<_>>();
    let generated_variants = build_film_shot_variant_plans(
        &selected_scenes,
        &strategies,
        &existing_keys,
        replace_existing,
        now_ms,
    );
    let generated_summary = build_film_shot_variant_summary(&generated_variants);

    next_variants.extend(generated_variants);
    pre_production.insert(
        "shotVariants".to_string(),
        Value::Array(next_variants.clone()),
    );
    pre_production.insert(
        "shotVariantsSummary".to_string(),
        build_film_shot_variant_summary(&next_variants),
    );
    pre_production.insert("updatedAt".to_string(), json_number(now_ms));

    object.insert("preProduction".to_string(), Value::Object(pre_production));
    object.insert("updatedAt".to_string(), json_number(now_ms));

    let project = attach_film_project_graph(Value::Object(object))?;
    Ok((project, generated_summary))
}

fn resolve_film_shot_variant_strategies(
    strategies: &[String],
    variant_count_per_scene: Option<usize>,
) -> Vec<String> {
    let mut resolved = Vec::new();
    let mut seen = BTreeSet::new();
    let normalized = if strategies.is_empty() {
        vec![
            "cinematic".to_string(),
            "coverage".to_string(),
            "performance".to_string(),
        ]
    } else {
        strategies
            .iter()
            .map(|value| value.trim().to_ascii_lowercase())
            .collect::<Vec<_>>()
    };
    for strategy in normalized {
        if !matches!(strategy.as_str(), "cinematic" | "coverage" | "performance") {
            continue;
        }
        if seen.insert(strategy.clone()) {
            resolved.push(strategy);
        }
    }

    let target_count = variant_count_per_scene
        .unwrap_or(resolved.len())
        .clamp(1, 3);
    resolved.into_iter().take(target_count).collect()
}

fn build_film_shot_variant_plans(
    scenes: &[Map<String, Value>],
    strategies: &[String],
    existing_keys: &BTreeSet<(String, String)>,
    replace_existing: bool,
    now_ms: i64,
) -> Vec<Value> {
    let mut plans = Vec::new();
    for scene in scenes {
        let scene_uuid = read_map_text(scene, "sceneUuid").unwrap_or_default();
        if scene_uuid.is_empty() {
            continue;
        }
        for strategy in strategies {
            if !replace_existing && existing_keys.contains(&(scene_uuid.clone(), strategy.clone()))
            {
                continue;
            }
            plans.push(build_film_shot_variant_plan(scene, strategy, now_ms));
        }
    }

    plans
}

fn build_film_shot_variant_plan(scene: &Map<String, Value>, strategy: &str, now_ms: i64) -> Value {
    let scene_uuid = read_map_text(scene, "sceneUuid").unwrap_or_else(|| "scene".to_string());
    let scene_id = read_map_text(scene, "sceneId");
    let scene_number = read_map_i64(scene, "sceneNumber").unwrap_or(1);
    let title = read_map_text(scene, "title").unwrap_or_else(|| format!("Scene {scene_number}"));
    let summary = read_map_text(scene, "summary").unwrap_or_default();
    let time_of_day = read_map_text(scene, "timeOfDay").unwrap_or_else(|| "DAY".to_string());
    let visual_prompt = read_map_text(scene, "visualPrompt").unwrap_or_else(|| summary.clone());
    let mood_tags = read_map_string_array(scene, "moodTags");
    let location_name = scene
        .get("location")
        .and_then(Value::as_object)
        .and_then(|value| read_map_text(value, "name"))
        .unwrap_or_else(|| "unassigned location".to_string());
    let character_names = scene
        .get("characters")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_object)
        .filter_map(|value| read_map_text(value, "name"))
        .collect::<Vec<_>>();
    let prop_names = scene
        .get("props")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_object)
        .filter_map(|value| read_map_text(value, "name"))
        .collect::<Vec<_>>();
    let source_shot_uuids = read_map_string_array(scene, "shotUuids");
    let target_shot_count = read_map_i64(scene, "shotCount")
        .map(|value| value.max(2).min(4) as usize)
        .unwrap_or(3);
    let variant_id = format!("{scene_uuid}:variant:{strategy}");
    let (label, rationale, shot_specs) = build_film_shot_variant_specs(
        strategy,
        &title,
        &summary,
        &location_name,
        &time_of_day,
        &character_names,
        &prop_names,
        &mood_tags,
        &visual_prompt,
        target_shot_count,
    );

    let shots = shot_specs
        .into_iter()
        .enumerate()
        .map(
            |(index, (title, description, prompt, duration, framing, focus_subjects))| {
                json!({
                    "id": format!("{variant_id}:shot:{}", index + 1),
                    "order": index + 1,
                    "title": title,
                    "description": description,
                    "prompt": prompt,
                    "duration": duration,
                    "framing": framing,
                    "focusSubjects": focus_subjects,
                    "basedOnShotUuid": source_shot_uuids.get(index).cloned(),
                })
            },
        )
        .collect::<Vec<_>>();

    json!({
        "id": variant_id,
        "sceneId": scene_id,
        "sceneUuid": scene_uuid,
        "sceneNumber": scene_number,
        "title": title,
        "strategy": strategy,
        "label": label,
        "rationale": rationale,
        "sourceShotUuids": source_shot_uuids,
        "shots": shots,
        "createdAt": now_ms,
        "updatedAt": now_ms,
    })
}

fn build_film_shot_variant_specs(
    strategy: &str,
    scene_title: &str,
    summary: &str,
    location_name: &str,
    time_of_day: &str,
    character_names: &[String],
    prop_names: &[String],
    mood_tags: &[String],
    visual_prompt: &str,
    target_shot_count: usize,
) -> (
    String,
    String,
    Vec<(String, String, String, i64, String, Vec<String>)>,
) {
    let primary_subject = if character_names.is_empty() {
        location_name.to_string()
    } else {
        join_names_with_and(character_names)
    };
    let primary_prop = prop_names
        .first()
        .cloned()
        .unwrap_or_else(|| "key detail".to_string());
    let atmosphere = if mood_tags.is_empty() {
        time_of_day.to_string()
    } else {
        mood_tags.join(", ")
    };

    let mut shots = match strategy {
        "coverage" => vec![
            (
                "Master Coverage".to_string(),
                format!("Full-scene master shot covering {scene_title}."),
                format!(
                    "Master coverage of {scene_title} at {location_name}, {summary}. Atmosphere: {atmosphere}."
                ),
                4,
                "wide".to_string(),
                vec![location_name.to_string()],
            ),
            (
                "Interaction Coverage".to_string(),
                format!("Medium coverage on {primary_subject}."),
                format!(
                    "Medium coverage focused on {primary_subject}, preserving blocking and continuity. Base prompt: {visual_prompt}."
                ),
                3,
                "medium".to_string(),
                character_names.to_vec(),
            ),
            (
                "Insert Coverage".to_string(),
                format!("Insert coverage for {primary_prop}."),
                format!(
                    "Insert shot for {primary_prop} within {scene_title}, supporting {summary}."
                ),
                2,
                "insert".to_string(),
                vec![primary_prop.clone()],
            ),
        ],
        "performance" => vec![
            (
                "Performance Close-Up".to_string(),
                format!("Emotional close-up on {primary_subject}."),
                format!(
                    "Close-up performance shot of {primary_subject} reacting during {scene_title}. Emotional context: {summary}."
                ),
                3,
                "close-up".to_string(),
                character_names.to_vec(),
            ),
            (
                "Reaction Coverage".to_string(),
                format!("Reaction beat coverage for {primary_subject}."),
                format!(
                    "Reaction coverage focused on subtle expression changes from {primary_subject}. Setting: {location_name}, {atmosphere}."
                ),
                3,
                "medium-close".to_string(),
                character_names.to_vec(),
            ),
            (
                "Gesture Detail".to_string(),
                format!("Detailed gesture or prop interaction featuring {primary_prop}."),
                format!(
                    "Tactile detail shot of hands, gesture, or {primary_prop} interaction to reinforce performance beats in {scene_title}."
                ),
                2,
                "detail".to_string(),
                vec![primary_subject, primary_prop.clone()],
            ),
        ],
        _ => vec![
            (
                "Cinematic Establishing".to_string(),
                format!("Cinematic establishing shot for {scene_title}."),
                format!(
                    "Wide cinematic establishing shot of {location_name} during {time_of_day}, {summary}."
                ),
                4,
                "wide".to_string(),
                vec![location_name.to_string()],
            ),
            (
                "Hero Beat".to_string(),
                format!("Hero image centered on {primary_subject}."),
                format!(
                    "Stylized hero shot focused on {primary_subject}. Visual direction: {visual_prompt}. Atmosphere: {atmosphere}."
                ),
                3,
                "medium".to_string(),
                character_names.to_vec(),
            ),
            (
                "Emotional Detail".to_string(),
                format!("Emotional detail and texture inside {scene_title}."),
                format!(
                    "Close cinematic detail of {primary_subject} with environmental texture from {location_name}. Reinforce {summary}."
                ),
                3,
                "close-up".to_string(),
                vec![primary_subject],
            ),
        ],
    };

    if target_shot_count > shots.len() {
        shots.push((
            "Rhythm Accent".to_string(),
            format!("Rhythm accent shot for {scene_title}."),
            format!(
                "Additional rhythm accent shot to bridge action and continuity in {scene_title}, using {primary_prop} and {visual_prompt}."
            ),
            2,
            "accent".to_string(),
            vec![primary_prop],
        ));
    }

    shots.truncate(target_shot_count);
    let (label, rationale) = match strategy {
        "coverage" => (
            "Coverage Plan".to_string(),
            "Prioritizes editorial coverage and clear spatial continuity.".to_string(),
        ),
        "performance" => (
            "Performance Focus".to_string(),
            "Prioritizes actor performance, reaction beats, and emotional detail.".to_string(),
        ),
        _ => (
            "Cinematic Emphasis".to_string(),
            "Prioritizes stylized composition and visually distinctive storytelling beats."
                .to_string(),
        ),
    };

    (label, rationale, shots)
}

fn build_film_shot_variant_summary(plans: &[Value]) -> Value {
    let mut scene_uuids = BTreeSet::new();
    let mut strategies = BTreeSet::new();
    let mut total_shot_count = 0usize;
    for plan in plans {
        let Some(object) = plan.as_object() else {
            continue;
        };
        if let Some(scene_uuid) = read_map_text(object, "sceneUuid") {
            scene_uuids.insert(scene_uuid);
        }
        if let Some(strategy) = read_map_text(object, "strategy") {
            strategies.insert(strategy);
        }
        total_shot_count += object
            .get("shots")
            .and_then(Value::as_array)
            .map(|value| value.len())
            .unwrap_or_default();
    }

    json!({
        "sceneCount": scene_uuids.len(),
        "variantPlanCount": plans.len(),
        "totalShotCount": total_shot_count,
        "strategies": strategies.into_iter().collect::<Vec<_>>(),
    })
}

fn attach_film_shooting_plan_to_project(
    document: Value,
    input: FilmCreateShootingPlanInput,
) -> ServerResult<(Value, Value, bool)> {
    let mut object = require_object(document, "FILM_PROJECT_INVALID")?;
    let now_ms = current_time_millis();
    let project_uuid = read_map_text(&object, "uuid")
        .or_else(|| read_map_text(&object, "id"))
        .unwrap_or_else(|| "film-project".to_string());
    let mut pre_production = object
        .get("preProduction")
        .and_then(Value::as_object)
        .cloned()
        .unwrap_or_default();
    let scene_breakdown = pre_production
        .get("sceneBreakdown")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    if scene_breakdown.is_empty() {
        return Err(ServerError::bad_request(
            "FILM_SCENE_BREAKDOWN_REQUIRED",
            "create-shooting-plan requires project.preProduction.sceneBreakdown",
        ));
    }

    let shot_variants = if input.prefer_shot_variants.unwrap_or(true) {
        pre_production
            .get("shotVariants")
            .and_then(Value::as_array)
            .cloned()
            .unwrap_or_default()
    } else {
        Vec::new()
    };
    let max_scenes_per_day = input.max_scenes_per_day.unwrap_or(3).clamp(1, 6);
    let group_by_location = input.group_by_location.unwrap_or(true);
    let split_by_time_of_day = input.split_by_time_of_day.unwrap_or(true);
    let (shooting_plan, shooting_plan_summary, used_shot_variants) = build_film_shooting_plan(
        &project_uuid,
        &scene_breakdown,
        &shot_variants,
        max_scenes_per_day,
        group_by_location,
        split_by_time_of_day,
    );

    pre_production.insert("shootingPlan".to_string(), Value::Array(shooting_plan));
    pre_production.insert(
        "shootingPlanSummary".to_string(),
        shooting_plan_summary.clone(),
    );
    pre_production.insert("updatedAt".to_string(), json_number(now_ms));

    object.insert("preProduction".to_string(), Value::Object(pre_production));
    object.insert("updatedAt".to_string(), json_number(now_ms));

    let project = attach_film_project_graph(Value::Object(object))?;
    Ok((project, shooting_plan_summary, used_shot_variants))
}

fn build_film_shooting_plan(
    project_uuid: &str,
    scene_breakdown: &[Value],
    shot_variants: &[Value],
    max_scenes_per_day: usize,
    group_by_location: bool,
    split_by_time_of_day: bool,
) -> (Vec<Value>, Value, bool) {
    let mut variants_by_scene = BTreeMap::<String, Vec<Map<String, Value>>>::new();
    for variant in shot_variants {
        let Some(object) = variant.as_object() else {
            continue;
        };
        let Some(scene_uuid) = read_map_text(object, "sceneUuid") else {
            continue;
        };
        variants_by_scene
            .entry(scene_uuid)
            .or_default()
            .push(object.clone());
    }

    let mut drafts = Vec::new();
    for scene in scene_breakdown.iter().filter_map(Value::as_object) {
        let Some(scene_uuid) = read_map_text(scene, "sceneUuid") else {
            continue;
        };
        let variant_plans = variants_by_scene
            .get(&scene_uuid)
            .map(Vec::as_slice)
            .unwrap_or(&[]);
        if let Some(draft) = build_film_shooting_plan_scene_draft(scene, variant_plans) {
            drafts.push(draft);
        }
    }
    drafts.sort_by(|left, right| {
        left.scene_number
            .cmp(&right.scene_number)
            .then(left.scene_uuid.cmp(&right.scene_uuid))
    });

    let used_shot_variants = drafts
        .iter()
        .any(|draft| !draft.variant_plan_ids.is_empty());

    let mut grouped = BTreeMap::<String, Vec<FilmShootingPlanSceneDraft>>::new();
    for draft in drafts {
        let mut group_key = if group_by_location {
            draft.location_key.clone()
        } else {
            "story-sequence".to_string()
        };
        if split_by_time_of_day {
            group_key.push_str("::");
            group_key.push_str(&draft.time_bucket);
        }
        grouped.entry(group_key).or_default().push(draft);
    }

    let mut ordered_groups = grouped
        .into_iter()
        .map(|(group_key, mut scenes)| {
            scenes.sort_by(|left, right| {
                left.scene_number
                    .cmp(&right.scene_number)
                    .then(left.scene_uuid.cmp(&right.scene_uuid))
            });
            let first_scene_number = scenes
                .first()
                .map(|scene| scene.scene_number)
                .unwrap_or_default();
            (first_scene_number, group_key, scenes)
        })
        .collect::<Vec<_>>();
    ordered_groups.sort_by(|left, right| left.0.cmp(&right.0).then(left.1.cmp(&right.1)));

    let mut days = Vec::new();
    let mut day_number = 1usize;
    let mut scheduled_scene_count = 0usize;
    let mut scheduled_shot_count = 0usize;
    let mut estimated_minutes = 0usize;
    let mut variant_backed_scene_count = 0usize;
    let mut distinct_locations = BTreeSet::new();
    let mut previous_day_transition_key: Option<String> = None;
    let mut company_move_count = 0usize;

    for (_, _, scenes) in ordered_groups {
        for chunk in scenes.chunks(max_scenes_per_day) {
            let day_transition_key =
                resolve_film_shooting_day_transition_key(chunk, group_by_location);
            if let Some(previous_key) = previous_day_transition_key.as_ref() {
                if previous_key != &day_transition_key {
                    company_move_count += 1;
                }
            }
            previous_day_transition_key = Some(day_transition_key);

            let day_location = resolve_film_shooting_day_location(chunk);
            let day_time_of_day = resolve_film_shooting_day_time_of_day(chunk);
            let location_name = day_location
                .as_ref()
                .and_then(Value::as_object)
                .and_then(|location| read_map_text(location, "name"))
                .unwrap_or_else(|| {
                    if group_by_location {
                        chunk
                            .first()
                            .map(|scene| scene.location_label.clone())
                            .unwrap_or_else(|| "Location TBD".to_string())
                    } else {
                        "Mixed Locations".to_string()
                    }
                });

            let mut day_characters = Vec::new();
            let mut seen_characters = BTreeSet::new();
            let mut day_props = Vec::new();
            let mut seen_props = BTreeSet::new();
            let mut day_strategies = BTreeSet::new();
            let mut scene_values = Vec::new();
            let mut day_scene_count = 0usize;
            let mut day_shot_count = 0usize;
            let mut day_estimated_minutes = 0usize;

            for scene in chunk {
                day_scene_count += 1;
                day_shot_count += scene.shot_count;
                day_estimated_minutes += scene.estimated_minutes;
                scheduled_scene_count += 1;
                scheduled_shot_count += scene.shot_count;
                estimated_minutes += scene.estimated_minutes;
                if !scene.variant_plan_ids.is_empty() {
                    variant_backed_scene_count += 1;
                }
                if scene.location.is_some() {
                    distinct_locations.insert(scene.location_key.clone());
                }
                for character in &scene.characters {
                    push_unique_film_entity_ref(
                        &mut day_characters,
                        &mut seen_characters,
                        character,
                    );
                }
                for prop in &scene.props {
                    push_unique_film_entity_ref(&mut day_props, &mut seen_props, prop);
                }
                for strategy in &scene.available_strategies {
                    day_strategies.insert(strategy.clone());
                }
                scene_values.push(build_film_shooting_plan_scene_value(scene));
            }

            let mut strategies = day_strategies.into_iter().collect::<Vec<_>>();
            strategies.sort_by_key(|strategy| film_shot_variant_strategy_rank(strategy));
            let title = build_film_shooting_day_title(
                day_number,
                &location_name,
                day_time_of_day.as_deref(),
                group_by_location,
            );
            let rationale = build_film_shooting_day_rationale(
                &location_name,
                day_time_of_day.as_deref(),
                &strategies,
                group_by_location,
            );

            days.push(json!({
                "id": format!("{project_uuid}:shooting-day:{day_number}"),
                "dayNumber": day_number,
                "title": title,
                "location": day_location,
                "timeOfDay": day_time_of_day,
                "sceneCount": day_scene_count,
                "shotCount": day_shot_count,
                "estimatedMinutes": day_estimated_minutes,
                "strategies": strategies,
                "characters": day_characters,
                "props": day_props,
                "scenes": scene_values,
                "rationale": rationale,
            }));
            day_number += 1;
        }
    }

    let summary = json!({
        "dayCount": days.len(),
        "scheduledSceneCount": scheduled_scene_count,
        "scheduledShotCount": scheduled_shot_count,
        "estimatedMinutes": estimated_minutes,
        "locationCount": distinct_locations.len(),
        "companyMoveCount": company_move_count,
        "variantBackedSceneCount": variant_backed_scene_count,
    });

    (days, summary, used_shot_variants)
}

fn build_film_shooting_plan_scene_draft(
    scene: &Map<String, Value>,
    variant_plans: &[Map<String, Value>],
) -> Option<FilmShootingPlanSceneDraft> {
    let scene_uuid =
        read_map_text(scene, "sceneUuid").or_else(|| read_map_text(scene, "sceneId"))?;
    let scene_number = read_map_i64(scene, "sceneNumber").unwrap_or(1);
    let title = read_map_text(scene, "title").unwrap_or_else(|| format!("Scene {scene_number}"));
    let location = scene
        .get("location")
        .and_then(Value::as_object)
        .map(|value| Value::Object(value.clone()));
    let location_key = location
        .as_ref()
        .and_then(Value::as_object)
        .and_then(|value| read_map_text(value, "uuid").or_else(|| read_map_text(value, "id")))
        .unwrap_or_else(|| format!("locationless:{scene_uuid}"));
    let location_label = location
        .as_ref()
        .and_then(Value::as_object)
        .and_then(|value| read_map_text(value, "name"))
        .unwrap_or_else(|| "Location TBD".to_string());
    let time_of_day = read_map_text(scene, "timeOfDay");
    let time_bucket = normalize_film_shooting_time_bucket(time_of_day.as_deref());
    let characters = collect_film_entity_refs(scene.get("characters"));
    let props = collect_film_entity_refs(scene.get("props"));
    let shot_count = read_map_i64(scene, "shotCount")
        .map(|value| value.max(0) as usize)
        .unwrap_or_default();
    let production_flags = read_map_string_array(scene, "productionFlags");
    let (variant_plan_ids, available_strategies, preferred_strategy, variant_shot_count) =
        extract_film_shooting_variant_metadata(variant_plans);
    let base_shot_count = shot_count.max(variant_shot_count).max(1);
    let mut complexity_bonus = 0usize;
    if location.is_none() {
        complexity_bonus += 15;
    }
    if characters.len() > 4 {
        complexity_bonus += 15;
    }
    if props.len() > 3 {
        complexity_bonus += 15;
    }
    if production_flags
        .iter()
        .any(|flag| flag == "missing-storyboard")
    {
        complexity_bonus += 15;
    }

    Some(FilmShootingPlanSceneDraft {
        scene_id: read_map_text(scene, "sceneId"),
        scene_uuid,
        scene_number,
        title,
        location,
        location_key,
        location_label,
        time_of_day,
        time_bucket,
        characters,
        props,
        shot_count,
        estimated_minutes: base_shot_count * 45 + complexity_bonus,
        variant_plan_ids,
        available_strategies,
        preferred_strategy,
        production_flags,
    })
}

fn extract_film_shooting_variant_metadata(
    variant_plans: &[Map<String, Value>],
) -> (Vec<String>, Vec<String>, Option<String>, usize) {
    let mut plan_ids = Vec::new();
    let mut strategies = Vec::new();
    let mut seen_strategies = BTreeSet::new();
    let mut variant_shot_count = 0usize;
    for plan in variant_plans {
        if let Some(plan_id) = read_map_text(plan, "id") {
            plan_ids.push(plan_id);
        }
        if let Some(strategy) = read_map_text(plan, "strategy")
            .and_then(|value| normalize_film_shot_variant_strategy_text(&value))
        {
            if seen_strategies.insert(strategy.clone()) {
                strategies.push(strategy);
            }
        }
        variant_shot_count = variant_shot_count.max(
            plan.get("shots")
                .and_then(Value::as_array)
                .map(|value| value.len())
                .unwrap_or_default(),
        );
    }
    strategies.sort_by_key(|strategy| film_shot_variant_strategy_rank(strategy));
    let preferred_strategy = strategies.first().cloned();
    (plan_ids, strategies, preferred_strategy, variant_shot_count)
}

fn normalize_film_shot_variant_strategy_text(value: &str) -> Option<String> {
    let normalized = value.trim().to_ascii_lowercase();
    if matches!(
        normalized.as_str(),
        "cinematic" | "coverage" | "performance"
    ) {
        Some(normalized)
    } else {
        None
    }
}

fn film_shot_variant_strategy_rank(value: &str) -> usize {
    match value {
        "cinematic" => 0,
        "coverage" => 1,
        "performance" => 2,
        _ => 99,
    }
}

fn collect_film_entity_refs(value: Option<&Value>) -> Vec<Value> {
    let mut items = Vec::new();
    let mut seen = BTreeSet::new();
    let Some(values) = value.and_then(Value::as_array) else {
        return items;
    };
    for candidate in values {
        push_unique_film_entity_ref(&mut items, &mut seen, candidate);
    }
    items
}

fn push_unique_film_entity_ref(
    target: &mut Vec<Value>,
    seen: &mut BTreeSet<String>,
    candidate: &Value,
) {
    let Some(object) = candidate.as_object() else {
        return;
    };
    let Some(key) = read_map_text(object, "uuid")
        .or_else(|| read_map_text(object, "id"))
        .or_else(|| read_map_text(object, "name"))
    else {
        return;
    };
    if seen.insert(key) {
        target.push(Value::Object(object.clone()));
    }
}

fn build_film_shooting_plan_scene_value(scene: &FilmShootingPlanSceneDraft) -> Value {
    json!({
        "sceneId": scene.scene_id.clone(),
        "sceneUuid": scene.scene_uuid.clone(),
        "sceneNumber": scene.scene_number,
        "title": scene.title.clone(),
        "location": scene.location.clone(),
        "timeOfDay": scene.time_of_day.clone(),
        "characters": scene.characters.clone(),
        "props": scene.props.clone(),
        "shotCount": scene.shot_count,
        "estimatedMinutes": scene.estimated_minutes,
        "variantPlanIds": scene.variant_plan_ids.clone(),
        "availableStrategies": scene.available_strategies.clone(),
        "preferredStrategy": scene.preferred_strategy.clone(),
        "productionFlags": scene.production_flags.clone(),
    })
}

fn normalize_film_shooting_time_bucket(value: Option<&str>) -> String {
    value
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_ascii_uppercase)
        .unwrap_or_else(|| "UNSPECIFIED".to_string())
}

fn resolve_film_shooting_day_transition_key(
    scenes: &[FilmShootingPlanSceneDraft],
    group_by_location: bool,
) -> String {
    if group_by_location {
        return scenes
            .first()
            .map(|scene| scene.location_key.clone())
            .unwrap_or_else(|| "locationless".to_string());
    }
    let unique_locations = scenes
        .iter()
        .map(|scene| scene.location_key.clone())
        .collect::<BTreeSet<_>>();
    if unique_locations.len() == 1 {
        return unique_locations
            .into_iter()
            .next()
            .unwrap_or_else(|| "locationless".to_string());
    }
    format!(
        "mixed:{}",
        scenes
            .first()
            .map(|scene| scene.scene_number)
            .unwrap_or_default()
    )
}

fn resolve_film_shooting_day_location(scenes: &[FilmShootingPlanSceneDraft]) -> Option<Value> {
    let first_location = scenes.first().and_then(|scene| scene.location.clone())?;
    if scenes
        .iter()
        .all(|scene| scene.location.as_ref() == Some(&first_location))
    {
        Some(first_location)
    } else {
        None
    }
}

fn resolve_film_shooting_day_time_of_day(scenes: &[FilmShootingPlanSceneDraft]) -> Option<String> {
    let unique_buckets = scenes
        .iter()
        .map(|scene| scene.time_bucket.clone())
        .collect::<BTreeSet<_>>();
    if unique_buckets.len() != 1 {
        return None;
    }
    let bucket = unique_buckets.into_iter().next().unwrap_or_default();
    if bucket == "UNSPECIFIED" {
        return None;
    }
    scenes
        .iter()
        .find_map(|scene| scene.time_of_day.clone())
        .or(Some(bucket))
}

fn build_film_shooting_day_title(
    day_number: usize,
    location_name: &str,
    time_of_day: Option<&str>,
    group_by_location: bool,
) -> String {
    let base_name = if group_by_location {
        location_name.to_string()
    } else {
        "Story Sequence".to_string()
    };
    match time_of_day.map(str::trim).filter(|value| !value.is_empty()) {
        Some(value) => format!("Day {day_number} - {base_name} ({value})"),
        None => format!("Day {day_number} - {base_name}"),
    }
}

fn build_film_shooting_day_rationale(
    location_name: &str,
    time_of_day: Option<&str>,
    strategies: &[String],
    group_by_location: bool,
) -> String {
    let mut parts = Vec::new();
    if group_by_location {
        parts.push(format!(
            "Grouped around {location_name} to reduce company moves and keep setups stable."
        ));
    } else {
        parts.push(
            "Kept story-sequence continuity instead of forcing a single-location block."
                .to_string(),
        );
    }
    if let Some(value) = time_of_day.map(str::trim).filter(|value| !value.is_empty()) {
        parts.push(format!(
            "Scenes share a {value} setup window for lighting and continuity."
        ));
    }
    if !strategies.is_empty() {
        parts.push(format!(
            "Shot-variant coverage is available for {}.",
            strategies.join(", ")
        ));
    }
    parts.join(" ")
}

fn standardize_film_project_script(
    service: &FileBackedFilmService,
    project_key: &str,
    input: FilmScriptStandardizeInput,
) -> ServerResult<Value> {
    let include_validation = input.include_validation.unwrap_or(true);
    let (path, project) = service.read_document_by_key(
        service.storage_paths.film_projects_dir(),
        project_key,
        "film project",
    )?;
    let (standardized_project, summary) = standardize_film_project_script_document(project)?;

    FileBackedFilmService::write_document(&path, &standardized_project, "FILM_PROJECT")?;

    let mut response = Map::new();
    response.insert("project".to_string(), standardized_project.clone());
    response.insert("summary".to_string(), summary);
    if include_validation {
        response.insert(
            "validation".to_string(),
            build_film_project_validation_report(
                preview_normalize_film_project(standardized_project, Some(project_key))?,
                "stored-project",
                false,
            )?,
        );
    }

    Ok(Value::Object(response))
}

fn standardize_film_project_script_document(document: Value) -> ServerResult<(Value, Value)> {
    let mut object = require_object(document, "FILM_PROJECT_INVALID")?;
    let now_ms = current_time_millis();
    let project_name =
        read_map_text(&object, "name").unwrap_or_else(|| "Untitled Film Project".to_string());
    let script = object
        .get_mut("script")
        .and_then(Value::as_object_mut)
        .ok_or_else(|| {
            ServerError::bad_request("FILM_SCRIPT_MISSING", "film project is missing script")
        })?;
    let original_content = read_map_text(script, "content").ok_or_else(|| {
        ServerError::bad_request(
            "FILM_SCRIPT_CONTENT_EMPTY",
            "film project script.content must not be empty",
        )
    })?;
    let original_content = require_non_empty_text(
        &original_content,
        "FILM_SCRIPT_CONTENT_EMPTY",
        "film project script.content",
    )?;

    let original_lines = normalize_script_lines(&original_content);
    let standardized_lines = standardize_film_script_lines(&original_lines);
    let standardized_content = standardized_lines.join("\n");
    let changed = original_lines.join("\n") != standardized_content;
    let scene_heading_count = standardized_lines
        .iter()
        .filter(|line| is_scene_heading(line))
        .count();
    let dialogue_cue_count = standardized_lines
        .iter()
        .filter(|line| {
            line.contains(':')
                && extract_character_name_from_line(line)
                    .map(|name| !name.is_empty())
                    .unwrap_or(false)
        })
        .count();

    script.insert("content".to_string(), Value::String(standardized_content));
    script.insert("standardized".to_string(), Value::Bool(true));
    if read_map_text(script, "title").is_none() {
        script.insert("title".to_string(), Value::String(project_name));
    }
    script.insert("updatedAt".to_string(), json_number(now_ms));
    object.insert("updatedAt".to_string(), json_number(now_ms));

    let standardized_project = attach_film_project_graph(Value::Object(object))?;
    let summary = json!({
        "changed": changed,
        "lineCountBefore": original_lines.len(),
        "lineCountAfter": standardized_lines.len(),
        "sceneHeadingCount": scene_heading_count,
        "dialogueCueCount": dialogue_cue_count,
    });

    Ok((standardized_project, summary))
}

fn run_film_authoring_batch(
    service: &FileBackedFilmService,
    project_key: &str,
    input: FilmAuthoringBatchInput,
) -> ServerResult<Value> {
    if input.commands.is_empty() {
        return Err(ServerError::bad_request(
            "FILM_AUTHORING_COMMANDS_EMPTY",
            "commands must contain at least one authoring command",
        ));
    }

    let (path, project) = service.read_document_by_key(
        service.storage_paths.film_projects_dir(),
        project_key,
        "film project",
    )?;

    let mut current_project = project;
    let mut results = Vec::new();
    for command in input.commands {
        current_project = apply_film_authoring_command(current_project, command.clone())?;
        results.push(build_film_authoring_command_result(
            &command.command,
            &current_project,
        )?);
    }

    FileBackedFilmService::write_document(&path, &current_project, "FILM_PROJECT")?;

    let mut response = Map::new();
    response.insert("project".to_string(), current_project.clone());
    response.insert("results".to_string(), Value::Array(results));
    if input.include_validation.unwrap_or(true) {
        response.insert(
            "validation".to_string(),
            build_film_project_validation_report(
                preview_normalize_film_project(current_project, Some(project_key))?,
                "stored-project",
                false,
            )?,
        );
    }

    Ok(Value::Object(response))
}

fn apply_film_authoring_command(
    project: Value,
    command: FilmAuthoringCommandInput,
) -> ServerResult<Value> {
    let normalized_command =
        require_non_empty_text(&command.command, "FILM_AUTHORING_COMMAND_EMPTY", "command")?
            .to_ascii_lowercase();

    match normalized_command.as_str() {
        "standardize-script" => {
            standardize_film_project_script_document(project).map(|value| value.0)
        }
        "hydrate-analysis" => hydrate_film_project_entities(project, command.language),
        "reindex-scenes" => reindex_film_project_scenes(project),
        "generate-storyboard" => generate_storyboard_project(
            project,
            FilmStoryboardGenerateInput {
                language: command.language,
                replace_shots: command.replace_shots,
                max_shots_per_scene: command.max_shots_per_scene,
                include_establishing_shot: command.include_establishing_shot,
            },
        ),
        "sync-shots" => sync_film_project_shots(
            project,
            FilmShotSyncInput {
                regenerate_shot_numbers: command.regenerate_shot_numbers,
                fill_scene_bindings: command.fill_scene_bindings,
            },
        ),
        _ => Err(ServerError::bad_request(
            "FILM_AUTHORING_COMMAND_UNSUPPORTED",
            format!("authoring command {normalized_command} is not supported"),
        )),
    }
}

fn build_film_authoring_command_result(command: &str, project: &Value) -> ServerResult<Value> {
    let project_object = require_object(project.clone(), "FILM_PROJECT_INVALID")?;
    let message = match command {
        "standardize-script" => "Standardized canonical script content",
        "hydrate-analysis" => "Hydrated canonical film entities from script content",
        "reindex-scenes" => "Reindexed canonical scene ordering",
        "generate-storyboard" => "Generated canonical storyboard shots",
        "sync-shots" => "Synchronized shot numbering and scene bindings",
        _ => "Applied canonical film authoring command",
    };

    Ok(json!({
        "command": command,
        "applied": true,
        "message": message,
        "counts": build_film_project_count_snapshot(&project_object),
    }))
}

fn hydrate_film_project_entities(document: Value, language: Option<String>) -> ServerResult<Value> {
    let mut object = require_object(document, "FILM_PROJECT_INVALID")?;
    let now_ms = current_time_millis();
    hydrate_film_project_from_script_analysis(&mut object, language)?;
    set_film_project_status(&mut object);
    object.insert("updatedAt".to_string(), json_number(now_ms));
    attach_film_project_graph(Value::Object(object))
}

fn reindex_film_project_scenes(document: Value) -> ServerResult<Value> {
    let mut object = require_object(document, "FILM_PROJECT_INVALID")?;
    let now_ms = current_time_millis();
    let scenes = ensure_array_field(&mut object, "scenes")?;
    let mut ordered_scenes = scenes
        .iter()
        .enumerate()
        .filter_map(|(fallback_index, value)| {
            value.as_object().cloned().map(|scene| {
                (
                    resolve_scene_order_from_object(&scene, fallback_index),
                    scene,
                )
            })
        })
        .collect::<Vec<_>>();
    ordered_scenes.sort_by(|left, right| left.0.cmp(&right.0));

    let mut next_scenes = Vec::new();
    for (index, (_, mut scene)) in ordered_scenes.into_iter().enumerate() {
        let order = index + 1;
        scene.insert("sceneNumber".to_string(), json_number(order as i64));
        scene.insert("index".to_string(), json_number(order as i64));
        scene.insert("updatedAt".to_string(), json_number(now_ms));
        next_scenes.push(Value::Object(scene));
    }

    *scenes = next_scenes;
    object.insert("updatedAt".to_string(), json_number(now_ms));
    attach_film_project_graph(Value::Object(object))
}

fn resolve_film_bind_target_field(
    entity_type: &str,
    target_field: Option<String>,
) -> ServerResult<String> {
    if let Some(value) = normalize_optional_text(target_field) {
        return Ok(value);
    }

    match entity_type {
        "project" => Ok("media".to_string()),
        "shot" => Ok("assets".to_string()),
        "character" | "location" | "prop" => Ok("refAssets".to_string()),
        _ => Err(ServerError::bad_request(
            "FILM_BIND_ENTITY_TYPE_UNSUPPORTED",
            format!("entityType {entity_type} is not supported"),
        )),
    }
}

fn normalize_film_bind_mode(mode: Option<String>) -> ServerResult<String> {
    let normalized = normalize_optional_text(mode).unwrap_or_else(|| "append".to_string());
    match normalized.as_str() {
        "append" | "replace" | "set-primary" => Ok(normalized),
        _ => Err(ServerError::bad_request(
            "FILM_BIND_MODE_UNSUPPORTED",
            format!("mode {normalized} is not supported"),
        )),
    }
}

fn normalize_film_bind_asset_resource(
    input: FilmAssetBindAssetInput,
    now_ms: i64,
) -> ServerResult<Value> {
    let url = input.url.as_deref().ok_or_else(|| {
        ServerError::bad_request("FILM_BIND_ASSET_URL_MISSING", "asset.url must not be empty")
    })?;
    let url = require_non_empty_text(url, "FILM_BIND_ASSET_URL_EMPTY", "asset.url")?;
    let asset_type = normalize_film_asset_type(input.r#type, &url)?;
    let asset_id = first_non_empty_text([
        input.asset_id.as_deref(),
        input.id.as_deref(),
        input.file_id.as_deref(),
        input.asset_uuid.as_deref(),
        input.uuid.as_deref(),
    ])
    .unwrap_or_else(|| next_film_entity_key("film-asset"));
    let asset_uuid = first_non_empty_text([
        input.asset_uuid.as_deref(),
        input.uuid.as_deref(),
        Some(asset_id.as_str()),
    ])
    .unwrap_or_else(|| asset_id.clone());
    let file_id = first_non_empty_text([input.file_id.as_deref(), Some(asset_id.as_str())]);
    let scene = normalize_optional_text(input.scene);

    let mut object = Map::new();
    object.insert("id".to_string(), Value::String(asset_id.clone()));
    object.insert("uuid".to_string(), Value::String(asset_uuid.clone()));
    object.insert("type".to_string(), Value::String(asset_type.clone()));
    object.insert("assetId".to_string(), Value::String(asset_id.clone()));
    object.insert("assetType".to_string(), Value::String(asset_type));
    object.insert("url".to_string(), Value::String(url));
    if let Some(file_id) = file_id {
        object.insert("fileId".to_string(), Value::String(file_id));
    }
    if let Some(file_name) = normalize_optional_text(input.file_name) {
        object.insert("fileName".to_string(), Value::String(file_name));
    }
    if let Some(scene) = scene {
        object.insert("scene".to_string(), Value::String(scene));
    }
    if let Some(metadata) = input.metadata.filter(Value::is_object) {
        object.insert("metadata".to_string(), metadata);
    }
    object.insert("createdAt".to_string(), json_number(now_ms));
    object.insert("updatedAt".to_string(), json_number(now_ms));

    Ok(Value::Object(object))
}

fn normalize_film_asset_type(value: Option<String>, url: &str) -> ServerResult<String> {
    let normalized = normalize_optional_text(value)
        .unwrap_or_else(|| infer_film_asset_type_from_url(url).to_string());
    match normalized.as_str() {
        "image" | "video" | "audio" | "music" | "voice" | "document" | "other" => Ok(normalized),
        _ => Err(ServerError::bad_request(
            "FILM_BIND_ASSET_TYPE_UNSUPPORTED",
            format!("asset.type {normalized} is not supported"),
        )),
    }
}

fn infer_film_asset_type_from_url(url: &str) -> &'static str {
    let normalized = url.to_ascii_lowercase();
    if normalized.ends_with(".mp4")
        || normalized.ends_with(".mov")
        || normalized.ends_with(".webm")
        || normalized.ends_with(".mkv")
        || normalized.ends_with(".avi")
    {
        "video"
    } else if normalized.ends_with(".mp3")
        || normalized.ends_with(".wav")
        || normalized.ends_with(".ogg")
        || normalized.ends_with(".flac")
        || normalized.ends_with(".m4a")
    {
        "audio"
    } else if normalized.ends_with(".pdf")
        || normalized.ends_with(".doc")
        || normalized.ends_with(".docx")
        || normalized.ends_with(".txt")
        || normalized.ends_with(".md")
        || normalized.ends_with(".json")
    {
        "document"
    } else {
        "image"
    }
}

fn apply_reference_entity_asset_binding(
    entity_type: &str,
    entity: &mut Map<String, Value>,
    target_field: &str,
    mode: &str,
    asset: &Value,
    now_ms: i64,
) -> ServerResult<()> {
    match target_field {
        "refAssets" => {
            let ref_assets = ensure_array_field(entity, "refAssets")?;
            *ref_assets = upsert_film_asset_collection(ref_assets.clone(), asset.clone(), mode);
            synchronize_reference_asset_projection(entity_type, entity, asset, now_ms)?;
        }
        "faceImage" | "threeViewImage" | "gridViewImage" | "image" => {
            let image = build_film_image_binding_resource(asset)?;
            entity.insert(target_field.to_string(), image);

            let projected_asset =
                with_default_projection_scene(entity_type, target_field, asset.clone());
            let ref_assets = ensure_array_field(entity, "refAssets")?;
            *ref_assets = upsert_film_asset_collection(ref_assets.clone(), projected_asset, mode);
        }
        _ => {
            return Err(ServerError::bad_request(
                "FILM_BIND_TARGET_FIELD_UNSUPPORTED",
                format!("targetField {target_field} is not supported for {entity_type} assets"),
            ));
        }
    }

    entity.insert("updatedAt".to_string(), json_number(now_ms));
    Ok(())
}

fn apply_shot_asset_binding(
    shot: &mut Map<String, Value>,
    target_field: &str,
    mode: &str,
    asset: &Value,
    now_ms: i64,
) -> ServerResult<()> {
    match target_field {
        "assets" => {
            let assets = ensure_array_field(shot, "assets")?;
            *assets = upsert_film_asset_collection(assets.clone(), asset.clone(), mode);
        }
        "generation.assets" => {
            let generation = ensure_object_field(shot, "generation")?;
            let assets = ensure_array_field(generation, "assets")?;
            *assets = upsert_film_asset_collection(assets.clone(), asset.clone(), mode);
        }
        "generation.video" => {
            let next_generation_assets = {
                let generation = ensure_object_field(shot, "generation")?;
                generation.insert(
                    "video".to_string(),
                    build_film_video_binding_resource(asset)?,
                );
                let generation_assets = ensure_array_field(generation, "assets")?;
                let next =
                    upsert_film_asset_collection(generation_assets.clone(), asset.clone(), mode);
                *generation_assets = next.clone();
                next
            };

            let assets = ensure_array_field(shot, "assets")?;
            let mut next_assets = upsert_film_asset_collection(assets.clone(), asset.clone(), mode);
            if next_assets.is_empty() && !next_generation_assets.is_empty() {
                next_assets = next_generation_assets;
            }
            *assets = next_assets;
        }
        _ => {
            return Err(ServerError::bad_request(
                "FILM_BIND_TARGET_FIELD_UNSUPPORTED",
                format!("targetField {target_field} is not supported for shot assets"),
            ));
        }
    }

    shot.insert("updatedAt".to_string(), json_number(now_ms));
    Ok(())
}

fn upsert_film_asset_collection(existing: Vec<Value>, asset: Value, mode: &str) -> Vec<Value> {
    if mode == "replace" {
        return vec![asset];
    }

    let mut filtered = existing
        .into_iter()
        .filter(|current| !matches_film_asset_slot_or_identity(current, &asset))
        .collect::<Vec<_>>();

    if mode == "set-primary" {
        let mut next = vec![asset];
        next.append(&mut filtered);
        next
    } else {
        filtered.push(asset);
        filtered
    }
}

fn matches_film_asset_slot_or_identity(current: &Value, incoming: &Value) -> bool {
    let current_object = match current.as_object() {
        Some(object) => object,
        None => return false,
    };
    let incoming_object = match incoming.as_object() {
        Some(object) => object,
        None => return false,
    };

    let incoming_scene = read_map_text(incoming_object, "scene");
    if let Some(scene) = incoming_scene.as_deref() {
        if read_map_text(current_object, "scene").as_deref() == Some(scene) {
            return true;
        }
    }

    let current_asset_keys = [
        read_map_text(current_object, "assetId"),
        read_map_text(current_object, "fileId"),
        read_map_text(current_object, "uuid"),
        read_map_text(current_object, "id"),
    ];
    let incoming_asset_keys = [
        read_map_text(incoming_object, "assetId"),
        read_map_text(incoming_object, "fileId"),
        read_map_text(incoming_object, "uuid"),
        read_map_text(incoming_object, "id"),
    ];

    current_asset_keys.into_iter().flatten().any(|left| {
        incoming_asset_keys
            .iter()
            .flatten()
            .any(|right| left == *right)
    })
}

fn synchronize_reference_asset_projection(
    entity_type: &str,
    entity: &mut Map<String, Value>,
    asset: &Value,
    _now_ms: i64,
) -> ServerResult<()> {
    let Some(field) = projection_field_from_asset_scene(entity_type, asset) else {
        return Ok(());
    };
    entity.insert(field.to_string(), build_film_image_binding_resource(asset)?);
    Ok(())
}

fn projection_field_from_asset_scene(entity_type: &str, asset: &Value) -> Option<&'static str> {
    let object = asset.as_object()?;
    let scene = read_map_text(object, "scene")?;

    match (entity_type, scene.as_str()) {
        ("character", "AVATAR") => Some("faceImage"),
        ("character", "THREE_VIEW") => Some("threeViewImage"),
        ("character", "GRID_IMAGE") => Some("gridViewImage"),
        ("location", "LOCATION_VISUAL") | ("location", "SCENE_CONCEPT") => Some("image"),
        ("location", "THREE_VIEW") => Some("threeViewImage"),
        ("location", "GRID_IMAGE") => Some("gridViewImage"),
        ("prop", "PROP_VISUAL") => Some("faceImage"),
        ("prop", "THREE_VIEW") => Some("threeViewImage"),
        ("prop", "GRID_IMAGE") => Some("gridViewImage"),
        _ => None,
    }
}

fn with_default_projection_scene(entity_type: &str, target_field: &str, asset: Value) -> Value {
    let Some(scene) = default_projection_scene(entity_type, target_field) else {
        return asset;
    };

    let mut object = match asset.as_object() {
        Some(object) => object.clone(),
        None => return asset,
    };
    if read_map_text(&object, "scene").is_none() {
        object.insert("scene".to_string(), Value::String(scene.to_string()));
    }
    Value::Object(object)
}

fn default_projection_scene(entity_type: &str, target_field: &str) -> Option<&'static str> {
    match (entity_type, target_field) {
        ("character", "faceImage") => Some("AVATAR"),
        ("character", "threeViewImage") => Some("THREE_VIEW"),
        ("character", "gridViewImage") => Some("GRID_IMAGE"),
        ("location", "image") => Some("LOCATION_VISUAL"),
        ("location", "threeViewImage") => Some("THREE_VIEW"),
        ("location", "gridViewImage") => Some("GRID_IMAGE"),
        ("prop", "faceImage") => Some("PROP_VISUAL"),
        ("prop", "threeViewImage") => Some("THREE_VIEW"),
        ("prop", "gridViewImage") => Some("GRID_IMAGE"),
        _ => None,
    }
}

fn build_film_image_binding_resource(asset: &Value) -> ServerResult<Value> {
    let object = asset.as_object().ok_or_else(|| {
        ServerError::bad_request(
            "FILM_BIND_ASSET_INVALID",
            "asset binding resource must be a JSON object",
        )
    })?;
    let asset_type = read_map_text(object, "type").unwrap_or_else(|| "image".to_string());
    if asset_type != "image" {
        return Err(ServerError::bad_request(
            "FILM_BIND_ASSET_TYPE_MISMATCH",
            format!("asset type {asset_type} cannot be projected as an image"),
        ));
    }

    let url = read_map_text(object, "url").ok_or_else(|| {
        ServerError::bad_request("FILM_BIND_ASSET_URL_EMPTY", "asset.url must not be empty")
    })?;
    let mut image = Map::new();
    if let Some(id) = read_map_text(object, "id") {
        image.insert("id".to_string(), Value::String(id));
    }
    if let Some(uuid) = read_map_text(object, "uuid") {
        image.insert("uuid".to_string(), Value::String(uuid));
    }
    image.insert("type".to_string(), Value::String("image".to_string()));
    image.insert("url".to_string(), Value::String(url));
    if let Some(file_id) =
        read_map_text(object, "fileId").or_else(|| read_map_text(object, "assetId"))
    {
        image.insert("fileId".to_string(), Value::String(file_id));
    }
    if let Some(file_name) = read_map_text(object, "fileName") {
        image.insert("fileName".to_string(), Value::String(file_name));
    }
    if let Some(created_at) = object.get("createdAt").cloned() {
        image.insert("createdAt".to_string(), created_at);
    }
    if let Some(updated_at) = object.get("updatedAt").cloned() {
        image.insert("updatedAt".to_string(), updated_at);
    }
    Ok(Value::Object(image))
}

fn build_film_video_binding_resource(asset: &Value) -> ServerResult<Value> {
    let object = asset.as_object().ok_or_else(|| {
        ServerError::bad_request(
            "FILM_BIND_ASSET_INVALID",
            "asset binding resource must be a JSON object",
        )
    })?;
    let asset_type = read_map_text(object, "type").unwrap_or_else(|| "video".to_string());
    if asset_type != "video" {
        return Err(ServerError::bad_request(
            "FILM_BIND_ASSET_TYPE_MISMATCH",
            format!("asset type {asset_type} cannot be projected as a video"),
        ));
    }

    let url = read_map_text(object, "url").ok_or_else(|| {
        ServerError::bad_request("FILM_BIND_ASSET_URL_EMPTY", "asset.url must not be empty")
    })?;
    let metadata = object.get("metadata").and_then(Value::as_object);
    let mut video = Map::new();
    video.insert("url".to_string(), Value::String(url.clone()));
    video.insert("thumbnailUrl".to_string(), Value::String(url));
    if let Some(duration) = metadata.and_then(|value| read_map_i64(value, "duration")) {
        video.insert("duration".to_string(), json_number(duration));
    }
    if let Some(width) = metadata.and_then(|value| read_map_i64(value, "width")) {
        video.insert("width".to_string(), json_number(width));
    }
    if let Some(height) = metadata.and_then(|value| read_map_i64(value, "height")) {
        video.insert("height".to_string(), json_number(height));
    }
    Ok(Value::Object(video))
}

fn build_film_asset_inventory_result(document: Value) -> ServerResult<Value> {
    let project = require_object(document, "FILM_PROJECT_INVALID")?;
    let project_id = read_map_text(&project, "id")
        .or_else(|| read_map_text(&project, "uuid"))
        .unwrap_or_else(|| "film-project".to_string());
    let project_uuid = read_map_text(&project, "uuid").unwrap_or_else(|| project_id.clone());
    let project_name =
        read_map_text(&project, "name").unwrap_or_else(|| "Untitled Film Project".to_string());
    let items = collect_film_asset_inventory(&project);
    let mut by_entity_type = BTreeMap::<String, i64>::new();
    let mut by_asset_type = BTreeMap::<String, i64>::new();
    let mut by_target_field = BTreeMap::<String, i64>::new();

    for item in &items {
        let Some(object) = item.as_object() else {
            continue;
        };
        if let Some(entity_type) = read_map_text(object, "entityType") {
            *by_entity_type.entry(entity_type).or_insert(0) += 1;
        }
        if let Some(asset_type) = read_map_text(object, "type") {
            *by_asset_type.entry(asset_type).or_insert(0) += 1;
        }
        if let Some(target_field) = read_map_text(object, "targetField") {
            *by_target_field.entry(target_field).or_insert(0) += 1;
        }
    }

    Ok(json!({
        "projectId": project_id,
        "projectUuid": project_uuid,
        "projectName": project_name,
        "summary": {
            "totalCount": items.len(),
            "byEntityType": by_entity_type,
            "byAssetType": by_asset_type,
            "byTargetField": by_target_field,
        },
        "items": items,
    }))
}

fn collect_film_asset_inventory(project: &Map<String, Value>) -> Vec<Value> {
    let project_id = read_map_text(project, "id")
        .or_else(|| read_map_text(project, "uuid"))
        .unwrap_or_else(|| "film-project".to_string());
    let mut seen = BTreeSet::new();
    let mut items = Vec::new();

    collect_film_asset_records_from_array(
        &mut items,
        &mut seen,
        "project",
        &project_id,
        "media",
        project.get("media"),
    );

    collect_film_asset_records_from_entities(
        &mut items,
        &mut seen,
        "character",
        project.get("characters"),
        &["refAssets", "faceImage", "threeViewImage", "gridViewImage"],
    );
    collect_film_asset_records_from_entities(
        &mut items,
        &mut seen,
        "location",
        project.get("locations"),
        &["refAssets", "image", "threeViewImage", "gridViewImage"],
    );
    collect_film_asset_records_from_entities(
        &mut items,
        &mut seen,
        "prop",
        project.get("props"),
        &["refAssets", "faceImage", "threeViewImage", "gridViewImage"],
    );
    collect_film_asset_records_from_shots(&mut items, &mut seen, project.get("shots"));

    items
}

fn collect_film_asset_records_from_entities(
    items: &mut Vec<Value>,
    seen: &mut BTreeSet<String>,
    entity_type: &str,
    entities: Option<&Value>,
    fields: &[&str],
) {
    let Some(values) = entities.and_then(Value::as_array) else {
        return;
    };

    for entity in values {
        let Some(object) = entity.as_object() else {
            continue;
        };
        let entity_id = read_map_text(object, "id")
            .or_else(|| read_map_text(object, "uuid"))
            .unwrap_or_else(|| format!("{entity_type}-unknown"));
        for field in fields {
            if *field == "refAssets" {
                collect_film_asset_records_from_array(
                    items,
                    seen,
                    entity_type,
                    &entity_id,
                    field,
                    object.get(*field),
                );
            } else if let Some(value) = object.get(*field) {
                push_film_asset_record(items, seen, entity_type, &entity_id, field, value);
            }
        }
    }
}

fn collect_film_asset_records_from_shots(
    items: &mut Vec<Value>,
    seen: &mut BTreeSet<String>,
    shots: Option<&Value>,
) {
    let Some(values) = shots.and_then(Value::as_array) else {
        return;
    };

    for shot in values {
        let Some(object) = shot.as_object() else {
            continue;
        };
        let shot_id = read_map_text(object, "id")
            .or_else(|| read_map_text(object, "uuid"))
            .unwrap_or_else(|| "film-shot-unknown".to_string());
        collect_film_asset_records_from_array(
            items,
            seen,
            "shot",
            &shot_id,
            "assets",
            object.get("assets"),
        );
        if let Some(generation) = object.get("generation").and_then(Value::as_object) {
            collect_film_asset_records_from_array(
                items,
                seen,
                "shot",
                &shot_id,
                "generation.assets",
                generation.get("assets"),
            );
            if let Some(video) = generation.get("video") {
                push_film_asset_record(items, seen, "shot", &shot_id, "generation.video", video);
            }
        }
    }
}

fn collect_film_asset_records_from_array(
    items: &mut Vec<Value>,
    seen: &mut BTreeSet<String>,
    entity_type: &str,
    entity_id: &str,
    target_field: &str,
    value: Option<&Value>,
) {
    let Some(values) = value.and_then(Value::as_array) else {
        return;
    };

    for asset in values {
        push_film_asset_record(items, seen, entity_type, entity_id, target_field, asset);
    }
}

fn push_film_asset_record(
    items: &mut Vec<Value>,
    seen: &mut BTreeSet<String>,
    entity_type: &str,
    entity_id: &str,
    target_field: &str,
    asset: &Value,
) {
    let Some(object) = asset.as_object() else {
        return;
    };
    let asset_id = read_map_text(object, "assetId")
        .or_else(|| read_map_text(object, "fileId"))
        .or_else(|| read_map_text(object, "id"));
    let asset_uuid = read_map_text(object, "assetUuid").or_else(|| read_map_text(object, "uuid"));
    let url = read_map_text(object, "url").or_else(|| {
        object
            .get("image")
            .and_then(Value::as_object)
            .and_then(|image| read_map_text(image, "url"))
    });
    let scene = read_map_text(object, "scene");
    let dedupe_key = format!(
        "{entity_type}:{entity_id}:{target_field}:{}:{}:{}",
        asset_id.clone().unwrap_or_default(),
        asset_uuid.clone().unwrap_or_default(),
        url.clone().unwrap_or_default()
    );
    if !seen.insert(dedupe_key) {
        return;
    }

    items.push(json!({
        "entityType": entity_type,
        "entityId": entity_id,
        "targetField": target_field,
        "assetId": asset_id,
        "assetUuid": asset_uuid,
        "type": read_map_text(object, "type"),
        "url": url,
        "fileId": read_map_text(object, "fileId"),
        "fileName": read_map_text(object, "fileName"),
        "scene": scene,
    }));
}

fn build_film_export_manifest(
    project: &Map<String, Value>,
    project_id: &str,
    project_uuid: &str,
    project_name: &str,
    project_status: &str,
    export_id: &str,
    archive_file_name: &str,
    now_ms: i64,
    include_asset_inventory: bool,
    asset_count: usize,
) -> Value {
    json!({
        "formatVersion": 1,
        "domain": "film",
        "exportId": export_id,
        "exportedAtMs": now_ms,
        "project": {
            "id": project_id,
            "uuid": project_uuid,
            "name": project_name,
            "status": project_status,
            "counts": {
                "characters": array_len(project.get("characters")),
                "locations": array_len(project.get("locations")),
                "props": array_len(project.get("props")),
                "scenes": array_len(project.get("scenes")),
                "shots": array_len(project.get("shots")),
                "media": array_len(project.get("media")),
            }
        },
        "contents": {
            "projectGraphIncluded": project.get("projectGraph").is_some(),
            "assetInventoryIncluded": include_asset_inventory,
            "assetCount": asset_count,
        },
        "archive": {
            "fileName": archive_file_name,
            "mimeType": "application/zip",
        }
    })
}

fn build_film_export_file_record(
    relative_path: &str,
    kind: &str,
    absolute_path: &Path,
) -> ServerResult<Value> {
    let size_bytes = fs::metadata(absolute_path)
        .map(|metadata| metadata.len())
        .map_err(|error| {
            ServerError::internal(
                "FILM_EXPORT_FILE_STAT_FAILED",
                format!("failed to stat {}: {error}", absolute_path.display()),
            )
        })?;

    Ok(json!({
        "relativePath": relative_path,
        "kind": kind,
        "sizeBytes": size_bytes,
    }))
}

fn normalize_film_export_file_name(value: Option<String>, fallback_stem: &str) -> String {
    let raw = normalize_optional_text(value).unwrap_or_else(|| fallback_stem.to_string());
    let without_extension = raw.trim_end_matches(".zip").trim_end_matches(".ZIP").trim();
    format!("{}.zip", sanitize_file_name(without_extension))
}

fn sanitize_path_segment(value: &str) -> String {
    let sanitized = value
        .chars()
        .map(|character| {
            if character.is_ascii_alphanumeric() || matches!(character, '-' | '_') {
                character
            } else {
                '-'
            }
        })
        .collect::<String>()
        .trim_matches('-')
        .to_string();

    if sanitized.is_empty() {
        "film".to_string()
    } else {
        sanitized
    }
}

fn sanitize_file_name(value: &str) -> String {
    let sanitized = value
        .chars()
        .map(|character| {
            if character.is_ascii_alphanumeric() || matches!(character, '-' | '_' | ' ' | '.') {
                character
            } else {
                '-'
            }
        })
        .collect::<String>()
        .trim()
        .trim_matches('.')
        .to_string();

    if sanitized.is_empty() {
        "film-export".to_string()
    } else {
        sanitized
    }
}

fn relative_storage_path(root: &Path, path: &Path) -> String {
    path.strip_prefix(root)
        .map(path_to_string)
        .unwrap_or_else(|_| path_to_string(path))
}

fn path_to_string(path: &Path) -> String {
    path.to_string_lossy().replace('\\', "/")
}

fn html_escape_text(value: &str) -> String {
    value
        .replace('&', "&amp;")
        .replace('<', "&lt;")
        .replace('>', "&gt;")
        .replace('"', "&quot;")
        .replace('\'', "&#39;")
}

fn array_len(value: Option<&Value>) -> usize {
    value.and_then(Value::as_array).map(Vec::len).unwrap_or(0)
}

fn ensure_array_field<'a>(
    object: &'a mut Map<String, Value>,
    key: &str,
) -> ServerResult<&'a mut Vec<Value>> {
    if !object.get(key).is_some_and(Value::is_array) {
        object.insert(key.to_string(), Value::Array(Vec::new()));
    }
    object
        .get_mut(key)
        .and_then(Value::as_array_mut)
        .ok_or_else(|| {
            ServerError::internal(
                "FILM_ARRAY_FIELD_INVALID",
                format!("field {key} must resolve to a JSON array"),
            )
        })
}

fn ensure_object_field<'a>(
    object: &'a mut Map<String, Value>,
    key: &str,
) -> ServerResult<&'a mut Map<String, Value>> {
    if !object.get(key).is_some_and(Value::is_object) {
        object.insert(key.to_string(), Value::Object(Map::new()));
    }
    object
        .get_mut(key)
        .and_then(Value::as_object_mut)
        .ok_or_else(|| {
            ServerError::internal(
                "FILM_OBJECT_FIELD_INVALID",
                format!("field {key} must resolve to a JSON object"),
            )
        })
}

fn find_entity_index(items: &[Value], entity_id: &str) -> Option<usize> {
    items.iter().position(|item| match item.as_object() {
        Some(object) => {
            read_map_text(object, "id").as_deref() == Some(entity_id)
                || read_map_text(object, "uuid").as_deref() == Some(entity_id)
        }
        None => false,
    })
}

fn first_non_empty_text<'a, I>(values: I) -> Option<String>
where
    I: IntoIterator<Item = Option<&'a str>>,
{
    values
        .into_iter()
        .flatten()
        .map(str::trim)
        .find(|value| !value.is_empty())
        .map(str::to_string)
}

fn build_storyboard_shots(
    _project_key: &str,
    scenes: &[Value],
    locations: &[Value],
    characters: &[Value],
    now_ms: i64,
    max_shots_per_scene: usize,
    include_establishing_shot: bool,
) -> Vec<Value> {
    let mut ordered_scenes = scenes
        .iter()
        .enumerate()
        .filter_map(|(fallback_index, value)| {
            value.as_object().cloned().map(|scene| {
                (
                    resolve_scene_order_from_object(&scene, fallback_index),
                    scene,
                )
            })
        })
        .collect::<Vec<_>>();
    ordered_scenes.sort_by(|left, right| left.0.cmp(&right.0));

    let location_name_by_key = locations
        .iter()
        .filter_map(|value| {
            let object = value.as_object()?;
            let name = read_map_text(object, "name")?;
            let key = read_map_text(object, "uuid").or_else(|| read_map_text(object, "id"))?;
            Some((key, name))
        })
        .collect::<BTreeMap<_, _>>();
    let character_name_by_key = characters
        .iter()
        .filter_map(|value| {
            let object = value.as_object()?;
            let name = read_map_text(object, "name")?;
            let key = read_map_text(object, "uuid").or_else(|| read_map_text(object, "id"))?;
            Some((key, name))
        })
        .collect::<BTreeMap<_, _>>();

    let mut generated_shots = Vec::new();
    for (fallback_index, (_, scene)) in ordered_scenes.into_iter().enumerate() {
        let scene_uuid = read_map_text(&scene, "uuid")
            .or_else(|| read_map_text(&scene, "id"))
            .unwrap_or_else(|| next_film_entity_key("film-scene"));
        let scene_id = read_map_text(&scene, "id");
        let scene_summary =
            read_map_text(&scene, "summary").unwrap_or_else(|| "New film scene".to_string());
        let scene_visual_prompt =
            read_map_text(&scene, "visualPrompt").unwrap_or_else(|| scene_summary.clone());
        let scene_location_uuid =
            read_map_text(&scene, "locationUuid").or_else(|| read_map_text(&scene, "locationId"));
        let scene_location_name = scene_location_uuid
            .as_ref()
            .and_then(|value| location_name_by_key.get(value).cloned())
            .unwrap_or_else(|| resolve_scene_title_from_object(&scene, fallback_index));
        let scene_time_of_day = read_map_string_array(&scene, "moodTags")
            .into_iter()
            .next()
            .unwrap_or_else(|| "DAY".to_string());
        let scene_character_keys = {
            let keys = read_map_string_array(&scene, "characterUuids");
            if keys.is_empty() {
                read_map_string_array(&scene, "characterIds")
            } else {
                keys
            }
        };
        let scene_character_names = scene_character_keys
            .iter()
            .filter_map(|key| character_name_by_key.get(key).cloned())
            .collect::<Vec<_>>();
        let focus_subject = if scene_character_names.is_empty() {
            scene_location_name.clone()
        } else {
            join_names_with_and(&scene_character_names)
        };

        let target_shot_count = if max_shots_per_scene == 1 {
            1
        } else if scene_character_names.is_empty() {
            max_shots_per_scene.min(2)
        } else {
            max_shots_per_scene.min(3)
        };

        let mut shot_specs = Vec::<(String, String, i64)>::new();
        if include_establishing_shot {
            shot_specs.push((
                format!(
                    "Wide cinematic establishing shot of {} during {}, {}",
                    scene_location_name, scene_time_of_day, scene_summary
                ),
                format!("Wide establishing shot for {}.", scene_location_name),
                4,
            ));
        }
        shot_specs.push((
            format!("Medium cinematic shot, {}", scene_visual_prompt),
            format!("Primary action beat: {}.", scene_summary),
            3,
        ));
        shot_specs.push((
            format!(
                "Close-up emotional detail of {}, reacting within {}",
                focus_subject, scene_location_name
            ),
            format!("Close-up emotional detail featuring {}.", focus_subject),
            3,
        ));

        let trimmed_specs = shot_specs
            .into_iter()
            .take(target_shot_count)
            .collect::<Vec<_>>();

        for (shot_index, (prompt, description, duration)) in trimmed_specs.into_iter().enumerate() {
            let shot_key = next_film_entity_key("film-shot");
            generated_shots.push(json!({
                "id": shot_key,
                "uuid": shot_key,
                "type": "FILM_SHOT",
                "shotNumber": shot_index + 1,
                "index": shot_index + 1,
                "sceneId": scene_id.clone(),
                "sceneUuid": scene_uuid.clone(),
                "locationUuid": scene_location_uuid.clone(),
                "description": description,
                "dialogue": {
                    "items": Vec::<Value>::new(),
                },
                "duration": duration,
                "generation": {
                    "status": "PENDING",
                    "prompt": prompt.clone(),
                    "base": prompt,
                    "product": "image",
                    "assets": Vec::<Value>::new(),
                },
                "assets": Vec::<Value>::new(),
                "characterIds": scene_character_keys.clone(),
                "createdAt": now_ms,
                "updatedAt": now_ms,
            }));
        }
    }

    generated_shots
}

fn build_film_project_graph_document(project: &Map<String, Value>) -> Value {
    let timestamp = read_map_i64(project, "updatedAt")
        .or_else(|| read_map_i64(project, "createdAt"))
        .unwrap_or_else(current_time_millis);
    let project_uuid = read_map_text(project, "uuid")
        .or_else(|| read_map_text(project, "id"))
        .unwrap_or_else(|| "film-project".to_string());
    let project_name =
        read_map_text(project, "name").unwrap_or_else(|| "Untitled Film Project".to_string());
    let project_description = read_map_text(project, "description");
    let project_status = read_map_text(project, "status").unwrap_or_else(|| "DRAFT".to_string());
    let sequence_uuid = format!("{project_uuid}:film-sequence:primary");

    let mut surface_bindings = vec![create_surface_binding_value(
        "film-project",
        read_map_text(project, "id"),
        project_uuid.clone(),
        "project",
        project_uuid.clone(),
        timestamp,
    )];

    let mut ordered_scenes = project
        .get("scenes")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default()
        .into_iter()
        .enumerate()
        .filter_map(|(fallback_index, value)| {
            value.as_object().cloned().map(|scene| {
                (
                    resolve_scene_order_from_object(&scene, fallback_index),
                    scene,
                )
            })
        })
        .collect::<Vec<_>>();
    ordered_scenes.sort_by(|left, right| left.0.cmp(&right.0));

    let mut scenes_by_uuid = BTreeMap::<String, Value>::new();
    let mut scene_lookup = BTreeMap::<String, String>::new();
    let mut ordered_scene_uuids = Vec::<String>::new();
    let mut scene_shot_uuids = BTreeMap::<String, Vec<String>>::new();

    for (fallback_index, (_, scene)) in ordered_scenes.into_iter().enumerate() {
        let scene_uuid = read_map_text(&scene, "uuid")
            .or_else(|| read_map_text(&scene, "id"))
            .unwrap_or_else(|| format!("{project_uuid}:scene:{}", fallback_index + 1));
        let scene_order = resolve_scene_order_from_object(&scene, fallback_index) as i64;
        let scene_timestamp = read_map_i64(&scene, "updatedAt")
            .or_else(|| read_map_i64(&scene, "createdAt"))
            .unwrap_or(timestamp);

        ordered_scene_uuids.push(scene_uuid.clone());
        scene_lookup.insert(scene_uuid.clone(), scene_uuid.clone());
        if let Some(scene_id) = read_map_text(&scene, "id") {
            scene_lookup.insert(scene_id, scene_uuid.clone());
        }
        scene_shot_uuids.insert(scene_uuid.clone(), Vec::new());
        scenes_by_uuid.insert(
            scene_uuid.clone(),
            json!({
                "id": null,
                "uuid": scene_uuid,
                "createdAt": scene_timestamp,
                "updatedAt": scene_timestamp,
                "projectUuid": project_uuid,
                "sequenceUuid": sequence_uuid,
                "order": scene_order,
                "title": resolve_scene_title_from_object(&scene, fallback_index),
                "summary": read_map_text(&scene, "summary"),
                "shotUuids": Vec::<String>::new(),
                "metadata": {
                    "sourceSceneId": read_map_text(&scene, "id"),
                    "locationId": read_map_text(&scene, "locationId"),
                    "locationUuid": read_map_text(&scene, "locationUuid"),
                    "characterIds": read_map_string_array(&scene, "characterIds"),
                    "characterUuids": read_map_string_array(&scene, "characterUuids"),
                    "propUuids": read_map_string_array(&scene, "propUuids"),
                    "moodTags": read_map_string_array(&scene, "moodTags"),
                    "visualPrompt": read_map_text(&scene, "visualPrompt"),
                }
            }),
        );
        surface_bindings.push(create_surface_binding_value(
            "film-scene",
            read_map_text(&scene, "id"),
            scene_uuid.clone(),
            "scene",
            scene_uuid,
            timestamp,
        ));
    }

    let mut ordered_shots = project
        .get("shots")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default()
        .into_iter()
        .enumerate()
        .filter_map(|(fallback_index, value)| {
            value
                .as_object()
                .cloned()
                .map(|shot| (resolve_shot_order_from_object(&shot, fallback_index), shot))
        })
        .collect::<Vec<_>>();
    ordered_shots.sort_by(|left, right| left.0.cmp(&right.0));

    let mut shots_by_uuid = BTreeMap::<String, Value>::new();
    for (fallback_index, (_, shot)) in ordered_shots.into_iter().enumerate() {
        let shot_uuid = read_map_text(&shot, "uuid")
            .or_else(|| read_map_text(&shot, "id"))
            .unwrap_or_else(|| format!("{project_uuid}:shot:{}", fallback_index + 1));
        let scene_uuid = read_map_text(&shot, "sceneUuid")
            .and_then(|value| scene_lookup.get(&value).cloned())
            .or_else(|| {
                read_map_text(&shot, "sceneId").and_then(|value| scene_lookup.get(&value).cloned())
            })
            .or_else(|| ordered_scene_uuids.first().cloned())
            .unwrap_or_else(|| format!("{project_uuid}:scene:unassigned"));

        if !scene_shot_uuids.contains_key(&scene_uuid) {
            scene_shot_uuids.insert(scene_uuid.clone(), Vec::new());
            scenes_by_uuid.insert(
                scene_uuid.clone(),
                json!({
                    "id": null,
                    "uuid": scene_uuid,
                    "createdAt": timestamp,
                    "updatedAt": timestamp,
                    "projectUuid": project_uuid,
                    "sequenceUuid": sequence_uuid,
                    "order": ordered_scene_uuids.len() as i64,
                    "title": "Scene",
                    "summary": "Unassigned film shots",
                    "shotUuids": Vec::<String>::new(),
                    "metadata": {
                        "synthetic": true,
                    }
                }),
            );
            ordered_scene_uuids.push(scene_uuid.clone());
        }

        let shot_timestamp = read_map_i64(&shot, "updatedAt")
            .or_else(|| read_map_i64(&shot, "createdAt"))
            .unwrap_or(timestamp);
        let source = first_film_shot_asset_object(&shot)
            .and_then(|asset| build_film_project_graph_source(&asset));
        let product = read_nested_map_text(&shot, "generation", "product").or_else(|| {
            source.as_ref().and_then(|value| {
                value
                    .as_object()
                    .and_then(|object| read_map_text(object, "primaryType"))
            })
        });
        let mode = product.as_deref().and_then(resolve_film_graph_mode);
        let asset_ids = collect_film_shot_asset_ids(&shot);
        let duration = read_map_i64(&shot, "duration").unwrap_or_default();

        shots_by_uuid.insert(
            shot_uuid.clone(),
            json!({
                "id": null,
                "uuid": shot_uuid,
                "createdAt": shot_timestamp,
                "updatedAt": shot_timestamp,
                "projectUuid": project_uuid,
                "sequenceUuid": sequence_uuid,
                "sceneUuid": scene_uuid,
                "order": resolve_shot_order_from_object(&shot, fallback_index) as i64,
                "title": resolve_shot_title_from_object(&shot, fallback_index),
                "prompt": read_nested_map_text(&shot, "generation", "prompt")
                    .or_else(|| read_nested_map_text(&shot, "generation", "base"))
                    .or_else(|| read_map_text(&shot, "description")),
                "product": product.clone(),
                "mode": mode,
                "clipUuid": null,
                "source": source,
                "metadata": {
                    "sourceShotId": read_map_text(&shot, "id"),
                    "sceneId": read_map_text(&shot, "sceneId"),
                    "locationUuid": read_map_text(&shot, "locationUuid"),
                    "description": read_map_text(&shot, "description"),
                    "duration": duration,
                    "characterIds": read_map_string_array(&shot, "characterIds"),
                    "generationStatus": read_nested_map_text(&shot, "generation", "status"),
                    "modelId": read_nested_map_text(&shot, "generation", "modelId"),
                    "assetIds": asset_ids,
                }
            }),
        );
        scene_shot_uuids
            .entry(scene_uuid.clone())
            .or_default()
            .push(shot_uuid.clone());
        surface_bindings.push(create_surface_binding_value(
            "film-shot",
            read_map_text(&shot, "id"),
            shot_uuid.clone(),
            "shot",
            shot_uuid,
            timestamp,
        ));
    }

    let ordered_shot_uuids = ordered_scene_uuids
        .iter()
        .flat_map(|scene_uuid| {
            scene_shot_uuids
                .get(scene_uuid)
                .cloned()
                .unwrap_or_default()
        })
        .collect::<Vec<_>>();

    let mut timeline_cursor = 0_i64;
    for scene_uuid in &ordered_scene_uuids {
        let shot_uuids = scene_shot_uuids
            .get(scene_uuid)
            .cloned()
            .unwrap_or_default();
        let duration = shot_uuids
            .iter()
            .map(|shot_uuid| {
                shots_by_uuid
                    .get(shot_uuid)
                    .and_then(Value::as_object)
                    .and_then(|shot| shot.get("metadata"))
                    .and_then(Value::as_object)
                    .and_then(|metadata| metadata.get("duration"))
                    .and_then(Value::as_i64)
                    .unwrap_or_default()
            })
            .sum::<i64>();

        if let Some(Value::Object(scene)) = scenes_by_uuid.get_mut(scene_uuid) {
            scene.insert(
                "shotUuids".to_string(),
                Value::Array(shot_uuids.iter().cloned().map(Value::String).collect()),
            );
            scene.insert("startTime".to_string(), json_number(timeline_cursor));
            if duration > 0 {
                scene.insert("duration".to_string(), json_number(duration));
            }
        }
        timeline_cursor += duration;
    }

    let mut sequences = Map::new();
    sequences.insert(
        sequence_uuid.clone(),
        json!({
            "id": null,
            "uuid": sequence_uuid,
            "createdAt": timestamp,
            "updatedAt": timestamp,
            "projectUuid": project_uuid,
            "name": read_nested_map_text(project, "script", "title").unwrap_or(project_name.clone()),
            "order": 0,
            "sceneUuids": ordered_scene_uuids.clone(),
            "shotUuids": ordered_shot_uuids.clone(),
            "metadata": {
                "sourceSurface": "film",
                "projectStatus": project_status,
                "settings": {
                    "aspectRatio": read_nested_map_text(project, "settings", "aspectRatio")
                        .or_else(|| read_nested_map_text(project, "settings", "aspect")),
                    "resolution": read_nested_map_text(project, "settings", "resolution"),
                    "fps": read_nested_map_i64(project, "settings", "fps"),
                    "style": read_nested_map_text(project, "settings", "style"),
                }
            }
        }),
    );

    json!({
        "version": 1,
        "project": {
            "id": read_map_text(project, "id"),
            "uuid": project_uuid,
            "createdAt": read_map_i64(project, "createdAt").unwrap_or(timestamp),
            "updatedAt": timestamp,
            "domain": "film",
            "name": project_name,
            "description": project_description,
            "workspaceUuid": null,
            "sequenceUuids": [sequence_uuid.clone()],
            "timelineUuids": Vec::<String>::new(),
            "publishTargetUuids": Vec::<String>::new(),
            "metadata": {
                "sourceSurface": "film",
                "status": project_status,
            }
        },
        "sequences": Value::Object(sequences),
        "scenes": Value::Object(scenes_by_uuid.into_iter().collect()),
        "shots": Value::Object(shots_by_uuid.into_iter().collect()),
        "timelines": Value::Object(Map::new()),
        "tracks": Value::Object(Map::new()),
        "clips": Value::Object(Map::new()),
        "publishTargets": Value::Object(Map::new()),
        "surfaceBindings": surface_bindings,
        "metadata": {
            "sourceSurface": "film",
            "sceneCount": ordered_scene_uuids.len(),
            "shotCount": ordered_shot_uuids.len(),
        }
    })
}

fn create_surface_binding_value(
    surface: &str,
    surface_entity_id: Option<String>,
    surface_entity_uuid: String,
    graph_entity_type: &str,
    graph_entity_uuid: String,
    timestamp: i64,
) -> Value {
    json!({
        "id": null,
        "uuid": format!("{surface}:{surface_entity_uuid}:{graph_entity_uuid}"),
        "createdAt": timestamp,
        "updatedAt": timestamp,
        "surface": surface,
        "surfaceEntityId": surface_entity_id,
        "surfaceEntityUuid": surface_entity_uuid,
        "graphEntityType": graph_entity_type,
        "graphEntityId": null,
        "graphEntityUuid": graph_entity_uuid,
    })
}

fn build_film_project_graph_source(asset: &Map<String, Value>) -> Option<Value> {
    let asset_id = read_map_text(asset, "assetId");
    let resource_view_id = read_map_text(asset, "id");
    let primary_resource_id = read_map_text(asset, "fileId");
    if asset_id.is_none() && resource_view_id.is_none() && primary_resource_id.is_none() {
        return None;
    }

    let primary_type = read_map_text(asset, "type").or_else(|| read_map_text(asset, "assetType"));
    let locator = read_map_text(asset, "url").or_else(|| read_map_text(asset, "path"));
    let storage_mode = locator.as_deref().map(resolve_film_graph_storage_mode);

    Some(json!({
        "assetId": asset_id,
        "primaryResourceId": primary_resource_id,
        "resourceViewId": resource_view_id,
        "primaryType": primary_type,
        "storageMode": storage_mode,
        "scopeDomain": "film",
        "metadata": {
            "assetType": read_map_text(asset, "assetType"),
            "scene": read_map_text(asset, "scene"),
            "url": locator,
        }
    }))
}

fn first_film_shot_asset_object(shot: &Map<String, Value>) -> Option<Map<String, Value>> {
    shot.get("generation")
        .and_then(Value::as_object)
        .and_then(|generation| generation.get("assets"))
        .and_then(Value::as_array)
        .and_then(|assets| assets.first())
        .and_then(Value::as_object)
        .cloned()
        .or_else(|| {
            shot.get("assets")
                .and_then(Value::as_array)
                .and_then(|assets| assets.first())
                .and_then(Value::as_object)
                .cloned()
        })
}

fn collect_film_shot_asset_ids(shot: &Map<String, Value>) -> Vec<String> {
    let mut asset_ids = Vec::new();
    for assets in [
        shot.get("assets"),
        shot.get("generation")
            .and_then(Value::as_object)
            .and_then(|generation| generation.get("assets")),
    ] {
        if let Some(items) = assets.and_then(Value::as_array) {
            for item in items {
                if let Some(object) = item.as_object() {
                    if let Some(asset_id) = read_map_text(object, "assetId") {
                        asset_ids.push(asset_id);
                    }
                }
            }
        }
    }
    asset_ids
}

fn resolve_scene_order_from_object(object: &Map<String, Value>, fallback_index: usize) -> usize {
    read_map_i64(object, "index")
        .or_else(|| read_map_i64(object, "sceneNumber").map(|value| value - 1))
        .map(|value| value.max(0) as usize)
        .unwrap_or(fallback_index)
}

fn resolve_shot_order_from_object(object: &Map<String, Value>, fallback_index: usize) -> usize {
    read_map_i64(object, "index")
        .or_else(|| read_map_i64(object, "shotNumber").map(|value| value - 1))
        .map(|value| value.max(0) as usize)
        .unwrap_or(fallback_index)
}

fn resolve_scene_title_from_object(object: &Map<String, Value>, fallback_index: usize) -> String {
    read_map_i64(object, "sceneNumber")
        .map(|value| format!("Scene {}", value.max(1)))
        .unwrap_or_else(|| format!("Scene {}", fallback_index + 1))
}

fn resolve_shot_title_from_object(object: &Map<String, Value>, fallback_index: usize) -> String {
    read_map_i64(object, "shotNumber")
        .map(|value| format!("Shot {}", value.max(1)))
        .unwrap_or_else(|| format!("Shot {}", fallback_index + 1))
}

fn resolve_film_graph_storage_mode(locator: &str) -> &'static str {
    let normalized = locator.to_ascii_lowercase();
    if normalized.starts_with("http://") || normalized.starts_with("https://") {
        "remote-url"
    } else if normalized.starts_with("file://") || normalized.contains(":\\") {
        "desktop-fs"
    } else {
        "hybrid"
    }
}

fn resolve_film_graph_mode(product: &str) -> Option<&'static str> {
    match product {
        "image" => Some("text-to-image"),
        "video" | "short-video" | "short-drama-shot" => Some("text-to-video"),
        "audio" | "sfx" => Some("text-to-audio"),
        "music" => Some("text-to-music"),
        "speech" | "voice" => Some("text-to-speech"),
        _ => None,
    }
}

fn join_names_with_and(values: &[String]) -> String {
    match values {
        [] => "Subject".to_string(),
        [value] => value.clone(),
        [left, right] => format!("{left} and {right}"),
        _ => {
            let mut remaining = values[..values.len() - 1].join(", ");
            remaining.push_str(", and ");
            remaining.push_str(values.last().map(String::as_str).unwrap_or("Subject"));
            remaining
        }
    }
}

fn is_missing_or_empty_array(value: Option<&Value>) -> bool {
    match value {
        Some(Value::Array(items)) => items.is_empty(),
        Some(_) => false,
        None => true,
    }
}

fn json_number(value: i64) -> Value {
    Value::Number(serde_json::Number::from(value))
}

fn default_film_input(project_key: &str, now_ms: i64) -> Value {
    json!({
        "id": format!("{project_key}:input"),
        "uuid": format!("{project_key}:input"),
        "type": "FILM_USER_INPUT",
        "text": "",
        "language": DEFAULT_FILM_LANGUAGE,
        "createdAt": now_ms,
        "updatedAt": now_ms,
    })
}

fn default_film_script(project_key: &str, project_name: &str, now_ms: i64) -> Value {
    json!({
        "id": format!("{project_key}:script"),
        "uuid": format!("{project_key}:script"),
        "type": "FILM_SCRIPT",
        "title": project_name,
        "genres": [],
        "styles": [],
        "content": "",
        "standardized": false,
        "version": "1.0.0",
        "createdAt": now_ms,
        "updatedAt": now_ms,
    })
}

fn default_film_settings(project_key: &str, now_ms: i64) -> Value {
    json!({
        "id": format!("{project_key}:settings"),
        "uuid": format!("{project_key}:settings"),
        "theme": "default",
        "style": "cinematic",
        "aspect": "16:9",
        "resolution": "1080P",
        "fps": 24,
        "quality": "standard",
        "createdAt": now_ms,
        "updatedAt": now_ms,
    })
}

fn build_film_characters(names: &[String], now_ms: i64) -> Vec<Value> {
    names
        .iter()
        .map(|name| {
            let key = next_film_entity_key("film-character");
            json!({
                "id": key,
                "uuid": key,
                "type": "FILM_CHARACTER",
                "name": name,
                "characterType": "HUMAN",
                "refAssets": [],
                "status": "ACTIVE",
                "description": "",
                "personality": { "traits": [] },
                "appearance": {},
                "createdAt": now_ms,
                "updatedAt": now_ms,
            })
        })
        .collect()
}

fn build_film_locations(
    names: &[String],
    scene_drafts: &[FilmSceneDraft],
    now_ms: i64,
) -> Vec<Value> {
    names.iter()
        .map(|name| {
            let key = next_film_entity_key("film-location");
            let matching_scene = scene_drafts.iter().find(|scene| scene.location_name == *name);
            json!({
                "id": key,
                "uuid": key,
                "type": "FILM_LOCATION",
                "name": name,
                "description": matching_scene.map(|scene| scene.summary.clone()).unwrap_or_default(),
                "tags": [],
                "atmosphereTags": matching_scene
                    .and_then(|scene| scene.time_of_day.clone().map(|time| vec![time]))
                    .unwrap_or_default(),
                "visualDescription": matching_scene.map(|scene| scene.visual_prompt.clone()).unwrap_or_default(),
                "refAssets": [],
                "indoor": infer_location_is_indoor(name),
                "timeOfDay": matching_scene.and_then(|scene| scene.time_of_day.clone()).unwrap_or_else(|| "DAY".to_string()),
                "createdAt": now_ms,
                "updatedAt": now_ms,
            })
        })
        .collect()
}

fn build_film_props(names: Vec<String>, now_ms: i64) -> Vec<Value> {
    names
        .into_iter()
        .map(|name| {
            let key = next_film_entity_key("film-prop");
            json!({
                "id": key,
                "uuid": key,
                "type": "FILM_PROP",
                "name": name,
                "description": "",
                "tags": [],
                "refAssets": [],
                "createdAt": now_ms,
                "updatedAt": now_ms,
            })
        })
        .collect()
}

fn build_film_scenes(
    scene_drafts: &[FilmSceneDraft],
    location_uuid_by_name: &BTreeMap<String, String>,
    character_uuid_by_name: &BTreeMap<String, String>,
    now_ms: i64,
) -> Vec<Value> {
    scene_drafts
        .iter()
        .enumerate()
        .map(|(index, scene)| {
            let key = next_film_entity_key("film-scene");
            let character_uuids = scene
                .character_names
                .iter()
                .filter_map(|name| character_uuid_by_name.get(name).cloned())
                .collect::<Vec<_>>();

            json!({
                "id": key,
                "uuid": key,
                "type": "FILM_SCENE",
                "sceneNumber": index + 1,
                "index": index + 1,
                "summary": scene.summary,
                "locationUuid": location_uuid_by_name.get(&scene.location_name).cloned(),
                "characterUuids": character_uuids,
                "propUuids": Vec::<String>::new(),
                "moodTags": scene.time_of_day.clone().map(|value| vec![value]).unwrap_or_default(),
                "visualPrompt": scene.visual_prompt,
                "createdAt": now_ms,
                "updatedAt": now_ms,
            })
        })
        .collect()
}

fn build_scene_drafts(lines: &[String], character_names: &[String]) -> Vec<FilmSceneDraft> {
    let mut scenes = Vec::new();
    let mut current_heading: Option<String> = None;
    let mut current_lines: Vec<String> = Vec::new();
    let mut current_characters: BTreeSet<String> = BTreeSet::new();

    let flush_scene = |heading: Option<String>,
                       body_lines: &mut Vec<String>,
                       scene_characters: &mut BTreeSet<String>,
                       scenes: &mut Vec<FilmSceneDraft>| {
        if heading.is_none() && body_lines.is_empty() {
            return;
        }

        let heading_text = heading.unwrap_or_else(|| "INT. UNASSIGNED SPACE - DAY".to_string());
        let (location_name, time_of_day) = parse_scene_heading(&heading_text);
        let summary = summarize_scene_lines(body_lines);
        let visual_prompt = if summary.is_empty() {
            format!("{location_name} cinematic establishing shot")
        } else {
            format!("{location_name}, {summary}")
        };
        scenes.push(FilmSceneDraft {
            location_name,
            time_of_day,
            summary,
            visual_prompt,
            character_names: scene_characters.iter().cloned().collect(),
        });
        body_lines.clear();
        scene_characters.clear();
    };

    for line in lines {
        if is_scene_heading(line) {
            flush_scene(
                current_heading.take(),
                &mut current_lines,
                &mut current_characters,
                &mut scenes,
            );
            current_heading = Some(line.clone());
            continue;
        }

        if let Some(character_name) = extract_character_name_from_line(line) {
            if character_names
                .iter()
                .any(|candidate| candidate == &character_name)
            {
                current_characters.insert(character_name);
            }
        }

        if !line.trim().is_empty() {
            current_lines.push(line.clone());
        }
    }

    flush_scene(
        current_heading.take(),
        &mut current_lines,
        &mut current_characters,
        &mut scenes,
    );

    if scenes.is_empty() {
        scenes.push(FilmSceneDraft {
            location_name: "Unassigned Location".to_string(),
            time_of_day: Some("DAY".to_string()),
            summary: "Unstructured film script content".to_string(),
            visual_prompt: "Unstructured film scene".to_string(),
            character_names: Vec::new(),
        });
    }

    scenes
}

fn collect_location_names(scene_drafts: &[FilmSceneDraft]) -> Vec<String> {
    let mut names = BTreeSet::new();
    for scene in scene_drafts {
        if !scene.location_name.trim().is_empty() {
            names.insert(scene.location_name.clone());
        }
    }
    names.into_iter().collect()
}

fn standardize_film_script_lines(lines: &[String]) -> Vec<String> {
    let mut standardized = Vec::new();
    let has_scene_heading = lines.iter().any(|line| is_scene_heading(line));
    if !has_scene_heading && !lines.is_empty() {
        standardized.push("INT. UNASSIGNED SPACE - DAY".to_string());
    }

    for line in lines {
        if is_scene_heading(line) {
            standardized.push(canonicalize_scene_heading(line));
            continue;
        }

        if let Some(dialogue_line) = standardize_dialogue_line(line) {
            standardized.push(dialogue_line);
            continue;
        }

        let narration = collapse_script_whitespace(line);
        if !narration.is_empty() {
            standardized.push(narration);
        }
    }

    standardized
}

fn normalize_script_lines(content: &str) -> Vec<String> {
    content
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty())
        .map(str::to_string)
        .collect()
}

fn canonicalize_scene_heading(line: &str) -> String {
    let prefix = resolve_scene_heading_prefix(line);
    let (location_name, time_of_day) = parse_scene_heading(line);
    format!(
        "{prefix}. {} - {}",
        uppercase_ascii_segment(&location_name),
        time_of_day.unwrap_or_else(|| "DAY".to_string())
    )
}

fn resolve_scene_heading_prefix(line: &str) -> &'static str {
    let upper = line.trim().to_ascii_uppercase();
    if upper.starts_with("EXT.") || upper.starts_with("EXT/") {
        "EXT"
    } else {
        "INT"
    }
}

fn uppercase_ascii_segment(value: &str) -> String {
    if value.is_ascii() {
        value.to_ascii_uppercase()
    } else {
        value.to_string()
    }
}

fn standardize_dialogue_line(line: &str) -> Option<String> {
    for separator in [':', '：'] {
        if let Some((candidate, dialogue)) = line.split_once(separator) {
            let name = normalize_character_candidate(candidate)?;
            let dialogue = collapse_script_whitespace(dialogue);
            return Some(if dialogue.is_empty() {
                format!("{name}:")
            } else {
                format!("{name}: {dialogue}")
            });
        }
    }

    if is_uppercase_character_cue(line) {
        return normalize_character_candidate(line).map(|name| format!("{name}:"));
    }

    None
}

fn collapse_script_whitespace(value: &str) -> String {
    value.split_whitespace().collect::<Vec<_>>().join(" ")
}

fn extract_character_names(lines: &[String]) -> Vec<String> {
    let mut names = BTreeSet::new();
    for line in lines {
        if let Some(name) = extract_character_name_from_line(line) {
            names.insert(name);
        }
    }
    names.into_iter().collect()
}

fn extract_character_name_from_line(line: &str) -> Option<String> {
    let trimmed = line.trim();
    if trimmed.is_empty() || is_scene_heading(trimmed) {
        return None;
    }

    for separator in [':', '：'] {
        if let Some((candidate, _)) = trimmed.split_once(separator) {
            if let Some(name) = normalize_character_candidate(candidate) {
                return Some(name);
            }
        }
    }

    if is_uppercase_character_cue(trimmed) {
        return normalize_character_candidate(trimmed);
    }

    None
}

fn normalize_character_candidate(value: &str) -> Option<String> {
    let candidate = value
        .trim()
        .trim_matches(|character: char| {
            matches!(
                character,
                '(' | ')' | '[' | ']' | '"' | '\'' | '.' | ',' | '!' | '?' | '-'
            )
        })
        .trim();

    if candidate.is_empty()
        || candidate.len() > 32
        || candidate
            .chars()
            .any(|character| character.is_ascii_digit())
    {
        return None;
    }

    let normalized_upper = candidate.to_ascii_uppercase();
    if matches!(
        normalized_upper.as_str(),
        "INT" | "EXT" | "CUT TO" | "FADE IN" | "FADE OUT" | "MONTAGE" | "INSERT"
    ) {
        return None;
    }

    if candidate.is_ascii() {
        let word_count = candidate.split_whitespace().count();
        if word_count == 0 || word_count > 4 {
            return None;
        }

        return Some(
            candidate
                .split_whitespace()
                .map(title_case_ascii_word)
                .collect::<Vec<_>>()
                .join(" "),
        );
    }

    Some(candidate.to_string())
}

fn is_uppercase_character_cue(line: &str) -> bool {
    if line.len() > 40 || line.contains('.') || line.contains('-') || line.contains('/') {
        return false;
    }

    let words = line.split_whitespace().collect::<Vec<_>>();
    if words.is_empty() || words.len() > 4 {
        return false;
    }

    words.iter().all(|word| {
        word.chars()
            .all(|character| !character.is_ascii_lowercase())
    })
}

fn title_case_ascii_word(word: &str) -> String {
    let mut characters = word.chars();
    let Some(first) = characters.next() else {
        return String::new();
    };
    let mut normalized = String::new();
    normalized.extend(first.to_uppercase());
    normalized.push_str(&characters.as_str().to_ascii_lowercase());
    normalized
}

fn is_scene_heading(line: &str) -> bool {
    let upper = line.trim().to_ascii_uppercase();
    upper.starts_with("INT.")
        || upper.starts_with("EXT.")
        || upper.starts_with("INT/")
        || upper.starts_with("EXT/")
        || line.starts_with("内景")
        || line.starts_with("外景")
}

fn parse_scene_heading(heading: &str) -> (String, Option<String>) {
    let trimmed = heading.trim();
    let normalized = trimmed
        .trim_start_matches("INT.")
        .trim_start_matches("EXT.")
        .trim_start_matches("INT/")
        .trim_start_matches("EXT/")
        .trim_start_matches("内景")
        .trim_start_matches("外景")
        .trim();

    let segments = normalized
        .split(['-', '—', '–'])
        .map(str::trim)
        .filter(|segment| !segment.is_empty())
        .collect::<Vec<_>>();

    if segments.is_empty() {
        return ("Unassigned Location".to_string(), Some("DAY".to_string()));
    }

    let location_name = title_case_segment(segments[0]);
    let time_of_day = segments
        .last()
        .map(|segment| normalize_time_of_day(segment));
    (location_name, time_of_day)
}

fn title_case_segment(segment: &str) -> String {
    if segment.is_ascii() {
        segment
            .split_whitespace()
            .map(title_case_ascii_word)
            .collect::<Vec<_>>()
            .join(" ")
    } else {
        segment.to_string()
    }
}

fn normalize_time_of_day(value: &str) -> String {
    let normalized = value.trim().to_ascii_uppercase();
    match normalized.as_str() {
        "NIGHT" | "EVENING" | "DUSK" | "MIDNIGHT" | "夜" | "夜晚" => "NIGHT".to_string(),
        "SUNSET" | "TWILIGHT" | "黄昏" | "傍晚" => "SUNSET".to_string(),
        _ => "DAY".to_string(),
    }
}

fn summarize_scene_lines(lines: &[String]) -> String {
    let summary = lines
        .iter()
        .take(3)
        .map(|line| line.trim())
        .filter(|line| !line.is_empty())
        .collect::<Vec<_>>()
        .join(" ");

    if summary.is_empty() {
        "New film scene".to_string()
    } else if summary.len() > 240 {
        summary[..240].trim().to_string()
    } else {
        summary
    }
}

fn extract_prop_names(
    lines: &[String],
    character_names: &[String],
    location_names: &[String],
) -> Vec<String> {
    let character_keys = character_names
        .iter()
        .map(|value| value.to_ascii_lowercase())
        .collect::<BTreeSet<_>>();
    let location_keys = location_names
        .iter()
        .map(|value| value.to_ascii_lowercase())
        .collect::<BTreeSet<_>>();
    let mut props = BTreeSet::new();

    for line in lines {
        if is_scene_heading(line) || is_uppercase_character_cue(line) {
            continue;
        }

        for candidate in extract_ascii_prop_candidates(line) {
            let normalized = candidate.to_ascii_lowercase();
            if !character_keys.contains(&normalized)
                && !location_keys.contains(&normalized)
                && !is_prop_stop_phrase(&normalized)
            {
                props.insert(candidate);
            }
        }

        if let Some(candidate) = extract_cjk_prop_candidate(line) {
            if !character_keys.contains(&candidate.to_ascii_lowercase())
                && !location_keys.contains(&candidate.to_ascii_lowercase())
            {
                props.insert(candidate);
            }
        }
    }

    props.into_iter().collect()
}

fn extract_ascii_prop_candidates(line: &str) -> Vec<String> {
    let tokens = line
        .split(|character: char| !character.is_ascii_alphanumeric() && character != '\'')
        .filter(|token| !token.is_empty())
        .collect::<Vec<_>>();
    let mut candidates = Vec::new();

    for index in 0..tokens.len() {
        let token = tokens[index].to_ascii_lowercase();
        if !matches!(
            token.as_str(),
            "a" | "an"
                | "the"
                | "his"
                | "her"
                | "their"
                | "holding"
                | "holds"
                | "grabs"
                | "takes"
                | "pulls"
                | "shows"
                | "with"
        ) {
            continue;
        }

        if let Some(next) = tokens.get(index + 1) {
            let next_normalized = next.to_ascii_lowercase();
            if is_prop_stop_phrase(&next_normalized) {
                continue;
            }

            let candidate = if let Some(third) = tokens.get(index + 2) {
                if is_common_adjective(&next_normalized)
                    && !is_prop_stop_phrase(&third.to_ascii_lowercase())
                {
                    format!(
                        "{} {}",
                        title_case_ascii_word(next),
                        title_case_ascii_word(third)
                    )
                } else {
                    title_case_ascii_word(next)
                }
            } else {
                title_case_ascii_word(next)
            };

            if candidate.len() >= 3 {
                candidates.push(candidate);
            }
        }
    }

    candidates
}

fn extract_cjk_prop_candidate(line: &str) -> Option<String> {
    for marker in [
        "一把",
        "一张",
        "一台",
        "一部",
        "一个",
        "拿着",
        "手持",
        "佩戴着",
    ] {
        if let Some(index) = line.find(marker) {
            let start = index + marker.len();
            let rest = &line[start..];
            let candidate = rest
                .split(['，', '。', '、', '；', ',', '.', ' '])
                .next()
                .unwrap_or("")
                .trim();
            if !candidate.is_empty() && candidate.chars().count() <= 8 {
                return Some(candidate.to_string());
            }
        }
    }
    None
}

fn is_common_adjective(word: &str) -> bool {
    matches!(
        word,
        "small"
            | "large"
            | "old"
            | "new"
            | "silver"
            | "black"
            | "white"
            | "red"
            | "blue"
            | "golden"
            | "metal"
            | "wooden"
            | "glass"
            | "digital"
            | "folded"
            | "broken"
            | "matte"
            | "glowing"
    )
}

fn is_prop_stop_phrase(word: &str) -> bool {
    matches!(
        word,
        "room"
            | "hall"
            | "street"
            | "alley"
            | "day"
            | "night"
            | "man"
            | "woman"
            | "camera"
            | "scene"
            | "moment"
            | "silence"
            | "look"
            | "eyes"
            | "face"
            | "voice"
    )
}

fn infer_location_is_indoor(name: &str) -> bool {
    let normalized = name.to_ascii_lowercase();
    !matches!(
        normalized.as_str(),
        value if value.contains("street")
            || value.contains("alley")
            || value.contains("forest")
            || value.contains("park")
            || value.contains("beach")
            || value.contains("outside")
    )
}

fn require_object(value: Value, code: &str) -> ServerResult<Map<String, Value>> {
    value
        .as_object()
        .cloned()
        .ok_or_else(|| ServerError::bad_request(code, "request document must be a JSON object"))
}

fn read_object_text(object: &Map<String, Value>, key: &str) -> Option<String> {
    object
        .get(key)
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
}

fn read_map_text(object: &Map<String, Value>, key: &str) -> Option<String> {
    read_object_text(object, key)
}

fn read_map_i64(object: &Map<String, Value>, key: &str) -> Option<i64> {
    object.get(key).and_then(read_value_i64)
}

fn read_map_string_array(object: &Map<String, Value>, key: &str) -> Vec<String> {
    object
        .get(key)
        .and_then(Value::as_array)
        .map(|items| {
            items
                .iter()
                .filter_map(Value::as_str)
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .map(str::to_string)
                .collect()
        })
        .unwrap_or_default()
}

fn read_json_string_array(value: Option<&Value>) -> Option<Vec<String>> {
    value.and_then(Value::as_array).map(|items| {
        items
            .iter()
            .filter_map(Value::as_str)
            .map(str::trim)
            .filter(|item| !item.is_empty())
            .map(str::to_string)
            .collect()
    })
}

fn read_nested_map_text(
    object: &Map<String, Value>,
    parent_key: &str,
    child_key: &str,
) -> Option<String> {
    object
        .get(parent_key)
        .and_then(Value::as_object)
        .and_then(|child| read_map_text(child, child_key))
}

fn read_nested_map_i64(
    object: &Map<String, Value>,
    parent_key: &str,
    child_key: &str,
) -> Option<i64> {
    object
        .get(parent_key)
        .and_then(Value::as_object)
        .and_then(|child| read_map_i64(child, child_key))
}

fn read_value_i64(value: &Value) -> Option<i64> {
    value
        .as_i64()
        .or_else(|| value.as_u64().and_then(|number| i64::try_from(number).ok()))
        .or_else(|| value.as_f64().map(|number| number.round() as i64))
        .or_else(|| {
            value
                .as_str()
                .and_then(|text| text.trim().parse::<i64>().ok())
        })
}

fn resolve_json_entity_key(document: &Value) -> Option<String> {
    document
        .as_object()
        .and_then(|object| read_map_text(object, "uuid").or_else(|| read_map_text(object, "id")))
}

fn matches_json_entity_key(document: &Value, key: &str) -> bool {
    resolve_json_entity_key(document)
        .map(|value| value == key)
        .unwrap_or(false)
}

fn require_non_empty_text(value: &str, code: &str, field_name: &str) -> ServerResult<String> {
    let trimmed = value.trim();
    if trimmed.is_empty() {
        return Err(ServerError::bad_request(
            code,
            format!("{field_name} must not be empty"),
        ));
    }
    Ok(trimmed.to_string())
}

fn normalize_optional_text(value: Option<String>) -> Option<String> {
    value.and_then(|value| {
        let trimmed = value.trim();
        if trimmed.is_empty() {
            None
        } else {
            Some(trimmed.to_string())
        }
    })
}

fn normalize_page(value: Option<usize>) -> usize {
    value.unwrap_or(1).max(1)
}

fn normalize_page_size(value: Option<usize>) -> usize {
    value.unwrap_or(20).clamp(1, 100)
}

fn normalize_sort_fields(sort: Vec<String>) -> Vec<FilmSortField> {
    let mut fields = sort
        .into_iter()
        .filter_map(|value| {
            let normalized = value.trim();
            if normalized.is_empty() {
                return None;
            }

            let mut segments = normalized.split(':');
            let field = normalize_sort_field_name(segments.next()?);
            let ascending = !matches!(
                segments.next().map(|segment| segment.trim().to_ascii_lowercase()),
                Some(direction) if direction == "desc" || direction == "-1"
            );
            Some(FilmSortField { field, ascending })
        })
        .collect::<Vec<_>>();

    if fields.is_empty() {
        fields.push(FilmSortField {
            field: "updatedAt",
            ascending: false,
        });
    }

    fields
}

fn normalize_sort_field_name(field: &str) -> &'static str {
    match field.trim() {
        "name" => "name",
        "createdAt" => "createdAt",
        "updatedAt" => "updatedAt",
        _ => "updatedAt",
    }
}

fn keyword_matches(document: &Value, keyword: Option<&str>) -> bool {
    let Some(keyword) = keyword else {
        return true;
    };

    let object = match document.as_object() {
        Some(object) => object,
        None => return false,
    };

    [
        read_map_text(object, "name"),
        read_map_text(object, "description"),
        object
            .get("script")
            .and_then(Value::as_object)
            .and_then(|script| read_map_text(script, "title")),
        object
            .get("script")
            .and_then(Value::as_object)
            .and_then(|script| read_map_text(script, "content")),
    ]
    .into_iter()
    .flatten()
    .any(|value| value.to_lowercase().contains(keyword))
}

fn compare_documents(left: &Value, right: &Value, sort_fields: &[FilmSortField]) -> Ordering {
    for field in sort_fields {
        let ordering = match field.field {
            "name" => read_json_text(left, "name").cmp(&read_json_text(right, "name")),
            "createdAt" => created_at_millis(left).cmp(&created_at_millis(right)),
            "updatedAt" => updated_at_millis(left).cmp(&updated_at_millis(right)),
            _ => Ordering::Equal,
        };

        if ordering != Ordering::Equal {
            return if field.ascending {
                ordering
            } else {
                ordering.reverse()
            };
        }
    }

    Ordering::Equal
}

fn read_json_text(document: &Value, key: &str) -> String {
    document
        .as_object()
        .and_then(|object| read_map_text(object, key))
        .unwrap_or_default()
        .to_lowercase()
}

fn created_at_millis(document: &Value) -> i64 {
    document
        .as_object()
        .and_then(|object| object.get("createdAt"))
        .and_then(Value::as_i64)
        .unwrap_or_default()
}

fn updated_at_millis(document: &Value) -> i64 {
    document
        .as_object()
        .and_then(|object| object.get("updatedAt"))
        .and_then(Value::as_i64)
        .unwrap_or_default()
}

fn current_time_millis() -> i64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_millis() as i64
}

fn next_film_entity_key(prefix: &str) -> String {
    format!(
        "{prefix}-{}",
        FILM_ENTITY_COUNTER.fetch_add(1, AtomicOrdering::Relaxed)
    )
}
